INSERT INTO nuances (id, word_a, word_b, word_c, ko_a, ko_b, ko_c, comparison, tip, cefr, topic_id, priority, sort_order, image_keyword, ex_a, ex_a_ko, ex_b, ex_b_ko, ex_c, ex_c_ko, ex4, ex4_ko, ex5, ex5_ko) VALUES
('nuc_academic_01','quote','paraphrase',NULL,'인용하다 (원문 그대로)','바꿔 말하다',NULL,'quote는 원문 그대로 인용하는 것, paraphrase는 의미를 유지하며 자기 말로 바꾸는 것이에요.','논문에서는 quote와 paraphrase 모두 출처를 밝혀야 해요.','B1','academic',1,1,'quote paraphrase writing academic','"To be or not to be" — I''m quoting Shakespeare.','"사느냐 죽느냐" — 셰익스피어를 인용하는 거예요.','To paraphrase, he said life''s choices are difficult.','다르게 풀어 말하면, 그는 인생의 선택이 어렵다고 말했어요.','Be sure to quote the author''s exact words inside quotation marks.','저자의 정확한 말을 반드시 따옴표 안에 넣어 인용하세요.','Quoting a famous line still requires a citation.','유명한 구절을 인용해도 출처 표기가 필요해요.','Paraphrase in your own words but credit the source.','자기 말로 바꿔 쓰되 출처를 밝히세요.'),
('nuc_academic_02','thesis','hypothesis',NULL,'논제 / 학위 논문','가설',NULL,'thesis는 논문의 주장이나 학위 논문, hypothesis는 검증이 필요한 과학적 가설이에요.','thesis는 인문·사회과학, hypothesis는 과학 연구에서 주로 써요.','B1','academic',1,2,'thesis hypothesis research academic','Her thesis argues that language shapes culture.','그녀의 논제는 언어가 문화를 형성한다는 거예요.','The hypothesis was tested through experiments.','그 가설은 실험을 통해 검증되었어요.','He is writing his master''s thesis on renewable energy policy.','그는 재생 에너지 정책에 관한 석사 논문을 쓰고 있어요.','Her thesis is being reviewed by three professors.','그녀의 논문은 세 교수님이 심사 중이에요.','The hypothesis was supported by the experimental data.','가설이 실험 데이터로 뒷받침됐어요.'),
('nuc_academic_03','abstract','introduction',NULL,'초록 / 요약','서론',NULL,'abstract는 논문 전체를 압축한 요약, introduction은 주제와 배경을 소개하는 서론이에요.','abstract는 논문 앞에 붙는 요약, introduction은 본문의 첫 부분이에요.','B2','academic',2,3,'abstract introduction research paper','Read the abstract to decide if the paper is relevant.','그 논문이 적절한지 판단하려면 초록을 읽어 보세요.','The introduction explains the research question.','서론은 연구 질문을 설명해요.','Most readers skim the abstract before downloading the full paper.','대부분의 독자는 전체 논문을 다운로드하기 전에 초록을 훑어봐요.','The abstract should give a complete picture of the study.','초록은 연구의 전체 그림을 담아야 해요.','A strong introduction guides the reader into the topic.','좋은 서론은 독자를 주제로 이끌어요.'),
('nuc_academic_04','cite','reference',NULL,'인용하다','참고하다 / 참고문헌',NULL,'cite는 특정 자료를 직접 인용하는 것, reference는 참고한 자료를 목록으로 제시하는 것이에요.','cite(본문 내 인용) → reference list(마지막 참고문헌)가 세트예요.','B2','academic',1,4,'cite reference bibliography academic','The paper cites 30 sources.','그 논문은 30개의 출처를 인용해요.','A full list of references appears at the end.','전체 참고 문헌 목록은 끝부분에 나와요.','Remember to cite the original study whenever you use its findings.','원래 연구의 결과를 사용할 때는 반드시 그 연구를 인용하는 것을 잊지 마세요.','Cite every source you used, even online articles.','온라인 기사를 포함해 사용한 모든 출처를 인용하세요.','A complete reference list belongs at the end of the paper.','완전한 참고문헌 목록은 논문 끝에 있어요.'),
('nuc_academic_05','argument','evidence',NULL,'주장','근거',NULL,'argument는 주장·논지, evidence는 그것을 뒷받침하는 근거·증거예요.','argument(주장) + evidence(근거) = 설득력 있는 글의 핵심이에요.','B2','academic',2,5,'argument evidence writing academic','Her argument is that early education matters most.','그녀의 주장은 조기 교육이 가장 중요하다는 거예요.','The evidence includes data from 10 countries.','그 증거에는 10개국의 데이터가 포함되어 있어요.','A convincing argument needs solid evidence to back it up.','설득력 있는 주장에는 그것을 뒷받침할 탄탄한 증거가 필요해요.','Build your argument step by step, point by point.','단계적으로 한 가지씩 자기 주장을 쌓아가세요.','Strong evidence makes any claim more believable.','강한 근거는 어떤 주장이든 더 신뢰할 만하게 만들어요.'),
('nuc_academic_06','qualitative','quantitative',NULL,'질적 연구','양적 연구',NULL,'qualitative는 인터뷰·관찰 등 비수치 방법, quantitative는 통계·수치를 사용하는 연구 방법이에요.','사회과학 연구에서 두 방법 모두 중요해요.','B2','academic',1,6,'qualitative quantitative research method','Qualitative research explores people''s experiences.','질적 연구는 사람들의 경험을 탐구해요.','Quantitative methods measure variables numerically.','양적 방법은 변수를 수치로 측정해요.','They combined qualitative case studies with statistical analysis.','그들은 질적 사례 연구와 통계 분석을 결합했어요.','Qualitative interviews captured students'' personal experiences.','질적 인터뷰가 학생들의 개인적 경험을 포착했어요.','Quantitative surveys measured changes over the semester.','양적 설문조사가 한 학기 동안의 변화를 측정했어요.'),
('nuc_academic_07','peer review','editorial review',NULL,'동료 심사','편집 심사',NULL,'peer review는 전문가들이 논문을 심사하는 과정, editorial review는 편집자가 출판 적합성을 검토하는 것이에요.','peer-reviewed journal은 학술 신뢰성의 기준이에요.','B2','academic',2,7,'peer review editorial journal academic','Only peer-reviewed papers are accepted.','동료 심사를 거친 논문만 받아들여져요.','The manuscript passed the editorial review stage.','그 원고는 편집 심사 단계를 통과했어요.','The journal sent the paper out for peer review by three experts.','그 학술지는 세 명의 전문가에게 동료 심사를 받기 위해 논문을 보냈어요.','Peer review helps ensure research quality.','동료 심사는 연구 품질을 확보하는 데 도움이 돼요.','Editorial review focuses on style and fit for the journal.','편집 심사는 스타일과 저널 적합성에 집중해요.'),
('nuc_academic_14','theory','hypothesis',NULL,'이론 (검증된 설명)','가설 (검증 전 추측)',NULL,'theory는 검증·관찰을 통해 확립된 설명, hypothesis는 검증 전의 추측·예측.','hypothesis < theory. 일상에서 "I have a theory"는 "내 추측"으로 쓰이기도 하지만 학술적으로는 다름.','B2','academic',1,0,'science research hypothesis theory laboratory','Darwin''s theory of evolution is well-established.','다윈의 진화론은 잘 정립되어 있어요.','My hypothesis is that students learn better in groups.','제 가설은 학생들이 그룹에서 더 잘 배운다는 거예요.','The theory of plate tectonics explains how continents move.','판 구조론은 대륙이 어떻게 움직이는지 설명해요.','A hypothesis becomes a theory only after extensive testing.','가설은 광범위한 검증을 거쳐야 이론이 돼요.','She proposed a hypothesis; later studies turned it into a theory.','그녀는 가설을 제시했고, 이후 연구를 통해 이론이 됐어요.'),
('nuc_academic_08','correlation','causation',NULL,'상관관계','인과관계',NULL,'correlation은 두 변수가 함께 변하는 것, causation은 하나가 다른 하나를 직접 일으키는 것이에요.','"Correlation does not imply causation"은 통계 리터러시의 핵심 원칙이에요.','C1','academic',1,8,'correlation causation statistics research','There is a correlation between ice cream sales and drowning rates.','아이스크림 판매량과 익사율 사이에는 상관관계가 있어요.','Smoking causes lung cancer — this is causation.','흡연은 폐암을 일으켜요. 이것이 인과관계예요.','Researchers found a clear correlation between exercise and better sleep.','연구자들은 운동과 더 나은 수면 사이에서 분명한 상관관계를 발견했어요.','A strong correlation does not prove causation.','강한 상관관계가 인과관계를 증명하지는 않아요.','Establishing causation requires careful experimentation.','인과관계를 입증하려면 신중한 실험이 필요해요.'),
('nuc_academic_09','methodology','method',NULL,'방법론 (철학·원칙)','방법 (구체적)',NULL,'method는 구체적인 연구 절차, methodology는 연구 방법의 철학적 근거와 원칙이에요.','method는 what(무엇을), methodology는 why(왜)를 다뤄요.','C1','academic',2,9,'methodology method research design','The study used questionnaires as its primary method.','그 연구는 설문지를 주된 방법으로 사용했어요.','The methodology chapter explains why this approach was chosen.','방법론 장은 왜 이 접근법을 선택했는지를 설명해요.','A weak methodology can undermine even the most interesting research question.','허술한 방법론은 아무리 흥미로운 연구 질문이라도 무너뜨릴 수 있어요.','The methodology section explains the research design.','방법론 부분은 연구 설계를 설명해요.','They used interviews as the main method.','그들은 인터뷰를 주요 방법으로 사용했어요.'),
('nuc_academic_10','validity','reliability',NULL,'타당도 (측정 정확성)','신뢰도 (일관성)',NULL,'validity는 측정 도구가 목적에 맞는지, reliability는 반복해도 일관된 결과가 나오는지예요.','valid하지만 reliable하지 않을 수 있어요. 좋은 연구는 둘 다 필요해요.','C1','academic',1,10,'validity reliability research measurement','The test must have face validity to be taken seriously.','그 시험은 진지하게 받아들여지려면 표면 타당도를 갖춰야 해요.','High reliability means the results are consistent.','높은 신뢰도는 결과가 일관됨을 의미해요.','A test can be reliable yet still lack validity if it measures the wrong thing.','시험이 신뢰도가 높더라도 엉뚱한 것을 측정한다면 타당도가 부족할 수 있어요.','Construct validity is essential when measuring abstract concepts.','추상적 개념을 측정할 때 구성 타당도가 필수예요.','High reliability means the test gives consistent results.','높은 신뢰도는 시험이 일관된 결과를 낸다는 뜻이에요.'),
('nuc_academic_11','plagiarism','paraphrasing',NULL,'표절','바꿔 쓰기',NULL,'plagiarism은 남의 글을 허락 없이 자신의 것처럼 쓰는 것, paraphrasing은 출처를 밝히며 자기 말로 바꾸는 것이에요.','paraphrasing도 출처를 밝히지 않으면 표절이 될 수 있어요.','C1','academic',2,11,'plagiarism paraphrase integrity academic','Submitting copied text without citing is plagiarism.','출처를 밝히지 않고 베낀 글을 제출하는 것은 표절이에요.','Paraphrasing correctly avoids plagiarism.','올바르게 바꿔 쓰면 표절을 피할 수 있어요.','The university expelled the student for repeated plagiarism.','그 대학은 반복적인 표절로 그 학생을 퇴학시켰어요.','Plagiarism can have severe academic consequences.','표절은 심각한 학문적 결과를 초래할 수 있어요.','Good paraphrasing still requires citing the original source.','좋은 바꿔 쓰기도 여전히 원본 출처를 인용해야 해요.'),
('nuc_academic_12','epistemological','ontological',NULL,'인식론적','존재론적',NULL,'epistemological은 지식의 본질과 획득 방법에 관한 것, ontological은 존재·실재의 본질에 관한 것이에요.','학술 논문에서 두 개념은 연구 패러다임을 정의하는 데 사용돼요.','C2','academic',1,12,'epistemological ontological research philosophy','The study raises epistemological questions about how we know truth.','그 연구는 우리가 진리를 어떻게 아는지에 관한 인식론적 질문을 제기해요.','Ontological assumptions shape the research design.','존재론적 가정이 연구 설계를 형성해요.','Their disagreement was really epistemological: they differed on what counts as evidence.','그들의 의견 차이는 사실 인식론적인 것이었어요. 무엇을 증거로 볼지에 대해 달랐거든요.','The paper raises epistemological questions about scientific knowledge.','그 논문은 과학 지식에 관한 인식론적 질문을 제기해요.','Ontological positions affect how we define reality.','존재론적 입장은 우리가 현실을 어떻게 정의하는지에 영향을 줘요.'),
('nuc_academic_13','hegemony','sovereignty',NULL,'패권 / 지배력','주권',NULL,'hegemony는 하나의 집단이 다른 집단에 영향력을 행사하는 것, sovereignty는 국가가 자국을 통치할 권한이에요.','hegemony는 비공식 권력 지배, sovereignty는 공식·법적 자기 통치 권한이에요.','C2','academic',2,13,'hegemony sovereignty power political','American cultural hegemony is felt globally.','미국의 문화적 패권은 전 세계적으로 느껴져요.','The nation''s sovereignty was threatened by the invasion.','그 나라의 주권은 침략으로 위협받았어요.','During the Cold War, two superpowers competed for global hegemony.','냉전 시기에 두 초강대국은 세계 패권을 두고 경쟁했어요.','Cultural hegemony shapes which voices get heard.','문화적 패권은 어떤 목소리가 들리는지를 형성해요.','Sovereignty allows a country to set its own laws.','주권은 국가가 자국 법을 정할 수 있게 해줘요.'),
('nuc_body_01','see','look','watch','보이다 (자연스럽게)','쳐다보다 (의도적으로)','시청하다 (지속적으로)','''see''는 시야에 들어오는 것, ''look''은 잠깐 시선을 두는 것, ''watch''는 움직이는 것을 일정 시간 관찰하는 거예요.','''see''는 무의식적, ''look''은 짧은 의도적 시선, ''watch''는 영화·경기처럼 지속 관찰할 때 써요.','B1','body',1,0,'see look watch eyes','I can see the mountain from here.','여기서 산이 보여요.','Look at this beautiful painting.','이 아름다운 그림을 보세요.','We watched a movie last night.','우리는 어젯밤에 영화를 봤어요.','I looked at the clock and saw that I was already late.','시계를 쳐다보니 제가 이미 늦었다는 걸 알 수 있었어요.','She likes to watch the birds while she looks out the window.','그녀는 창밖을 바라보면서 새들을 관찰하는 걸 좋아해요.'),
('nuc_body_02','hear','listen',NULL,'들리다 (수동적)','귀 기울여 듣다 (능동적)',NULL,'''hear''는 소리가 자연히 들리는 것, ''listen''은 의도적으로 집중해서 듣는 거예요.','hear는 ''to''를 안 붙이고, listen은 ''listen to''로 써요.','B2','body',2,0,'hear listen ear sound','I hear birds singing outside.','밖에서 새들이 노래하는 소리가 들려요.','Please listen carefully to the instructions.','지시 사항을 주의 깊게 들어 주세요.','Stop and listen for a moment; can you hear that strange noise?','잠시 멈추고 귀를 기울여 보세요. 저 이상한 소리가 들리세요?','I could hear voices in the next room, but I wasn''t listening to them.','옆방에서 목소리가 들리긴 했지만, 거기에 귀 기울이지는 않았어요.','Listen to the doctor''s advice; don''t just hear it and forget.','의사 선생님의 조언을 귀담아들으세요. 그냥 흘려듣고 잊지 마세요.'),
('nuc_body_03','speak','talk',NULL,'말하다 (격식·공식)','대화하다 (편안한 잡담)',NULL,'''speak''는 일방적·공식적인 발화, ''talk''은 쌍방향 대화에 가까워요.','언어 능력은 ''speak English''(영어로 말하다), 친구와의 수다는 ''talk to a friend''로 써요.','B2','body',2,0,'speak talk conversation','The CEO will speak at the conference.','CEO가 그 회의에서 연설할 거예요.','Let''s talk about our weekend plans.','우리 주말 계획에 대해 이야기해요.','She was nervous to speak in front of such a large audience.','그녀는 그렇게 많은 청중 앞에서 말하는 게 긴장됐어요.','The professor will speak to the graduates this afternoon.','교수님께서 오늘 오후에 졸업생들에게 연설하실 거예요.','We talked for hours over coffee about everything and nothing.','저희는 커피를 마시며 별의별 이야기를 몇 시간이나 나눴어요.'),
('nuc_body_04','ache','pain','sore','쑤시다 (둔하고 지속적)','아픔 (날카롭거나 강한)','뻐근한 (운동 후·만지면 아픈)','''ache''는 둔하게 지속되는 통증, ''pain''은 강하고 급성, ''sore''는 운동 후나 부어서 아픈 느낌이에요.','두통·치통 같은 둔통은 ''ache'', 부상은 ''pain'', 운동 후 근육통은 ''sore''가 자연스러워요.','C1','body',2,0,'ache pain sore body','My head aches after the long meeting.','긴 회의 후에 머리가 아파요.','I felt a sharp pain in my chest.','가슴에 날카로운 통증을 느꼈어요.','My muscles are sore from yesterday''s workout.','어제 운동 때문에 근육이 쑤셔요.','My lower back has been aching all day from sitting too long.','너무 오래 앉아 있어서 허리가 하루 종일 쑤셨어요.','My throat is sore, so it hurts whenever I swallow.','목이 뻐근해서 침을 삼킬 때마다 아파요.'),
('nuc_body_05','tired','exhausted','drained','피곤한 (일반적)','기진맥진한 (극도로 지친)','진이 빠진 (감정적·정신적으로)','''tired''는 일반적인 피곤함, ''exhausted''는 신체적으로 한계, ''drained''는 감정·정신적 소진이에요.','''exhausted''는 ''very tired''의 격식 표현, ''drained''는 에너지가 ''빠져나간'' 비유적 느낌이에요.','C1','body',2,0,'tired exhausted drained fatigue','I''m tired after a long day at work.','저는 직장에서 긴 하루를 보내고 나서 피곤해요.','She was exhausted after the marathon.','그녀는 마라톤 후에 기진맥진했어요.','I feel emotionally drained after that argument.','저는 그 말다툼 후에 감정적으로 진이 빠진 느낌이에요.','By midnight I was completely exhausted and could barely stand.','자정이 되자 저는 완전히 기진맥진해서 거의 서 있기도 힘들었어요.','Caring for the patients all week left the nurses emotionally drained.','일주일 내내 환자들을 돌보느라 간호사들은 감정적으로 진이 빠졌어요.'),
('nuc_body_06','skin','complexion',NULL,'피부 (조직 자체)','안색·피부톤 (얼굴 외양)',NULL,'''skin''은 신체의 외피 조직 전체, ''complexion''은 주로 얼굴의 피부 색조와 상태를 격식 있게 말해요.','의학적·일반적 맥락은 ''skin'', 화장품·미용 광고에서는 ''complexion''이 자주 쓰여요.','C2','body',3,0,'skin complexion face beauty','Sunscreen protects your skin from UV rays.','자외선 차단제는 자외선으로부터 피부를 보호해 줘요.','She has a clear, radiant complexion.','그녀는 맑고 빛나는 피부를 가지고 있어요.','Cold weather often leaves my skin feeling dry and tight.','추운 날씨는 제 피부를 건조하고 당기게 만들곤 해요.','Years of careful skincare gave her a flawless complexion.','수년간의 꼼꼼한 피부 관리가 그녀에게 흠 없는 안색을 선사했어요.','Dry winter air can damage the skin and dull your complexion.','건조한 겨울 공기는 피부를 상하게 하고 안색을 칙칙하게 만들 수 있어요.'),
('nuc_cafe_14','tasty','delicious',NULL,'맛있는 (일상)','정말 맛있는 (강조)',NULL,'tasty는 일반적으로 맛있는 정도, delicious는 더 강한 칭찬 (매우 맛있는).','tasty < delicious 강도. delicious는 칭찬을 강조할 때 자주 써요. 음식 후기엔 delicious가 만점.','A2','cafe',1,0,'delicious food tasty meal happy eating','That sandwich was tasty.','그 샌드위치는 맛있었어요.','This cake is absolutely delicious!','이 케이크 정말 너무 맛있어요!','The street food at the market was cheap and surprisingly tasty.','시장의 길거리 음식은 저렴하고 의외로 맛있었어요.','The soup was tasty, but the dessert was delicious.','수프는 맛있었고, 디저트는 정말 맛있었어요.','Everyday meals are tasty; special meals are delicious.','일상 식사는 맛있고, 특별한 식사는 정말 맛있어요.'),
('nuc_cafe_15','huge','big',NULL,'엄청 큰 (강조)','큰 (일반)',NULL,'big은 큰 정도, huge는 매우 큰 (강조). big < huge.','big < huge 강도. enormous, gigantic도 비슷한 강조 (huge보다 더 강함).','A2','cafe',1,0,'huge portion big food meal large','We had a big pizza.','우리는 큰 피자를 먹었어요.','That portion is huge!','그 양은 정말 엄청나요!','They served the dessert on a huge sharing plate.','그들은 디저트를 커다란 공유 접시에 담아 냈어요.','The cake was big, but the wedding cake was huge.','케이크가 컸지만 결혼식 케이크는 어마어마했어요.','A big coffee for me; a huge espresso for him.','저는 큰 커피요; 그는 엄청 큰 에스프레소예요.'),
('nuc_cafe_01','drink','beverage',NULL,'마시다 / 음료 (일상)','음료 (격식)',NULL,'drink는 일상 구어, beverage는 격식·메뉴판·상업용 표현이에요.','메뉴판·광고에서 beverage, 일상 주문에서 drink가 자연스러워요.','B1','cafe',1,1,'coffee drinks beverages cafe menu','What would you like to drink?','무엇을 마시고 싶으세요?','Our beverages include coffee, tea, and juice.','저희 음료에는 커피, 차, 주스가 있어요.','"Can I get you anything to drink?" she asked, pointing to the beverage menu on the wall.','"마실 것 좀 드릴까요?"라고 그녀는 벽에 붙은 음료 메뉴를 가리키며 물었어요.','What kind of drink would you like with your meal?','식사와 함께 어떤 음료를 드시겠어요?','They serve a wide selection of beverages all day.','그들은 종일 다양한 음료를 제공해요.'),
('nuc_cafe_02','strong','bold',NULL,'진한 (커피)','풍미 강한 (커피)',NULL,'strong coffee는 카페인이나 농도가 진한 커피, bold는 풍부하고 묵직한 맛을 강조해요.','카페 메뉴에서 bold는 맛 설명, strong은 농도를 가리켜요.','B1','cafe',2,2,'coffee strong bold flavor espresso','I need a strong coffee to wake up.','잠을 깨려면 진한 커피가 필요해요.','This blend has a bold, smoky flavor.','이 블렌드는 진하고 스모키한 풍미가 있어요.','I like my coffee strong in the morning, with a bold, roasty flavor.','저는 아침에 진하고 묵직한 로스티 풍미의 커피를 좋아해요.','I asked for a strong coffee with no sugar.','저는 설탕 없는 진한 커피를 부탁했어요.','This dark roast has a bold, smoky finish.','이 다크 로스트는 풍부하고 스모키한 풍미가 있어요.'),
('nuc_cafe_03','order','ask for',NULL,'주문하다','요청하다',NULL,'order는 공식적으로 음식이나 음료를 주문하는 것, ask for는 무언가를 부탁하거나 요청하는 것이에요.','order는 카운터·종업원에게, ask for는 추가 요청이나 부탁에 써요.','B1','cafe',1,3,'order coffee cafe counter','I''d like to order a latte, please.','라테 한 잔 주문할게요.','Can I ask for an extra napkin?','냅킨 한 장 더 부탁드려도 될까요?','I''d like to order a cappuccino, and could I also ask for some extra sugar?','카푸치노 한 잔 주문하고 싶은데, 설탕도 조금 더 부탁드려도 될까요?','I''d like to order two croissants and a flat white.','크루아상 두 개와 플랫 화이트 하나 주문할게요.','Could I ask for a second napkin, please?','냅킨 한 장 더 부탁드려도 될까요?'),
('nuc_cafe_04','takeaway','to go',NULL,'포장 (영국식)','포장 (미국식)',NULL,'"takeaway"는 영국 영어, "to go"는 미국 영어로 포장 주문을 뜻해요.','한국 스타벅스는 "for here or to go?"라는 미국식 표현을 써요.','B1','cafe',2,4,'takeaway to go coffee cup','One coffee, takeaway please.','커피 한 잔 포장해 주세요.','Can I get that to go?','그거 포장해 주실 수 있나요?','I''ll grab a takeaway flat white on my way to work.','출근길에 플랫 화이트 한 잔을 포장해 가야겠어요.','A latte, please — takeaway.','라테 하나요 — 포장이요.','Is that for here or to go?','드시고 가실 건가요, 포장이세요?'),
('nuc_cafe_05','hot','iced',NULL,'따뜻한','아이스',NULL,'hot과 iced는 음료 온도를 나타내는 기본 구분이에요. 영어 카페에서는 hot / iced로 구분해요.','미국·영국 카페에서는 "hot" 또는 "iced"로 명확하게 말해야 해요.','B1','cafe',2,5,'hot iced coffee temperature drink','I''ll have a hot Americano, please.','따뜻한 아메리카노 한 잔 주세요.','Give me an iced latte.','아이스 라테 한 잔 주세요.','It''s too cold for an iced drink today, so I''ll have a hot tea instead.','오늘은 아이스 음료를 마시기엔 너무 추워서 대신 따뜻한 차를 마실게요.','A hot chocolate sounds wonderful right now.','뜨거운 초콜릿이 지금 딱이겠어요.','I''ll have an iced americano with two extra shots.','아이스 아메리카노에 샷 두 번 추가로 주세요.'),
('nuc_cafe_06','bitter','sour',NULL,'쓴','신',NULL,'bitter는 커피·다크초콜릿의 쓴맛, sour는 식초·레몬처럼 신맛이에요.','과추출(over-extracted) 커피는 bitter, 미추출(under-extracted)은 sour해져요.','B2','cafe',1,6,'bitter sour taste coffee flavor','This espresso is too bitter for me.','이 에스프레소는 저한테 너무 써요.','The cold brew tastes slightly sour.','콜드 브루가 살짝 신맛이 나요.','The espresso was bitter, while the lemon tart afterward tasted sharply sour.','에스프레소는 썼고, 그 뒤에 먹은 레몬 타르트는 시큼할 정도로 신맛이 났어요.','This dark chocolate is quite bitter.','이 다크 초콜릿은 꽤 써요.','The yogurt tastes a little sour, but I like it.','요거트가 약간 시지만 저는 좋아요.'),
('nuc_cafe_06b','cozy','comfortable',NULL,'아늑한','편안한',NULL,'cozy는 작고 따뜻하며 아늑한 분위기, comfortable은 넓게 편안한 상태를 뜻해요.','cozy는 분위기, comfortable은 물리적 편안함을 강조해요.','B2','cafe',2,10,'cozy comfortable cafe atmosphere','This cafe has a cozy atmosphere.','이 카페는 아늑한 분위기예요.','The chairs here are very comfortable.','여기 의자들은 정말 편안해요.','The corner sofa is cozy in winter, and the wide armchairs are comfortable for working all afternoon.','코너 소파는 겨울에 아늑하고, 넓은 안락의자는 오후 내내 일하기에 편안해요.','This little cafe is so cozy on rainy days.','비 오는 날 이 작은 카페는 정말 아늑해요.','These chairs are surprisingly comfortable for long study sessions.','이 의자들은 긴 공부 시간에 놀랍게 편안해요.'),
('nuc_cafe_07','decaf','caffeine-free',NULL,'디카페인 (카페인 제거)','무카페인 (원래 없음)',NULL,'decaf는 원래 카페인이 있는 음료에서 제거한 것, caffeine-free는 처음부터 카페인이 없는 음료예요.','카페인 걱정이 있다면 decaf coffee vs caffeine-free tea를 구분해 주문해요.','B2','cafe',2,7,'decaf caffeine coffee tea health','Do you have decaf espresso?','디카페인 에스프레소 있나요?','Herbal tea is naturally caffeine-free.','허브차는 원래 카페인이 없어요.','Could you make my cappuccino decaf, please?','제 카푸치노를 디카페인으로 만들어 주시겠어요?','I''ll have a decaf latte before bed.','저는 자기 전에 디카페인 라테 마실게요.','Most herbal teas are caffeine-free.','대부분의 허브차는 무카페인이에요.'),
('nuc_cafe_08','espresso','americano',NULL,'에스프레소','아메리카노',NULL,'espresso는 압력으로 뽑은 진한 원액, Americano는 에스프레소에 물을 희석한 음료예요.','Americano는 에스프레소의 진한 맛에 물을 더해 마시기 편하게 한 것이에요.','B2','cafe',1,8,'espresso americano coffee shot','A double espresso, please.','더블 에스프레소 한 잔 주세요.','I''ll have an Americano with an extra shot.','샷 추가한 아메리카노로 할게요.','If a single espresso feels too intense, try an Americano with hot water added.','싱글 에스프레소가 너무 진하게 느껴지시면, 뜨거운 물을 넣은 아메리카노를 드셔 보세요.','A double espresso, please — I''m exhausted.','더블 에스프레소 부탁해요 — 너무 피곤해요.','I usually have an Americano with breakfast.','저는 보통 아침 식사와 함께 아메리카노를 마셔요.'),
('nuc_cafe_09','aroma','flavor',NULL,'향','맛',NULL,'aroma는 코로 느끼는 향기, flavor는 입으로 느끼는 맛이에요. 커피 평가에서 둘 다 중요해요.','aroma는 후각, flavor는 미각이에요 — 커피 리뷰에서 함께 써요.','B2','cafe',2,9,'aroma flavor coffee sensory','The aroma of freshly brewed coffee is wonderful.','갓 내린 커피의 향은 정말 좋아요.','This blend has a chocolatey flavor.','이 블렌드는 초콜릿 같은 풍미가 있어요.','The rich aroma promised a lot, but the flavor turned out surprisingly mild.','진한 향은 기대를 많이 하게 했지만, 맛은 의외로 부드러웠어요.','The aroma of cinnamon filled the entire cafe.','시나몬 향이 카페 전체를 가득 채웠어요.','This blend has a chocolatey, nutty flavor.','이 블렌드는 초콜릿 향과 견과류 풍미가 있어요.'),
('nuc_cafe_11','artisan','specialty',NULL,'장인 (수제)','스페셜티 (고품질)',NULL,'artisan은 장인이 손으로 만든 것, specialty는 특별히 엄선된 고품질을 뜻해요.','specialty coffee는 국제 기준(SCA) 80점 이상의 고품질 원두를 가리켜요.','C1','cafe',1,11,'artisan specialty coffee bread craft','This artisan bakery makes bread by hand.','이 장인 베이커리는 빵을 손으로 만들어요.','We only serve specialty coffee here.','저희는 여기서 스페셜티 커피만 제공해요.','They roast specialty beans in-house and pair them with artisan pastries made by hand.','그들은 스페셜티 원두를 매장에서 직접 로스팅하고, 손으로 만든 장인 페이스트리와 함께 내요.','They sell artisan bread baked fresh every morning.','그들은 매일 아침 신선하게 구운 장인 빵을 팔아요.','This specialty coffee comes from a single farm in Ethiopia.','이 스페셜티 커피는 에티오피아의 한 농장에서 와요.'),
('nuc_cafe_12','ambient','atmosphere',NULL,'주변 환경 (음악·조명)','분위기 (전체)',NULL,'ambient는 배경 소리·빛 등 환경 요소, atmosphere는 장소 전체의 분위기를 뜻해요.','ambient music은 배경음악, atmosphere는 카페 전체 느낌을 표현해요.','C1','cafe',2,12,'ambient atmosphere cafe music lighting','The cafe has soft ambient music.','그 카페에는 잔잔한 배경 음악이 흘러요.','The atmosphere in this place is very relaxed.','이곳의 분위기는 아주 편안해요.','The soft ambient lighting adds to the warm atmosphere of the whole room.','은은한 조명이 방 전체의 따뜻한 분위기를 더해 줘요.','The ambient music made the studying easier.','배경 음악이 공부를 더 쉽게 만들었어요.','The atmosphere in that bookshop is calm and inviting.','그 서점의 분위기는 차분하고 따뜻해요.'),
('nuc_cafe_13','connoisseur','enthusiast',NULL,'전문 감식가','열정 애호가',NULL,'connoisseur는 전문적 감식 능력을 갖춘 사람, enthusiast는 단순히 매우 좋아하는 사람이에요.','connoisseur는 전문성 강조, enthusiast는 열정 강조예요.','C2','cafe',1,13,'connoisseur enthusiast coffee expert','She''s a coffee connoisseur who can identify the origin by taste.','그녀는 맛으로 원산지를 알아맞히는 커피 감정가예요.','He''s a coffee enthusiast who visits new cafes every week.','그는 매주 새로운 카페를 찾아다니는 커피 애호가예요.','As a wine connoisseur, she can pinpoint the vintage in one sip.','와인 감정가인 그녀는 한 모금으로 빈티지를 정확히 짚어내요.','A coffee connoisseur can tell beans apart by aroma alone.','커피 전문 감식가는 향만으로도 원두를 구별할 수 있어요.','He''s a coffee enthusiast who visits a new cafe each weekend.','그는 매 주말 새 카페를 방문하는 커피 애호가예요.'),
('nuc_cooking_01','cook','bake','fry','요리하다(일반)','오븐에 굽다','기름에 튀기다/볶다','''cook''은 요리 전반을 뜻하는 가장 일반적인 단어예요. ''bake''는 오븐에서 마른 열로 굽는 것(빵·케이크·쿠키), ''fry''는 기름에 튀기거나 볶는 것(계란·치킨·채소)을 가리켜요.','요리 방법을 정확히 말하고 싶을 땐 ''cook'' 대신 ''bake''나 ''fry''로 구체화하세요. 한국어 ''굽다''와 ''튀기다''의 구분과 비슷해요.','B1','cooking',1,0,'cooking baking frying methods','I cook dinner every night.','저는 매일 밤 저녁을 요리해요.','She bakes bread on weekends.','그녀는 주말마다 빵을 구워요.','He fries eggs for breakfast.','그는 아침으로 달걀을 부쳐요.','My mother taught me how to cook, but I prefer to bake desserts.','어머니께서 요리하는 법을 가르쳐 주셨지만, 저는 디저트를 굽는 걸 더 좋아해요.','Instead of frying the potatoes, you can bake them in the oven.','감자를 기름에 튀기는 대신 오븐에 구울 수 있어요.'),
('nuc_cooking_02','taste','flavor','savor','맛(느낌)','풍미(특징)','음미하다(동사)','''taste''는 혀로 느끼는 ''맛'' 자체예요. ''flavor''는 그 음식 고유의 ''풍미·특징''을 뜻하고, ''savor''는 동사로 ''천천히 음미하다''라는 의미예요.','''taste''는 일반적인 맛, ''flavor''는 그 요리만의 개성을, ''savor''는 ''즐겨 음미한다''는 동작을 나타내요. 한국어 ''맛''을 어떻게 풀어 쓸지 결정하는 데 도움이 돼요.','B2','cooking',2,0,'tasting wine flavor savor','The soup has a salty taste.','그 수프는 짠맛이 나요.','This wine has a fruity flavor.','이 와인은 과일 향이 나요.','I savor every bite of dessert.','저는 디저트를 한 입 한 입 음미해요.','Fresh herbs give the dish a richer flavor, and you can taste the difference right away.','신선한 허브가 요리에 더 깊은 풍미를 더해 주고, 그 차이를 바로 맛볼 수 있어요.','After such a long week, I want to savor this meal and enjoy every flavor slowly.','이렇게 긴 한 주를 보낸 뒤라, 이 식사를 천천히 음미하며 모든 풍미를 즐기고 싶어요.'),
('nuc_cooking_03','boil','simmer',NULL,'팔팔 끓이다','약하게 끓이다',NULL,'''boil''은 100도에서 큰 기포가 올라오게 ''팔팔'' 끓이는 거예요. ''simmer''는 그보다 약한 불에 보글보글 끓이는 거예요. 요리 결과가 완전히 달라져요.','레시피에서 ''bring to a boil, then simmer''(끓인 다음 약불로 줄여서 보글보글)는 가장 흔한 지시예요. 둘을 구분하면 요리 실력이 올라가요.','B2','cooking',2,0,'boiling simmering pot','Boil the water for pasta.','파스타용 물을 끓이세요.','Simmer the sauce for 30 minutes.','소스를 30분 동안 약하게 끓이세요.','Boil the eggs for exactly seven minutes for a soft center.','속이 부드럽게 되도록 달걀을 정확히 7분간 삶으세요.','Bring the soup to a boil before adding the noodles.','국수를 넣기 전에 국을 팔팔 끓여 주세요.','Let the stew simmer gently so the flavors blend slowly.','맛이 천천히 어우러지도록 스튜를 약한 불에 보글보글 끓여 주세요.'),
('nuc_cooking_04','slice','chop','dice','얇게 썰다','잘게 다지다','깍둑썰기 하다','''slice''는 ''얇은 조각''으로 써는 것(빵·고기·치즈), ''chop''은 ''잘게 다지는'' 것(양파·마늘·허브), ''dice''는 ''작은 정육면체''로 깍둑썰기하는 것(감자·당근)을 뜻해요.','레시피에서 자르는 방식이 결과를 크게 좌우해요. 한국어 ''썰다''만 쓰지 말고 영어로는 형태에 맞춰 구분해서 표현하세요.','C1','cooking',2,0,'slice chop dice cutting','Slice the bread thinly.','빵을 얇게 썰어 주세요.','Chop the garlic finely.','마늘을 곱게 다져 주세요.','Dice the carrots into small cubes.','당근을 작은 깍둑썰기로 썰어 주세요.','First slice the onion, then chop the parsley for the sauce.','먼저 양파를 얇게 썰고, 그다음 소스에 넣을 파슬리를 잘게 다져 주세요.','The recipe asks you to dice the potatoes and slice the mushrooms.','이 조리법은 감자를 깍둑썰기하고 버섯을 얇게 썰라고 안내해요.'),
('nuc_cooking_05','spicy','hot','pungent','향신료가 풍부한','얼얼하게 매운','톡 쏘는','''spicy''는 향신료(허브·후추)가 풍부해 ''풍미가 강한'' 느낌이에요. ''hot''은 고추처럼 ''얼얼하게 매운'' 정도가 강한 매움이고, ''pungent''는 마늘·겨자처럼 ''톡 쏘는 자극적인'' 향과 맛이에요.','한국어 ''맵다''는 영어에서 세 단어로 나뉘어요. 단순히 매운 정도가 강할 땐 ''hot'', 향신료가 풍부하면 ''spicy'', 톡 쏘는 자극이면 ''pungent''를 골라 쓰세요.','C1','cooking',2,0,'spicy chili pungent mustard','Indian food is often spicy.','인도 음식은 보통 매워요.','This curry is too hot for me.','이 카레는 저한테 너무 매워요.','Mustard has a pungent taste.','겨자는 톡 쏘는 맛이 나요.','The stew was richly spicy with cumin, ginger, and cinnamon.','그 스튜는 커민, 생강, 계피로 풍미가 풍부했어요.','The pungent smell of raw garlic filled the entire kitchen.','생마늘의 톡 쏘는 냄새가 부엌 전체에 가득 찼어요.'),
('nuc_cooking_06','tender','succulent','juicy','연한','즙이 풍부하고 풍미가 깊은','육즙이 많은','''tender''는 부드럽게 잘 씹히는 ''식감''이에요. ''juicy''는 ''육즙''이 많아 촉촉한 느낌이고, ''succulent''는 ''즙이 풍부하면서 풍미까지 깊은'' 격조 있는 표현으로 고급 요리 평론에 자주 써요.','''tender''는 식감 중심, ''juicy''는 수분 중심, ''succulent''는 둘 다에 풍미까지 더한 최상급 표현이에요. 음식 평론을 쓸 땐 ''succulent''로 격을 높이세요.','C2','cooking',3,0,'tender succulent juicy meat','The steak was incredibly tender.','그 스테이크는 믿을 수 없을 만큼 부드러웠어요.','The peaches were succulent and sweet.','그 복숭아는 즙이 많고 달콤했어요.','This burger is so juicy.','이 버거는 정말 육즙이 풍부해요.','The slow-braised lamb was wonderfully tender, falling apart at the touch of a fork.','천천히 조린 양고기는 포크만 대도 부서질 만큼 놀랍도록 연했어요.','The critic praised the succulent roast duck, its rich juices bursting with flavor.','그 평론가는 풍부한 육즙이 풍미로 가득한 즙 많고 깊은 맛의 구운 오리를 극찬했어요.'),
('nuc_culture_01','custom','tradition',NULL,'관습','전통',NULL,'custom은 일상적으로 따르는 관습·습관, tradition은 오래 이어져 내려온 문화적 전통이에요.','tradition은 오랜 역사·문화 배경, custom은 더 일상적 관습이에요.','B1','culture',1,1,'custom tradition culture heritage','It''s a local custom to remove your shoes indoors.','실내에서 신발을 벗는 것은 지역 관습이에요.','Chuseok is an important Korean tradition.','추석은 중요한 한국의 전통이에요.','Bowing when you greet someone is a long-standing custom.','인사할 때 고개를 숙이는 것은 오래된 관습이에요.','Removing your shoes is a custom in many Asian homes.','신발을 벗는 것은 많은 아시아 가정의 관습이에요.','Lunar New Year is a tradition that has lasted thousands of years.','음력 설은 수천 년 동안 이어진 전통이에요.'),
('nuc_culture_02','polite','respectful',NULL,'예의 바른','존중하는',NULL,'polite는 예절에 맞는 행동, respectful은 타인을 존중하는 태도를 뜻해요.','polite는 행동, respectful은 태도와 마음가짐을 강조해요.','B1','culture',2,2,'polite respectful manners culture','It''s polite to wait your turn in line.','줄을 서서 차례를 기다리는 것이 예의예요.','She was respectful of different cultural beliefs.','그녀는 서로 다른 문화적 신념을 존중했어요.','He was always polite, even when the customer was rude.','그는 손님이 무례하게 굴 때조차 늘 정중했어요.','It''s polite to thank the chef after a special meal.','특별한 식사 후 셰프에게 감사를 표하는 것은 예의예요.','She was respectful of every elder in the village.','그녀는 마을의 모든 어르신을 존중했어요.'),
('nuc_culture_03','festival','ceremony',NULL,'축제','의식 / 식',NULL,'festival은 흥겨운 축제 행사, ceremony는 형식을 갖춘 의식이에요.','festival은 즐거운 행사, ceremony는 엄숙한 형식을 강조해요.','B1','culture',1,3,'festival ceremony celebration culture','The Lantern Festival is beautiful.','등불 축제는 아름다워요.','The graduation ceremony was held in the main hall.','졸업식은 본관 강당에서 열렸어요.','Every spring, the village holds a flower festival by the river.','매년 봄, 마을에서는 강가에서 꽃 축제를 열어요.','The summer festival lit up the entire town.','여름 축제가 마을 전체를 밝혔어요.','The opening ceremony was elegant and well-organized.','개회식은 우아하고 잘 진행됐어요.'),
('nuc_culture_04','heritage','legacy',NULL,'유산 (문화·역사)','유산 (남긴 결과)',NULL,'heritage는 문화·역사적 유산, legacy는 개인이나 사건이 남긴 결과나 영향이에요.','heritage는 집단·문화, legacy는 개인·사건이 남긴 것이에요.','B2','culture',1,4,'heritage legacy culture history','Korea has a rich cultural heritage.','한국은 풍부한 문화유산을 가지고 있어요.','Her legacy as a scientist is still felt today.','과학자로서 그녀가 남긴 유산은 오늘날에도 느껴져요.','The old town is recognized as a world heritage site.','그 구시가지는 세계 유산으로 인정받고 있어요.','They wanted to share their cultural heritage with their kids.','그들은 자녀들과 문화유산을 나누고 싶어 했어요.','Her legacy as a teacher continues through her former students.','그녀의 교사로서의 유산은 옛 학생들을 통해 계속돼요.'),
('nuc_culture_05','multicultural','diverse',NULL,'다문화의','다양한',NULL,'multicultural은 여러 문화가 공존하는, diverse는 다양한 요소가 있다는 더 넓은 표현이에요.','multicultural은 문화 특화 표현, diverse는 인종·성별·의견 등 폭넓게 써요.','B2','culture',2,5,'multicultural diverse culture society','Toronto is known as a multicultural city.','토론토는 다문화 도시로 알려져 있어요.','The team benefits from diverse perspectives.','그 팀은 다양한 관점에서 도움을 받아요.','Growing up in a multicultural neighborhood broadened her outlook.','다문화 동네에서 자란 덕분에 그녀는 시야가 넓어졌어요.','New York is a deeply multicultural city.','뉴욕은 깊이 다문화적인 도시예요.','The team became stronger with more diverse perspectives.','팀은 더 다양한 관점으로 더 강해졌어요.'),
('nuc_culture_06','assimilate','integrate',NULL,'동화하다','통합하다',NULL,'assimilate는 주류 문화에 녹아들어 기존 문화를 잃는 것, integrate는 자신의 문화를 지키면서 사회에 참여하는 것이에요.','assimilation은 기존 정체성 포기, integration은 정체성 유지 + 사회 참여예요.','B2','culture',1,6,'assimilate integrate culture immigration','Immigrants were expected to assimilate into the dominant culture.','이민자들은 주류 문화에 동화될 것으로 기대되었어요.','The goal is to help newcomers integrate into society.','목표는 새로 온 사람들이 사회에 통합되도록 돕는 거예요.','Some families resist pressure to fully assimilate.','일부 가정은 완전히 동화되라는 압박에 저항해요.','Some societies expect newcomers to fully assimilate.','어떤 사회들은 새로 온 사람들이 완전히 동화하기를 기대해요.','Helping immigrants integrate enriches everyone.','이민자들의 통합을 돕는 것이 모두를 풍요롭게 해요.'),
('nuc_culture_07','stereotype','prejudice',NULL,'고정관념','편견',NULL,'stereotype은 특정 집단에 대한 과도한 일반화, prejudice는 근거 없이 갖는 부정적 선입견이에요.','stereotype은 인지적 일반화, prejudice는 감정적 부정 편견이에요.','B2','culture',2,7,'stereotype prejudice culture bias','Not all Koreans are good at math — that''s a stereotype.','모든 한국인이 수학을 잘하는 건 아니에요. 그건 고정관념이에요.','Prejudice against immigrants affects their job prospects.','이민자에 대한 편견은 그들의 취업 기회에 영향을 미쳐요.','We should question every stereotype we grew up believing.','우리는 자라면서 믿어 온 모든 고정관념에 의문을 가져야 해요.','Movies often rely on stereotypes for quick characterization.','영화는 빠른 캐릭터 묘사를 위해 종종 고정관념에 의존해요.','Prejudice can be reduced through meaningful contact.','편견은 의미 있는 접촉을 통해 줄어들 수 있어요.'),
('nuc_culture_08','taboo','etiquette',NULL,'금기','예절',NULL,'taboo는 사회적으로 금기시되는 것, etiquette는 지켜야 할 예절·예법이에요.','taboo는 하면 안 되는 것, etiquette는 해야 하는 것이에요.','B2','culture',1,8,'taboo etiquette culture manners','Discussing money is a taboo in some cultures.','어떤 문화권에서는 돈 이야기를 하는 것이 금기예요.','It''s good etiquette to arrive on time for meetings.','회의에 정시에 도착하는 것이 좋은 예절이에요.','Talking loudly on the phone in a quiet cafe is a social taboo here.','이곳에서는 조용한 카페에서 전화로 큰 소리로 통화하는 것이 사회적 금기예요.','In some cultures, discussing personal income is a taboo.','어떤 문화에서는 개인 소득을 논하는 것이 금기예요.','Business etiquette varies a lot across cultures.','비즈니스 예절은 문화마다 많이 달라요.'),
('nuc_culture_14','celebrate','commemorate',NULL,'축하·기념하다 (기쁨)','기리다 (엄숙·추모)',NULL,'celebrate는 즐거운 일을 축하 (생일, 결혼, 명절), commemorate는 엄숙히 기념 (역사적 사건, 추모일).','celebrate는 기쁨·축하, commemorate는 엄숙·추모. 광복절·전쟁기념일은 commemorate가 적절.','B2','culture',1,0,'celebration commemoration ceremony memorial respect','We celebrated her birthday at a restaurant.','우리는 식당에서 그녀의 생일을 축하했어요.','The country commemorates its independence every year.','그 나라는 매년 독립을 기념해요.','The whole town celebrates the harvest with a festival each autumn.','온 마을이 매년 가을 축제로 수확을 축하해요.','We celebrate the new year; we commemorate the fallen heroes.','새해는 축하하고, 전사한 영웅들은 기려요.','Celebrate joyful events; commemorate solemn occasions.','즐거운 행사는 축하하고, 엄숙한 일은 기려요.'),
('nuc_culture_15','modern','contemporary',NULL,'현대의 (시기적)','동시대의 (지금 살아있는)',NULL,'modern은 "현대 = 산업혁명 이후" 정도, contemporary는 "지금 이 시대에 살아있는·만들어진".','modern은 폭넓은 시대 구분 (현대), contemporary는 "지금 우리 시대" 강조. 미술·건축·문학에서 자주 구분돼요.','B2','culture',1,0,'modern art contemporary gallery architecture','Modern art started in the late 19th century.','현대 미술은 19세기 후반에 시작됐어요.','Contemporary art refers to art made today.','동시대 미술은 오늘날 만들어지는 미술을 말해요.','The gallery''s modern wing was renovated last year.','그 갤러리의 현대 미술관은 작년에 보수됐어요.','Modern architecture differs from contemporary architecture.','현대 건축은 동시대 건축과 달라요.','She studies modern history but loves contemporary novels.','그녀는 현대사를 공부하지만 동시대 소설을 좋아해요.'),
('nuc_culture_09','indigenous','native',NULL,'원주민의 / 토착의','토착의 / 현지의',NULL,'indigenous는 특히 원주민 문화·권리를 강조하는 표현, native는 더 넓게 어떤 지역 출신을 뜻해요.','indigenous는 원주민 집단, native speaker는 모국어 화자를 가리켜요.','C1','culture',2,9,'indigenous native culture community','Indigenous communities have lived there for thousands of years.','원주민 공동체는 수천 년 동안 그곳에서 살아왔어요.','She is a native speaker of Korean.','그녀는 한국어 원어민이에요.','The museum returned the artifacts to the indigenous people.','그 박물관은 유물을 원주민들에게 반환했어요.','Indigenous knowledge is helping researchers understand local ecosystems.','원주민 지식이 연구자들이 지역 생태계를 이해하는 데 도움을 주고 있어요.','She''s a native speaker of three languages.','그녀는 세 가지 언어의 모국어 화자예요.'),
('nuc_culture_10','acculturation','globalization',NULL,'문화 변용','세계화',NULL,'acculturation은 두 문화가 만나 변화하는 과정, globalization은 전 세계가 연결·균질화되는 현상이에요.','acculturation은 문화 간 접촉 변화, globalization은 전 세계적 연결이에요.','C1','culture',1,10,'acculturation globalization culture change','Acculturation occurs when immigrant groups adopt local norms.','문화 적응은 이민자 집단이 현지 규범을 받아들일 때 일어나요.','Globalization has spread Korean pop culture worldwide.','세계화는 한국 대중문화를 전 세계로 퍼뜨렸어요.','Second-generation immigrants often experience acculturation more smoothly.','이민 2세대는 흔히 문화 적응을 더 수월하게 경험해요.','Acculturation can lead to interesting blends of food and music.','문화 변용은 흥미로운 음식과 음악의 융합으로 이어질 수 있어요.','Globalization has connected economies and cultures in new ways.','세계화는 경제와 문화를 새로운 방식으로 연결했어요.'),
('nuc_culture_11','cosmopolitan','parochial',NULL,'세계적인 / 개방적인','지역 편향적인 / 협소한',NULL,'cosmopolitan은 다양한 문화에 개방적인 세계 시민적 태도, parochial은 좁은 지역·관점에 갇힌 것이에요.','cosmopolitan은 다양성 수용, parochial은 폐쇄성을 뜻해요.','C1','culture',2,11,'cosmopolitan parochial culture global','Seoul is a cosmopolitan city with global influences.','서울은 세계적인 영향이 어우러진 국제적인 도시예요.','A parochial mindset can limit international understanding.','편협한 사고방식은 국제적 이해를 제한할 수 있어요.','His cosmopolitan upbringing made him comfortable anywhere in the world.','국제적인 환경에서 자란 덕분에 그는 세계 어디서든 편안해해요.','Cosmopolitan cities tend to attract people from many countries.','세계적인 도시들은 많은 나라 사람들을 끌어들이는 경향이 있어요.','A parochial worldview can limit personal growth.','협소한 세계관은 개인 성장을 제한할 수 있어요.'),
('nuc_culture_12','ethnocentrism','cultural relativism',NULL,'자문화 중심주의','문화 상대주의',NULL,'ethnocentrism은 자기 문화가 기준이라 생각하는 것, cultural relativism은 각 문화를 그 맥락에서 이해하는 것이에요.','문화 비교 글쓰기·발표에서 이 두 개념이 자주 등장해요.','C2','culture',1,12,'ethnocentrism cultural relativism anthropology','Ethnocentrism can lead to misunderstanding other cultures.','자민족 중심주의는 다른 문화에 대한 오해로 이어질 수 있어요.','Cultural relativism helps anthropologists study societies without judgment.','문화 상대주의는 인류학자들이 편견 없이 사회를 연구하도록 도와줘요.','Travel can gradually break down our ethnocentrism.','여행은 우리의 자민족 중심주의를 점차 허물어 줄 수 있어요.','Ethnocentrism makes it hard to appreciate other ways of life.','자문화 중심주의는 다른 삶의 방식을 감상하기 어렵게 만들어요.','Cultural relativism encourages us to suspend judgment.','문화 상대주의는 우리가 판단을 유보하도록 격려해요.'),
('nuc_culture_13','zeitgeist','paradigm',NULL,'시대정신','패러다임',NULL,'zeitgeist는 특정 시대의 지배적 정신·분위기, paradigm은 사고·행동 방식의 근본적 틀이에요.','zeitgeist는 시대 분위기, paradigm shift는 근본적 사고 전환이에요.','C2','culture',2,13,'zeitgeist paradigm culture philosophy','K-pop captures the cultural zeitgeist of the 2020s.','케이팝은 2020년대의 문화적 시대정신을 담아내고 있어요.','A scientific paradigm shift changed how we view the universe.','과학적 패러다임의 전환이 우리가 우주를 보는 방식을 바꿨어요.','Fashion trends often reflect the zeitgeist of an era.','패션 트렌드는 흔히 한 시대의 시대정신을 반영해요.','Each generation captures its own zeitgeist in music.','각 세대는 음악으로 자기 시대정신을 포착해요.','The rise of AI represents a new paradigm in work.','AI의 부상은 일에서의 새로운 패러다임을 나타내요.'),
('nuc_discussion_21','still','yet','already','아직 (계속됨)','아직 (안 일어남)','벌써 (이미 일어남)','still은 계속 진행 중, yet은 아직 안 일어남 (부정/의문), already는 예상보다 빨리 일어남.','still=진행 중, yet=안 됨(부정/의문), already=벌써(예상보다 빠름). 한국어 "아직"이 둘로 갈려서 헷갈림.','A2','discussion',1,0,'time still continuing already complete waiting','He''s still working.','그는 아직 일하고 있어요.','He hasn''t finished yet.','그는 아직 끝내지 못했어요.','He''s already finished.','그는 이미 끝냈어요.','I''m still studying, haven''t finished yet, but my friend has already left.','전 아직 공부 중이고, 아직 끝내지 못했지만, 친구는 벌써 떠났어요.','Are you still here? — Yet? — Already done? Each gives a different vibe.','아직 있어요? — 아직? — 벌써 끝냈어요? — 각각 분위기가 달라요.'),
('nuc_discussion_01','discuss','argue',NULL,'토론하다','언쟁하다',NULL,'discuss는 여러 시각을 나누는 건설적인 토론, argue는 반박·언쟁에 가까운 표현이에요.','discuss는 협력적, argue는 대립적 뉘앙스예요. "discuss"가 더 중립적이에요.','B1','discussion',1,1,'discuss argue debate conversation','Let''s discuss the pros and cons.','장단점을 논의해 봅시다.','They argued about the best solution.','그들은 최선의 해결책을 두고 논쟁했어요.','The committee will discuss the proposal at tomorrow''s meeting.','위원회는 내일 회의에서 그 제안을 논의할 거예요.','Let''s discuss the next steps over coffee.','커피 마시며 다음 단계를 논의해요.','They argued for hours but couldn''t agree.','그들은 몇 시간 동안 언쟁했지만 동의할 수 없었어요.'),
('nuc_discussion_02','opinion','point of view',NULL,'의견','관점',NULL,'opinion은 특정 주제에 대한 생각, point of view는 어떤 입장에서 바라보는 관점이에요.','"In my opinion"은 개인 의견, "From X point of view"는 특정 입장 표현이에요.','B1','discussion',2,2,'opinion viewpoint discussion perspective','In my opinion, we should wait.','제 생각에는 우리가 기다려야 할 것 같아요.','From the customer''s point of view, this is unfair.','고객의 관점에서 보면, 이건 부당해요.','Everyone in the room had a different opinion about the plan.','그 방 안의 모든 사람이 그 계획에 대해 서로 다른 의견을 갖고 있었어요.','I''d love to hear your opinion on the new policy.','새 정책에 대한 당신의 의견을 듣고 싶어요.','From a parent''s point of view, the school is excellent.','부모의 관점에서 그 학교는 훌륭해요.'),
('nuc_discussion_14','do','make',NULL,'하다 (행위·임무)','만들다 (창조·생산)',NULL,'do는 추상적 행동·과제·임무를 할 때, make는 무언가를 새로 창조·생산할 때 써요.','do는 활동·임무, make는 창조·생산. 결과물이 손에 잡히면 make가 자연스러워요.','B1','discussion',1,0,'cooking chores activity making','I have to do my homework before dinner.','저는 저녁 먹기 전에 숙제를 해야 해요.','Can you make me a sandwich?','샌드위치 좀 만들어 주실 수 있어요?','I still need to do the dishes before I go out.','저는 나가기 전에 아직 설거지를 해야 해요.','You do exercise, but you make a cake.','운동은 do로, 케이크는 make로 만들어요.','She does the laundry while he makes dinner.','그녀는 빨래를 하고, 그는 저녁을 만들어요.'),
('nuc_discussion_15','explain','describe',NULL,'설명하다 (이유·원리)','묘사하다 (모습·특징)',NULL,'explain은 "왜·어떻게"를 설명할 때, describe는 "어떻게 생겼는지·어떤 모습인지" 묘사할 때 써요.','explain은 원리·이유, describe는 모습·특징. "왜?"는 explain, "어떻게 생겼어?"는 describe.','B1','discussion',1,0,'teacher explaining describing chalkboard','Can you explain why this works?','이게 왜 되는지 설명해 주실 수 있어요?','Can you describe what he looks like?','그가 어떻게 생겼는지 묘사해 주실 수 있어요?','Let me explain how the new payment system works.','새 결제 시스템이 어떻게 작동하는지 설명해 드릴게요.','I explained the process; she described the result.','저는 과정을 설명했고, 그녀는 결과를 묘사했어요.','The teacher explained the rule and described an example.','선생님은 규칙을 설명하고 예시를 묘사했어요.'),
('nuc_discussion_16','continue','keep',NULL,'계속하다','계속 ~하다',NULL,'continue는 동작/상태가 이어진다, keep + -ing는 "멈추지 않고 계속" 하는 느낌으로 더 일상적이에요.','continue는 동작을 이어가는 자체, keep + -ing는 반복/지속의 뉘앙스가 강해요.','B1','discussion',1,0,'persistence ongoing work flow','Please continue your story.','이야기를 계속해 주세요.','He kept talking for an hour.','그는 한 시간 동안 계속 이야기했어요.','We will continue the discussion after lunch.','점심 후에 논의를 계속하겠습니다.','I continued working; he kept distracting me.','저는 일을 계속했고, 그는 계속 방해했어요.','She continued the project but couldn''t keep going alone.','그녀는 프로젝트를 계속했지만 혼자 계속할 수는 없었어요.'),
('nuc_discussion_17','somewhat','rather','kind of','다소, 약간 (격식)','꽤, 다소 (격식)','약간, 좀 (구어)','somewhat은 약한 정도 (격식), rather는 다소 강한 정도 (격식·영국식), kind of/sort of는 캐주얼한 "좀".','somewhat/rather는 격식체, kind of/sort of는 구어. rather는 영국식에서 quite의 역할 대신 쓰여요.','B1','discussion',1,0,'thoughtful hedge approximate moderate degree','I''m somewhat tired today.','저는 오늘 좀 피곤해요.','The film was rather disappointing.','그 영화는 다소 실망스러웠어요.','I''m kind of nervous.','저는 약간 긴장돼요.','It''s somewhat cold, rather expensive, and kind of weird.','좀 춥고, 다소 비싸고, 약간 이상해요.','Use "somewhat" in writing, "rather" in formal speech, and "kind of" in casual chat.','글은 somewhat, 격식 대화는 rather, 일상은 kind of를 써요.'),
('nuc_discussion_18','quite','fairly','pretty','꽤, 매우 (영국)/조금 (미국)','상당히 (중간)','꽤 (구어)','quite는 영국에서는 "꽤 강함", 미국에서는 "조금"으로 의미가 갈려요. fairly는 안전한 중간, pretty는 캐주얼.','quite의 의미는 지역에 따라 달라요. 안전하게 쓰려면 fairly(중간) 또는 pretty(캐주얼·미국식)를 사용.','B1','discussion',1,0,'approximation degree intensifier conversation','The film was quite good.','그 영화는 꽤 좋았어요.','The exam was fairly difficult.','그 시험은 비교적 어려웠어요.','That''s pretty cool.','그거 꽤 멋지네요.','In American English, "quite" is weaker than in British English.','미국 영어에서 quite는 영국식보다 약해요.','The food was fairly tasty, the wine was quite good, and dessert was pretty amazing.','음식은 그럭저럭, 와인은 꽤 좋았고, 디저트는 정말 멋졌어요.'),
('nuc_discussion_19','maybe','perhaps',NULL,'아마도 (일상)','어쩌면 (격식)',NULL,'maybe와 perhaps는 동의어. maybe는 일상·구어체, perhaps는 격식·문어체에서 더 자주 써요.','maybe = perhaps 의미상 동일, 격식 차이만. 회의·이메일은 perhaps가 적절.','B1','discussion',1,0,'thinking hesitation maybe uncertain','Maybe we should leave.','어쩌면 우리는 떠나야 할 것 같아요.','Perhaps we should consider another option.','아마 다른 선택지를 고려해 봐야 할 것 같아요.','Maybe we can grab lunch together tomorrow.','어쩌면 내일 같이 점심을 먹을 수 있을 것 같아요.','Maybe she''s busy; perhaps she''ll call later.','어쩌면 그녀가 바쁜가 봐요; 아마 나중에 전화할 거예요.','Use "maybe" with friends, "perhaps" in essays or formal speech.','친구와는 maybe, 글이나 격식 대화는 perhaps를 써요.'),
('nuc_discussion_20','probably','likely','possibly','아마, 거의 확실 (80%)','~할 듯, 가능성 높음 (70%)','어쩌면 (가능성 있음, 50%)','probably > likely > possibly 확률 강도. probably는 거의 확실, possibly는 가능성만 있음.','probably > likely > possibly. "I will probably"는 거의 약속, "I might possibly"는 흐릿한 가능성.','B1','discussion',1,0,'probability uncertainty chance prediction','It''ll probably rain tomorrow.','내일 아마 비가 올 거예요.','It''s likely to rain tomorrow.','내일 비가 올 가능성이 높아요.','It might possibly rain tomorrow.','내일 어쩌면 비가 올 수도 있어요.','I''ll probably come (80%), it''s likely (70%), possibly (50%).','probably 80%, likely 70%, possibly 50% 확률.','He''ll probably win; she''s likely to win; they could possibly win too.','그는 거의 확실히 이기고, 그녀도 이길 가능성 높고, 그들도 어쩌면 이길 수도.'),
('nuc_discussion_22','just','only',NULL,'단지, 막 (시간/유일)','오직, 단지 (유일)',NULL,'just는 "방금" (시간) 또는 "단지", only는 "오직 ~만". 의미 겹치는 부분 있지만 강조점 다름.','just는 시간 강조("방금")나 부드러운 표현. only는 배타적 한정("그것만"). just one은 "한 개만", only one은 "오직 하나".','B1','discussion',1,0,'only just single moment exclusive','I just got home.','저는 방금 집에 도착했어요.','Only members can enter.','회원만 입장할 수 있어요.','I just wanted to say thank you for your help.','도와주셔서 그저 감사하다는 말을 하고 싶었어요.','I just need only one minute.','단지 1분만 있으면 돼요.','She just called; only she knew the answer.','그녀가 방금 전화했어요; 답을 아는 사람은 오직 그녀뿐이었어요.'),
('nuc_discussion_23','almost','nearly',NULL,'거의 (미국식 선호)','거의 (영국식 선호)',NULL,'almost와 nearly는 거의 같은 의미. almost가 미국에서 더 자주, nearly는 영국에서 더 자주 쓰여요.','almost ≈ nearly 의미상 동일. 다만 nothing/no/never 앞에는 almost만 자연스러움 ("almost never" OK, "nearly never" 어색).','B1','discussion',1,0,'almost nearly close approximation just barely','I almost missed the bus.','저는 버스를 거의 놓칠 뻔했어요.','I nearly missed the bus.','저는 버스를 하마터면 놓칠 뻔했어요.','It''s almost midnight, so we should head home.','거의 자정이 다 됐으니 집에 가는 게 좋겠어요.','We''re almost done; we''re nearly there.','거의 끝나가요; 거의 다 왔어요.','She almost cried, nearly fell, and almost forgot to leave.','그녀는 거의 울 뻔했고, 거의 넘어질 뻔했고, 거의 떠나는 걸 잊을 뻔했어요.'),
('nuc_discussion_24','used to','would',NULL,'~하곤 했다 (상태/습관)','~하곤 했다 (습관만)',NULL,'used to는 과거 상태·습관 모두, would는 과거 습관만. would는 상태 동사(love, be)와 안 쓰임.','used to = 상태+습관, would = 습관만. "I would be tall" 같은 상태 표현은 안 됨. used to be가 정확.','B1','discussion',1,0,'past habit memory nostalgic used to','I used to live in Paris.','저는 예전에 파리에 살았어요.','When I was young, I would play outside for hours.','어렸을 때 저는 몇 시간씩 밖에서 놀곤 했어요.','My grandfather used to tell us stories every evening.','제 할아버지는 저녁마다 저희에게 이야기를 들려주시곤 했어요.','I used to be shy, and I would hide behind my mother.','저는 수줍었었고, 엄마 뒤에 숨곤 했어요.','He used to smoke, and on Fridays he would go to the bar.','그는 담배를 피우곤 했고, 금요일마다 술집에 가곤 했어요.'),
('nuc_discussion_03','agree','consent',NULL,'동의하다 (의견)','동의하다 (허가)',NULL,'agree는 의견·제안에 동의하는 것, consent는 권리·행위에 공식 허가하는 것이에요.','agree는 의견 동의, consent는 법적·의료적 허가예요.','B2','discussion',1,3,'agree consent permission discussion','I agree with your proposal.','저는 당신의 제안에 동의해요.','Patients must consent to the procedure.','환자는 그 시술에 동의해야 해요.','We all agree that the project should start next month.','우리 모두 그 프로젝트가 다음 달에 시작되어야 한다는 데 동의해요.','I agree with most of what she said.','그녀가 말한 대부분에 동의해요.','Patients must give consent before any procedure.','환자들은 어떤 시술 전에도 동의를 해야 해요.'),
('nuc_discussion_04','debate','deliberate',NULL,'토론하다','심의하다',NULL,'debate는 입장을 내세워 토론하는 것, deliberate는 신중하게 논의하고 판단하는 것이에요.','debate는 대립, deliberate는 충분한 논의 후 결정을 강조해요.','B2','discussion',2,4,'debate deliberate committee decision','The students debated the merits of AI in education.','학생들은 교육에서 AI의 장점을 두고 토론했어요.','The committee deliberated for hours before voting.','위원회는 표결하기 전에 몇 시간 동안 숙의했어요.','The two candidates will debate economic policy on live television.','두 후보는 생방송에서 경제 정책을 두고 토론할 거예요.','The class debated whether AI should be regulated.','수업에서는 AI가 규제되어야 하는지 토론했어요.','The committee deliberated late into the night.','위원회는 밤늦게까지 심의했어요.'),
('nuc_discussion_05','concede','compromise',NULL,'인정하다 / 양보하다','타협하다',NULL,'concede는 상대 주장을 일부 인정하거나 양보하는 것, compromise는 서로 중간 지점에서 합의하는 것이에요.','concede는 한쪽이 양보, compromise는 양쪽이 함께 중간 합의해요.','B2','discussion',1,5,'concede compromise negotiation agreement','I concede that you have a valid point.','당신의 말에 타당한 점이 있다는 걸 인정해요.','Both sides agreed to compromise.','양측은 타협하기로 합의했어요.','After much debate, the union conceded on the working hours.','많은 논쟁 끝에 노조는 근무 시간 문제에서 양보했어요.','I''ll concede that you''re right about that detail.','그 세부 사항에 대해서는 당신이 옳다는 걸 인정할게요.','They reached a fair compromise on the price.','그들은 가격에서 공정한 타협을 이뤘어요.'),
('nuc_discussion_06','assert','claim',NULL,'단호히 주장하다','주장하다',NULL,'assert는 강하게 자신 있게 주장하는 것, claim은 증거 없이 주장하는 뉘앙스가 있어요.','assert는 자신감, claim은 증거가 불확실할 때 쓰는 경우가 많아요.','B2','discussion',2,6,'assert claim argument statement','She asserted her right to speak.','그녀는 발언할 권리를 강하게 주장했어요.','He claimed the product was safe, but there was no proof.','그는 제품이 안전하다고 주장했지만 증거는 없었어요.','The researcher firmly asserted that the data supported her theory.','그 연구자는 데이터가 자신의 이론을 뒷받침한다고 단호히 주장했어요.','She asserted her position confidently in the meeting.','그녀는 회의에서 자신 있게 자기 입장을 주장했어요.','He claimed to have data, but never showed any.','그는 데이터가 있다고 주장했지만 보여주지 않았어요.'),
('nuc_discussion_07','convince','persuade',NULL,'납득시키다 (이성)','설득하다 (감성+이성)',NULL,'convince는 논리로 이성적으로 납득시키는 것, persuade는 감정과 논리로 행동하게 만드는 것이에요.','convince는 생각 변화, persuade는 행동 변화를 이끌어요.','B2','discussion',1,7,'convince persuade argument discussion','The data convinced me that the plan would work.','그 데이터를 보고 그 계획이 통할 거라고 확신하게 됐어요.','She persuaded him to apply for the job.','그녀는 그를 설득해 그 일자리에 지원하게 했어요.','It took a lot of evidence to convince the committee.','위원회를 설득하는 데에는 많은 증거가 필요했어요.','The research convinced me to change my approach.','그 연구가 제가 접근 방식을 바꾸도록 납득시켰어요.','She persuaded her parents to let her study abroad.','그녀는 부모님이 해외 유학을 허락하시도록 설득했어요.'),
('nuc_discussion_08','contradict','counter',NULL,'모순되다 / 반박하다','반론을 제기하다',NULL,'contradict는 정면으로 반박하거나 모순을 지적하는 것, counter는 논거를 들어 반론하는 것이에요.','contradict는 모순 지적, counter는 전략적 반론이에요.','C1','discussion',1,8,'contradict counter argument debate','His actions contradicted his words.','그의 행동은 그의 말과 모순됐어요.','She countered with new evidence.','그녀는 새로운 증거로 반박했어요.','The new findings directly contradict the earlier theory.','새로운 연구 결과는 이전 이론과 정면으로 모순돼요.','His later statement contradicted what he said earlier.','그의 나중 발언은 앞서 한 말과 모순됐어요.','She countered his argument with three solid examples.','그녀는 세 가지 탄탄한 예시로 그의 주장에 반론했어요.'),
('nuc_discussion_09','implication','inference',NULL,'함의 (숨겨진 의미)','추론 (끌어낸 결론)',NULL,'implication은 말 속에 담긴 함의, inference는 주어진 정보로 끌어내는 결론이에요.','implication은 화자가 내포시킨 것, inference는 청자가 끌어낸 결론이에요.','C1','discussion',2,9,'implication inference logic discussion','The implication of his silence was that he disagreed.','그의 침묵이 함축하는 바는 그가 동의하지 않는다는 것이었어요.','From the evidence, we can draw the inference that prices will rise.','그 증거로부터 우리는 가격이 오를 것이라는 추론을 끌어낼 수 있어요.','The economic implication of the policy worried many small business owners.','그 정책이 함축하는 경제적 의미가 많은 소상공인을 걱정시켰어요.','The implication of her tone was disappointment.','그녀 어조의 함의는 실망이었어요.','From the data, we can make a reasonable inference.','데이터에서 우리는 합리적인 추론을 할 수 있어요.'),
('nuc_discussion_10','fallacy','bias',NULL,'오류 (논리적)','편향',NULL,'fallacy는 논리적으로 잘못된 추론, bias는 한쪽으로 치우친 사고 경향이에요.','fallacy는 논리 오류, bias는 사고의 치우침이에요.','C1','discussion',1,10,'fallacy bias logic argument','That''s a false dichotomy fallacy.','그건 잘못된 이분법 오류예요.','Confirmation bias led him to ignore contradicting facts.','확증 편향 때문에 그는 반대되는 사실을 무시했어요.','Attacking the person instead of the idea is a common fallacy.','생각이 아니라 사람을 공격하는 건 흔한 오류예요.','That argument contains a classic logical fallacy.','그 주장은 고전적인 논리적 오류를 담고 있어요.','Everyone has some unconscious bias to work on.','모든 사람은 다뤄야 할 어느 정도의 무의식적 편향이 있어요.'),
('nuc_discussion_11','rhetoric','eloquence',NULL,'수사학 / 과장된 언변','유창함 / 웅변',NULL,'rhetoric은 설득을 위한 언어 기술이지만 과장·공허함 뉘앙스도 있고, eloquence는 유창하고 표현력 있는 말솜씨예요.','rhetoric은 기술이지만 부정적 용법도 있고, eloquence는 긍정적 표현이에요.','C1','discussion',2,11,'rhetoric eloquence speech language','His speech was full of empty rhetoric.','그의 연설은 공허한 미사여구로 가득했어요.','Her eloquence moved the entire audience.','그녀의 유려한 화술이 청중 전체를 감동시켰어요.','Skilled use of rhetoric can make a weak case sound convincing.','능숙한 수사법은 빈약한 주장도 설득력 있게 들리게 할 수 있어요.','Political speeches often rely on hollow rhetoric.','정치 연설은 종종 공허한 수사학에 의존해요.','Her eloquence held the audience for the full hour.','그녀의 웅변이 청중을 한 시간 내내 사로잡았어요.'),
('nuc_discussion_12','sophistry','dialectic',NULL,'궤변','변증법',NULL,'sophistry는 외관상 그럴듯하지만 잘못된 논리, dialectic은 대립되는 의견을 통해 진리에 도달하는 방법이에요.','sophistry는 속이는 논리, dialectic은 철학적 진리 탐구 방법이에요.','C2','discussion',1,12,'sophistry dialectic philosophy argument','His argument was clever sophistry, not real logic.','그의 주장은 진짜 논리가 아니라 교묘한 궤변이었어요.','Hegel''s dialectic moves from thesis to antithesis to synthesis.','헤겔의 변증법은 정립에서 반정립을 거쳐 종합으로 나아가요.','What sounded like deep reasoning was really just elegant sophistry.','깊은 추론처럼 들렸던 것이 사실은 그저 그럴듯한 궤변이었어요.','His speech was sophistry wrapped in fancy words.','그의 연설은 화려한 말로 포장된 궤변이었어요.','Hegelian dialectic moves through thesis, antithesis, and synthesis.','헤겔의 변증법은 정-반-합을 거쳐 진행돼요.'),
('nuc_discussion_13','axiom','postulate',NULL,'공리 (자명한 진리)','공준 (가정)',NULL,'axiom은 증명 없이 자명한 진리, postulate는 특정 이론의 전제로 받아들이는 가정이에요.','axiom은 보편적 자명, postulate는 특정 이론 내 가정이에요.','C2','discussion',2,13,'axiom postulate logic philosophy','"All humans are mortal" is a classic axiom.','"모든 인간은 죽는다"는 고전적인 공리예요.','Euclid''s postulates form the basis of geometry.','유클리드의 공준들은 기하학의 기초를 이뤄요.','In logic, an axiom needs no proof because its truth is self-evident.','논리학에서 공리는 그 진리가 자명하기 때문에 증명이 필요 없어요.','Some statements are accepted as axioms in mathematics.','수학에서 어떤 진술들은 공리로 받아들여져요.','A postulate forms the starting point of a theory.','공준은 이론의 출발점을 형성해요.'),
('nuc_economy_14','spend','use',NULL,'쓰다 (돈·시간)','사용하다 (도구·자원)',NULL,'spend는 돈·시간을 소비할 때, use는 도구·자원을 활용할 때.','spend는 소비(돈·시간 한정), use는 사용(도구·서비스). 시간은 둘 다 가능하지만 spend가 더 자연스러워요.','A2','economy',1,0,'money time using spending budget','I spent fifty dollars on books.','저는 책에 50달러를 썼어요.','Use the calculator if you need to.','필요하면 계산기를 사용하세요.','I usually spend too much money on coffee every week.','저는 보통 매주 커피에 돈을 너무 많이 써요.','I spent two hours using the computer.','컴퓨터를 사용하면서 두 시간을 보냈어요.','She spends her free time using language apps.','그녀는 여가 시간을 언어 앱을 사용하면서 보내요.'),
('nuc_economy_15','save','keep',NULL,'저축하다, 절약하다','보관하다, 유지하다',NULL,'save는 미래를 위해 모으거나 아끼는 것, keep은 단순히 가지고 있는 것·유지하는 것.','save는 미래 대비(모으기·아끼기), keep은 현재 유지·소지. save the date는 일정 확보, keep in mind는 마음에 새기기.','A2','economy',1,0,'savings piggy bank money keeping safe','I save money every month.','저는 매달 돈을 저축해요.','I keep my passport in a safe place.','저는 여권을 안전한 곳에 보관해요.','We''re trying to save enough for a down payment on a house.','우리는 집 계약금을 마련하려고 저축하고 있어요.','I save money but keep my receipts just in case.','돈을 저축하지만 영수증은 만일을 대비해 보관해요.','Save energy; keep the lights off.','에너지를 절약하세요; 불은 꺼두세요.'),
('nuc_economy_01','cost','price','charge','비용 (총액)','가격 (표시)','요금 (부과)','price는 상품에 표시된 가격, cost는 총 드는 비용, charge는 특정 서비스에 부과하는 요금이에요.','price(물건), charge(서비스), cost(총비용)으로 구분해요.','B1','economy',1,1,'cost price charge money economics','The price of oil dropped this week.','이번 주에 유가가 떨어졌어요.','The total cost of the project was high.','그 프로젝트의 총비용은 높았어요.','There is a late charge for overdue payments.','연체된 결제에는 연체료가 부과돼요.','The price of fuel has fluctuated wildly this year.','연료 가격이 올해 크게 요동쳤어요.','There''s a small service charge for online bookings.','온라인 예약에는 작은 서비스 요금이 있어요.'),
('nuc_economy_02','income','revenue',NULL,'소득 (개인)','수익 (기업)',NULL,'income은 개인이 벌어들이는 소득, revenue는 기업·조직의 총 매출 수익이에요.','personal income(개인 소득), corporate revenue(기업 매출)처럼 대상이 달라요.','B1','economy',1,2,'income revenue money finance','Her monthly income is about 4 million won.','그녀의 월수입은 약 400만 원이에요.','The company''s annual revenue exceeded 1 trillion won.','그 회사의 연간 매출은 1조 원을 넘었어요.','A second job gave her some extra income each month.','부업 덕분에 그녀는 매달 약간의 추가 수입이 생겼어요.','Household income has barely kept up with inflation.','가계 소득이 인플레이션을 거의 따라가지 못했어요.','The company''s revenue grew 20% last quarter.','회사의 매출이 지난 분기에 20% 성장했어요.'),
('nuc_economy_03','invest','spend',NULL,'투자하다','소비하다',NULL,'spend는 돈을 쓰는 것, invest는 미래 수익을 기대하고 돈을 넣는 것이에요.','invest는 수익 기대, spend는 소비가 목적이에요.','B1','economy',2,3,'invest spend money finance','I invested in stocks last year.','저는 작년에 주식에 투자했어요.','She spent all her savings on a vacation.','그녀는 저축한 돈을 전부 휴가에 썼어요.','It''s wise to invest a portion of your salary every month.','매달 급여의 일부를 투자하는 게 현명해요.','I invested a small amount in an index fund.','저는 인덱스 펀드에 적은 금액을 투자했어요.','They spent too much on the wedding and regret it now.','그들은 결혼식에 너무 많이 써서 지금 후회해요.'),
('nuc_economy_04','inflation','deflation',NULL,'물가 상승','물가 하락',NULL,'inflation은 물가가 오르는 것, deflation은 물가가 내리는 것이에요. 둘 다 경제에 문제가 될 수 있어요.','적절한 inflation(2%)은 건전, 급격한 inflation이나 deflation은 문제예요.','B1','economy',2,4,'inflation deflation economy price','Inflation has driven up the cost of groceries.','인플레이션으로 식료품 가격이 올랐어요.','Deflation can lead to a slowdown in economic growth.','디플레이션은 경제 성장 둔화로 이어질 수 있어요.','Rapid inflation quickly eroded people''s savings.','급격한 인플레이션이 사람들의 저축을 빠르게 잠식했어요.','Inflation has made everyday groceries noticeably more expensive.','인플레이션으로 일상 식료품이 눈에 띄게 더 비싸졌어요.','Long deflation can be just as harmful as inflation.','장기 디플레이션은 인플레이션만큼이나 해로울 수 있어요.'),
('nuc_economy_05','profit','benefit',NULL,'이익 (금전적)','혜택 (폭넓은)',NULL,'profit은 수익에서 비용을 뺀 이익, benefit은 금전적 외에도 다양한 이점을 포함해요.','profit은 금전적, benefit은 비금전적 이점도 포함해요.','B2','economy',1,5,'profit benefit business financial','The company made a huge profit last year.','그 회사는 작년에 큰 이익을 냈어요.','There are many benefits to working from home.','재택근무에는 많은 이점이 있어요.','They reinvested most of the profit back into the business.','그들은 이익의 대부분을 사업에 재투자했어요.','The bakery made a small profit in its first year.','그 빵집은 첫해에 작은 이익을 냈어요.','Working remotely has many benefits, including more family time.','재택근무는 더 많은 가족 시간을 포함해 많은 혜택이 있어요.'),
('nuc_economy_06','budget','forecast',NULL,'예산','예측',NULL,'budget은 계획된 수입·지출 계획, forecast는 미래 경제 지표의 예측이에요.','budget은 계획(plan), forecast는 예측(prediction)이에요.','B2','economy',2,6,'budget forecast finance planning','The government set a budget for education.','정부는 교육 예산을 책정했어요.','Analysts released an economic forecast for next year.','분석가들이 내년도 경제 전망을 발표했어요.','We reviewed the household budget at the start of each month.','우리는 매달 초에 가계 예산을 점검했어요.','We''re sticking to a strict budget this year.','우리는 올해 엄격한 예산을 따르고 있어요.','The forecast for next quarter is cautiously optimistic.','다음 분기 예측은 조심스럽게 낙관적이에요.'),
('nuc_economy_07','export','import',NULL,'수출','수입',NULL,'export는 자국에서 외국으로 내보내는 것, import는 외국에서 자국으로 들여오는 것이에요.','export(내보내기) → import(들여오기). 무역 적자는 수입 > 수출인 상태예요.','B2','economy',1,7,'export import trade economy','Korea exports semiconductors worldwide.','한국은 전 세계에 반도체를 수출해요.','The country imports most of its oil.','그 나라는 석유 대부분을 수입해요.','Higher tariffs made it harder to export goods abroad.','관세가 높아지면서 해외로 상품을 수출하기가 더 어려워졌어요.','Korea exports electronics and cars to many countries.','한국은 전자제품과 자동차를 많은 나라에 수출해요.','The country imports most of its raw materials.','그 나라는 대부분의 원자재를 수입해요.'),
('nuc_economy_08','tax','tariff',NULL,'세금','관세',NULL,'tax는 정부에 납부하는 세금, tariff는 수입품에 부과하는 관세예요.','tax는 내국 세금, tariff는 국제 무역에 부과되는 세금이에요.','B2','economy',2,8,'tax tariff trade government','Income tax is deducted monthly.','소득세는 매달 공제돼요.','The US imposed tariffs on Chinese goods.','미국은 중국산 제품에 관세를 부과했어요.','The government raised the sales tax by two percent this year.','정부는 올해 판매세를 2퍼센트 인상했어요.','Property taxes vary widely between regions.','재산세는 지역마다 크게 달라요.','New tariffs raised the cost of imported electronics.','새 관세가 수입 전자제품 비용을 올렸어요.'),
('nuc_economy_09','recession','depression',NULL,'경기 침체','대공황 / 심각한 침체',NULL,'recession은 경제가 일시적으로 축소되는 것, depression은 더 장기적이고 심각한 경제 침체예요.','recession이 2분기 이상 지속·심화되면 depression으로 불릴 수 있어요.','C1','economy',1,9,'recession depression economy crisis','The country entered a mild recession last year.','그 나라는 작년에 가벼운 경기 침체에 들어섰어요.','The Great Depression lasted over a decade.','대공황은 10년 넘게 지속되었어요.','Rising unemployment signaled the start of a recession.','실업률 상승은 경기 침체의 시작을 알리는 신호였어요.','Many countries entered a recession after the global crisis.','많은 나라들이 글로벌 위기 후 경기 침체에 진입했어요.','The Great Depression reshaped how governments approach the economy.','대공황은 정부가 경제에 접근하는 방식을 재형성했어요.'),
('nuc_economy_10','fiscal','monetary',NULL,'재정의 (정부 지출)','통화의 (금리·통화량)',NULL,'fiscal policy는 정부 지출·세금 정책, monetary policy는 중앙은행의 금리·통화량 정책이에요.','fiscal = 정부, monetary = 중앙은행(한국은행)의 영역이에요.','C1','economy',2,10,'fiscal monetary policy government','The government announced new fiscal measures.','정부가 새로운 재정 정책을 발표했어요.','The central bank adjusted its monetary policy.','중앙은행이 통화 정책을 조정했어요.','Politicians often disagree about how aggressive fiscal policy should be.','정치인들은 재정 정책이 얼마나 적극적이어야 하는지를 두고 자주 의견이 갈려요.','The government announced new fiscal stimulus measures.','정부가 새 재정 부양책을 발표했어요.','Monetary policy is the central bank''s main tool.','통화 정책은 중앙은행의 주요 도구예요.'),
('nuc_economy_11','liquidity','solvency',NULL,'유동성 (단기 현금)','지급 능력 (장기)',NULL,'liquidity는 단기 현금 동원 능력, solvency는 장기 부채를 갚을 수 있는 능력이에요.','liquidity는 단기, solvency는 장기 재무 건전성을 가리켜요.','C1','economy',1,11,'liquidity solvency finance bank','The bank faced a liquidity crisis during the panic.','그 은행은 공황 중에 유동성 위기에 직면했어요.','Despite low profits, the firm remains solvent.','낮은 수익에도 불구하고, 그 회사는 지급 능력을 유지하고 있어요.','Holding too much cash hurts profits but improves liquidity.','현금을 너무 많이 보유하면 수익은 줄지만 유동성은 좋아져요.','During the crisis, many banks faced a liquidity shortage.','위기 동안 많은 은행이 유동성 부족에 직면했어요.','The firm remains solvent despite the recent losses.','회사는 최근 손실에도 불구하고 지급 능력을 유지하고 있어요.'),
('nuc_economy_12','austerity','stimulus',NULL,'긴축 (지출 삭감)','경기 부양',NULL,'austerity는 정부 지출을 줄이는 긴축 정책, stimulus는 경기 부양을 위해 지출하는 것이에요.','austerity와 stimulus는 경기 침체 대응 방식이 정반대예요.','C2','economy',1,12,'austerity stimulus policy economy','The government imposed austerity measures.','정부가 긴축 정책을 시행했어요.','The stimulus package helped revive the economy.','경기 부양책이 경제를 되살리는 데 도움이 됐어요.','Years of austerity left many public services underfunded.','수년간의 긴축으로 많은 공공 서비스가 재정 부족에 시달렸어요.','Austerity measures often hurt the most vulnerable people.','긴축 조치는 종종 가장 취약한 사람들에게 타격을 줘요.','The stimulus package helped revive struggling small businesses.','경기 부양책이 어려움을 겪던 소상공인들을 회복시키는 데 도움이 됐어요.'),
('nuc_economy_13','oligopoly','monopoly',NULL,'과점 (소수 지배)','독점 (하나 지배)',NULL,'monopoly는 한 기업이 시장을 독점, oligopoly는 소수 기업이 시장을 지배하는 구조예요.','monopoly(1개), duopoly(2개), oligopoly(소수)로 시장 구조를 구분해요.','C2','economy',2,13,'monopoly oligopoly market competition','The tech giant has a near monopoly on search engines.','그 거대 기술 기업은 검색 엔진 시장을 거의 독점하고 있어요.','The airline industry is often described as an oligopoly.','항공 업계는 흔히 과점 시장으로 묘사돼요.','An oligopoly often leads to less competition and higher prices.','과점은 흔히 경쟁 감소와 가격 상승으로 이어져요.','A few firms hold a near monopoly on cloud services.','소수 기업이 클라우드 서비스에서 거의 독점을 차지하고 있어요.','The mobile market is essentially an oligopoly of three brands.','모바일 시장은 본질적으로 세 브랜드의 과점이에요.'),
('nuc_education_01','study','learn',NULL,'공부하다','배우다',NULL,'study는 의식적으로 집중해서 공부하는 행위, learn은 새로운 지식·기술을 습득하는 결과예요.','study는 노력의 과정, learn은 지식을 얻은 결과에 초점을 둬요.','B1','education',1,1,'study learn student education','I studied for three hours last night.','저는 어젯밤에 세 시간 동안 공부했어요.','I learned a lot from that experience.','저는 그 경험에서 많은 것을 배웠어요.','I studied grammar for hours, but I learned to speak naturally only by talking to people.','저는 몇 시간 동안 문법을 공부했지만, 자연스럽게 말하는 법은 사람들과 대화하면서야 비로소 배웠어요.','I studied late into the night for the final exam.','저는 기말 시험을 위해 밤늦게까지 공부했어요.','You can learn so much just by traveling.','여행만으로도 정말 많은 것을 배울 수 있어요.'),
('nuc_education_02','teacher','professor',NULL,'선생님 (초중고)','교수 (대학)',NULL,'teacher는 초·중·고 교사, professor는 대학교 교수예요.','teacher는 school, professor는 university/college에서 써요.','B1','education',2,2,'teacher professor education school','My teacher explained the grammar rule clearly.','선생님이 그 문법 규칙을 명확하게 설명해 주셨어요.','The professor published a new research paper.','그 교수님은 새로운 연구 논문을 발표하셨어요.','Our history teacher organized a field trip to the museum.','우리 역사 선생님이 박물관 견학을 준비해 주셨어요.','My first English teacher made me love languages.','제 첫 영어 선생님이 저에게 언어를 사랑하게 만들어 주셨어요.','The professor''s lectures attract students from many countries.','그 교수님의 강의는 여러 나라의 학생들을 끌어들여요.'),
('nuc_education_03','exam','test','quiz','시험 (공식·중요)','시험 (일반)','퀴즈 (간단)','quiz는 짧고 간단한 확인 시험, test는 일반적인 시험, exam은 더 공식적이고 중요한 시험이에요.','규모 순서: quiz < test < exam으로 기억하세요.','B1','education',1,3,'exam test quiz school assessment','The final exam is worth 40% of your grade.','기말고사는 성적의 40퍼센트를 차지해요.','We have a test on chapter 5 tomorrow.','우리는 내일 5장에 대한 시험이 있어요.','The teacher gave a quick quiz at the start of class.','선생님이 수업 시작에 간단한 쪽지 시험을 냈어요.','A quick quiz at the start of class keeps everyone alert.','수업 시작에 짧은 퀴즈가 모두를 집중하게 해요.','The final exam covers everything from the semester.','기말 시험은 학기 전체를 다뤄요.'),
('nuc_education_04','homework','assignment',NULL,'숙제 (일반)','과제 (공식)',NULL,'homework는 집에서 하는 숙제, assignment는 과제·임무를 모두 포함하는 더 넓은 표현이에요.','homework는 초중고, assignment는 대학·직장 맥락에서 더 자주 써요.','B1','education',2,4,'homework assignment study task','I forgot to do my homework.','숙제하는 걸 깜빡했어요.','The professor gave us an assignment due next week.','교수님이 다음 주까지 제출하는 과제를 내주셨어요.','Don''t forget to bring your homework tomorrow.','내일 숙제 가져오는 걸 잊지 마세요.','I do my homework at the library after school.','저는 방과 후 도서관에서 숙제를 해요.','The assignment is due next Friday at midnight.','과제는 다음 주 금요일 자정까지예요.'),
('nuc_education_05','grade','score',NULL,'성적 (문자·등급)','점수 (숫자)',NULL,'score는 숫자 점수, grade는 A/B/C 같은 등급이나 학년을 뜻해요.','score는 숫자, grade는 등급 또는 미국식 학년(grade 1 = 1학년)이에요.','B1','education',1,5,'grade score mark academic result','She got a grade of A on her essay.','그녀는 에세이에서 A 학점을 받았어요.','His test score was 92 out of 100.','그의 시험 점수는 100점 만점에 92점이었어요.','Her final grade depended on both the essay and the exam.','그녀의 최종 성적은 에세이와 시험 둘 다에 달려 있었어요.','My grade on the project surprised me.','그 프로젝트에서 받은 성적이 저를 놀라게 했어요.','His score on the math test was perfect.','수학 시험에서 그의 점수는 만점이었어요.'),
('nuc_education_14','remember','remind',NULL,'기억하다 (스스로)','상기시키다 (남에게)',NULL,'remember는 스스로 기억해내는 것, remind는 누군가에게 기억하라고 알려주는 행위. 한국어는 둘 다 "기억"이라 헷갈림.','remember는 주체가 본인, remind는 남에게 알려주는 동작. "remind me of X"는 "X를 떠올리게 한다".','B1','education',1,0,'memory reminder notes phone alarm','I remember my first day of school.','저는 학교 첫날을 기억해요.','Please remind me to call her.','그녀에게 전화하라고 저에게 알려 주세요.','I still remember the lullaby my grandmother used to sing.','저는 할머니가 불러 주시던 자장가를 아직도 기억해요.','I tried to remember her name, so she had to remind me.','이름을 기억해내려 했지만 그녀가 상기시켜 줘야 했어요.','Remember to lock the door; I''ll remind you again later.','문 잠그는 거 기억하세요; 나중에 다시 상기시킬게요.'),
('nuc_education_15','explain','tell',NULL,'설명하다 (원리·이유)','말하다 (사실·정보)',NULL,'explain은 "왜·어떻게"를 풀어주는 설명, tell은 단순히 정보를 전달하는 것.','explain은 풀이/이유, tell은 정보 전달. "Tell me why"도 가능하지만 explain이 더 정확.','B1','education',1,0,'teacher explaining student information','Can you explain how this works?','이게 어떻게 작동하는지 설명해 주실 수 있나요?','He told me the news.','그가 저에게 그 소식을 전해 줬어요.','The teacher patiently explained the math problem step by step.','선생님께서 그 수학 문제를 차근차근 인내심 있게 설명해 주셨어요.','She told me the answer but didn''t explain why.','그녀는 답은 말해줬지만 이유는 설명하지 않았어요.','Tell me the time; explain how to read a clock.','시간을 말해 줘요; 시계 보는 법을 설명해 줘요.'),
('nuc_education_16','prepare','ready',NULL,'준비하다 (동사)','준비된 (형용사)',NULL,'prepare는 행위(동사), ready는 상태(형용사). "be ready"는 상태, "prepare"는 그 상태를 만드는 행위.','prepare는 동사(행위), ready는 형용사(상태). "get ready"는 "준비되다" = "준비를 마치다".','B1','education',1,0,'student preparing exam ready studying','I need to prepare for the exam.','저는 시험을 준비해야 해요.','Are you ready to go?','갈 준비 됐어요?','We spent the whole weekend preparing for the presentation.','저희는 주말 내내 발표를 준비했어요.','I prepared for hours and now I''m ready.','몇 시간 준비했고 이제 준비됐어요.','She prepared lunch; now lunch is ready.','그녀는 점심을 준비했고, 이제 점심이 준비됐어요.'),
('nuc_education_06','scholarship','grant',NULL,'장학금 (성적 기반)','보조금 (필요 기반)',NULL,'scholarship은 성적·능력 기반 장학금, grant는 필요나 프로젝트 기반 보조금이에요.','scholarship은 개인 성취 보상, grant는 프로젝트·연구 지원금이에요.','B2','education',1,6,'scholarship grant funding education','She won a merit scholarship to study abroad.','그녀는 유학을 위한 성적 우수 장학금을 받았어요.','The lab received a research grant.','그 연구실은 연구 보조금을 받았어요.','He couldn''t have attended university without that scholarship.','그 장학금이 없었다면 그는 대학에 다니지 못했을 거예요.','She won a full scholarship to an Ivy League school.','그녀는 아이비리그 학교의 전액 장학금을 받았어요.','The lab applied for a research grant from the government.','그 실험실은 정부 연구 보조금을 신청했어요.'),
('nuc_education_07','curriculum','syllabus',NULL,'교육과정 (전체)','강의계획서 (과목)',NULL,'curriculum은 학교 전체 교육과정, syllabus는 특정 과목의 강의계획서예요.','curriculum은 학교 전체, syllabus는 단일 과목 계획이에요.','B2','education',2,7,'curriculum syllabus course plan','The school updated its science curriculum.','그 학교는 과학 교육과정을 개정했어요.','Please read the syllabus before the first class.','첫 수업 전에 강의 계획서를 읽어 주세요.','The new curriculum places more emphasis on practical skills.','새 교육과정은 실용적인 기술에 더 중점을 둬요.','The curriculum was updated to include digital literacy.','교육과정이 디지털 리터러시를 포함하도록 업데이트됐어요.','Always read the syllabus carefully on the first day.','첫날 강의계획서를 항상 신중히 읽으세요.'),
('nuc_education_08','tutor','mentor',NULL,'개인 교사 / 튜터','멘토',NULL,'tutor는 특정 과목을 가르치는 교사, mentor는 경험과 조언으로 성장을 이끄는 사람이에요.','tutor는 학습·기술, mentor는 삶·커리어 조언에 집중해요.','B2','education',1,8,'tutor mentor guidance teaching','She hired a math tutor for her son.','그녀는 아들을 위해 수학 과외 선생님을 구했어요.','He became my mentor when I started my career.','제가 사회생활을 시작할 때 그는 제 멘토가 되어 주었어요.','I work as a part-time tutor on weekends to earn extra money.','저는 주말에 부수입을 벌려고 시간제 과외 선생님으로 일해요.','My math tutor helped me improve in just a month.','제 수학 튜터가 단 한 달 만에 제가 향상되도록 도와줬어요.','A good mentor can shape your entire career.','좋은 멘토가 당신의 전체 경력을 형성할 수 있어요.'),
('nuc_education_09','rote','critical thinking',NULL,'암기식 학습','비판적 사고',NULL,'rote learning은 반복 암기, critical thinking은 분석하고 판단하는 사고력이에요.','한국 교육은 rote 중심에서 critical thinking 중심으로 변화하고 있어요.','B2','education',2,9,'rote learning critical thinking study','Rote memorization won''t help you understand concepts.','무작정 암기하는 건 개념을 이해하는 데 도움이 안 돼요.','Critical thinking skills are valued in modern education.','비판적 사고력은 현대 교육에서 높이 평가받아요.','Some subjects still rely heavily on rote memorization for exams.','일부 과목은 시험을 위해 여전히 단순 암기에 크게 의존해요.','Rote learning has limits when ideas get complex.','암기식 학습은 아이디어가 복잡해질 때 한계가 있어요.','Critical thinking is the most important skill for university.','비판적 사고는 대학에서 가장 중요한 기술이에요.'),
('nuc_education_10','undergraduate','graduate',NULL,'학부생','대학원생',NULL,'undergraduate는 학사 과정, graduate는 석·박사 과정을 뜻해요.','undergraduate → bachelor''s, graduate → master''s / PhD로 연결해 기억해요.','B2','education',1,10,'undergraduate graduate university degree','She is an undergraduate student in her junior year.','그녀는 3학년 학부생이에요.','He is pursuing a graduate degree in economics.','그는 경제학 대학원 학위를 밟고 있어요.','Most of my friends are undergraduates studying engineering.','제 친구들 대부분은 공학을 전공하는 학부생이에요.','She''s a fourth-year undergraduate student in biology.','그녀는 생물학 4학년 학부생이에요.','He''s a graduate student researching marine ecosystems.','그는 해양 생태계를 연구하는 대학원생이에요.'),
('nuc_education_11','pedagogy','didactics',NULL,'교육학 (방법론)','교수법 (내용 중심)',NULL,'pedagogy는 가르치는 방법·철학, didactics는 교과 내용을 효과적으로 가르치는 방법이에요.','pedagogy는 더 넓은 교육 방법론, didactics는 교과 교수법에 특화돼요.','C1','education',1,11,'pedagogy didactics teaching method','She researches child-centered pedagogy.','그녀는 아동 중심 교수법을 연구해요.','Didactics focuses on how to teach specific subjects.','교과교육론은 특정 과목을 어떻게 가르칠지에 초점을 맞춰요.','The conference brought together experts on inclusive pedagogy.','그 학회는 포용적 교수법 전문가들을 한자리에 모았어요.','Modern pedagogy focuses on student-centered learning.','현대 교육학은 학생 중심 학습에 집중해요.','Didactics studies how to best teach specific subjects.','교수법은 특정 과목을 가장 잘 가르치는 방법을 연구해요.'),
('nuc_education_12','accreditation','certification',NULL,'인증 (기관)','자격증 (개인)',NULL,'accreditation은 학교·기관의 공식 인가, certification은 개인의 특정 능력 자격증이에요.','accreditation은 기관, certification은 개인에게 수여돼요.','C1','education',2,12,'accreditation certification credential','The university lost its accreditation.','그 대학은 인증을 잃었어요.','She earned a teaching certification.','그녀는 교사 자격증을 취득했어요.','International accreditation makes a degree more widely recognized.','국제 인증은 학위를 더 폭넓게 인정받게 해줘요.','The school is currently undergoing accreditation review.','그 학교는 현재 인증 심사를 받고 있어요.','She earned certification as a yoga instructor last year.','그녀는 작년에 요가 강사 자격증을 취득했어요.'),
('nuc_education_13','epistemology','ontology',NULL,'인식론 (지식의 본질)','존재론 (존재의 본질)',NULL,'epistemology는 지식이 무엇이고 어떻게 아는지를 탐구, ontology는 존재의 본질을 탐구해요.','철학·학술 논문에서 자주 등장하는 핵심 개념이에요.','C2','education',1,13,'epistemology ontology philosophy academic','Epistemology asks: how do we know what we know?','인식론은 묻습니다. 우리는 우리가 아는 것을 어떻게 아는가?','Ontology asks: what kinds of things exist?','존재론은 묻습니다. 어떤 종류의 것들이 존재하는가?','In epistemology, scholars debate whether true certainty is even possible.','인식론에서 학자들은 진정한 확실성이 과연 가능한지를 두고 논쟁해요.','Epistemology asks how we can claim to know anything at all.','인식론은 우리가 어떻게 무언가를 안다고 주장할 수 있는지 물어요.','Ontology explores what kinds of things actually exist.','존재론은 어떤 종류의 것들이 실제로 존재하는지 탐구해요.'),
('nuc_emotion_16','feel','think',NULL,'느끼다 (감정·직관)','생각하다 (논리·의견)',NULL,'feel은 감정·직관적 판단, think는 논리적 판단·의견. "I feel that..."도 가능하지만 더 부드러운 느낌.','feel은 감정/직감, think는 의견/추론. "I feel that..."은 부드러운 의견 표현으로도 쓰여요.','A2','emotion',1,0,'feeling thinking introspection emotion','I feel happy today.','저는 오늘 행복해요.','I think this is the best option.','저는 이게 최선의 선택이라고 생각해요.','I feel a little nervous before every interview.','저는 면접 때마다 조금 긴장돼요.','I feel something is wrong, but I think we should still try.','뭔가 잘못된 느낌이지만 그래도 시도해 봐야 한다고 생각해요.','She feels anxious; he thinks she''s overreacting.','그녀는 불안하다고 느끼지만, 그는 그녀가 과민 반응한다고 생각해요.'),
('nuc_emotion_18','very','really','extremely','매우 (일반)','정말 (강조·자연스러움)','극도로 (최고 강도)','very < really < extremely 강도. very는 일반, really는 감정·강조, extremely는 극단적 강도.','very < really < extremely. really는 감정 표현에 자연스럽고, extremely는 통계·과학에서도 자주 (extremely rare).','A2','emotion',1,0,'very excited extremely happy strong feeling','I''m very happy.','저는 아주 행복해요.','I''m really happy!','저는 정말 행복해요!','I''m extremely happy!','저는 너무나 행복해요!','It''s very cold today; really cold actually; extremely cold for May.','오늘 매우 춥고, 정말 춥고, 5월치고는 극도로 춥네요.','She''s very smart; he''s really kind; they''re extremely successful.','그녀는 매우 똑똑하고, 그는 정말 친절하고, 그들은 극도로 성공적이에요.'),
('nuc_emotion_01','happy','glad','content','행복한','기쁜 (순간)','만족한','happy는 전반적 행복감, glad는 특정 일에 대한 즉각적 기쁨, content는 조용한 만족감이에요.','glad는 "I''m glad to hear that"처럼 감사·안도 상황에 자주 써요.','B1','emotion',1,1,'happiness joy contentment','She feels happy every morning.','그녀는 매일 아침 행복함을 느껴요.','I''m glad you came.','와 주셔서 기뻐요.','He was content with his simple life.','그는 자신의 소박한 삶에 만족했어요.','I''m so glad you decided to join us tonight.','오늘 밤 함께해 주셔서 정말 기뻐요.','After years of stress, she finally feels content with her life.','몇 년간의 스트레스 끝에 그녀는 마침내 자기 삶에 만족해요.'),
('nuc_emotion_02','sad','upset',NULL,'슬픈','속상한 / 화난',NULL,'sad는 슬픔의 감정, upset는 슬픔뿐 아니라 화가 나거나 속상한 복합 감정이에요.','upset은 감정이 흔들린 상태를 폭넓게 가리켜 sad보다 강도가 세요.','B1','emotion',1,2,'sadness emotion feeling','She felt sad after the movie.','그녀는 영화를 보고 나서 슬펐어요.','He was upset about the cancellation.','그는 취소된 일 때문에 속상해했어요.','I always feel a little sad when summer comes to an end.','저는 여름이 끝나갈 때면 늘 조금 슬퍼져요.','He was sad to leave his childhood home behind.','그는 어린 시절의 집을 떠나는 것이 슬펐어요.','She was upset to find out she wasn''t invited.','그녀는 자기가 초대받지 못했다는 걸 알고 속상했어요.'),
('nuc_emotion_03','angry','annoyed','furious','화난','짜증난','격노한','annoyed는 가벼운 짜증, angry는 그보다 강한 화남, furious는 매우 격한 분노예요.','강도 순서: annoyed < angry < furious로 기억하세요.','B1','emotion',2,3,'anger frustration emotion','She was angry at the delay.','그녀는 지연에 화가 났어요.','He was annoyed by the noise.','그는 소음에 짜증이 났어요.','She was furious when she found out the truth.','그녀는 진실을 알게 되었을 때 격분했어요.','I get annoyed when people interrupt during meetings.','저는 회의 중에 사람들이 말을 끊으면 짜증이 나요.','He was furious about the unfair decision.','그는 불공정한 결정에 격노했어요.'),
('nuc_emotion_04','afraid','scared','terrified','두려운','무서운','공포에 질린','afraid는 다소 격식 있는 표현, scared는 일상적으로 자주 쓰고, terrified는 극심한 공포예요.','강도 순서: afraid ≈ scared < terrified. 일상 대화에서는 scared가 가장 자연스러워요.','B1','emotion',2,4,'fear scared emotion dark','She is afraid of the dark.','그녀는 어둠을 무서워해요.','The dog scared me.','그 개가 저를 놀라게 했어요.','He was terrified by the explosion.','그는 폭발에 겁에 질렸어요.','I''m a little scared of presenting in front of so many people.','저는 그렇게 많은 사람 앞에서 발표하는 게 조금 무서워요.','She was terrified during the turbulence on the flight.','그녀는 비행기 난기류 동안 공포에 질렸어요.'),
('nuc_emotion_08','lonely','alone',NULL,'외로운','혼자인',NULL,'alone은 혼자 있다는 사실, lonely는 혼자여서 외롭다는 감정이에요.','혼자(alone)라고 외로운(lonely) 건 아니에요 — 둘을 구분하는 게 중요해요.','B1','emotion',1,8,'loneliness solitude alone','She felt lonely in the crowd.','그녀는 사람들 속에서 외로움을 느꼈어요.','He lives alone but is not lonely.','그는 혼자 살지만 외롭지 않아요.','Even surrounded by classmates, the new student felt lonely rather than simply alone.','반 친구들에게 둘러싸여 있어도, 그 전학생은 단지 혼자라기보다 외로움을 느꼈어요.','He felt lonely on holidays when his family was far away.','그는 가족이 멀리 있는 휴일에 외로움을 느꼈어요.','She prefers to walk alone in the morning.','그녀는 아침에 혼자 걷는 걸 선호해요.'),
('nuc_emotion_14','hope','wish',NULL,'바라다 (실현 가능)','바라다 (비현실적·후회)',NULL,'hope는 일어날 가능성 있는 일에 대한 기대, wish는 비현실적이거나 과거에 못 한 일에 대한 아쉬움.','hope는 실현 가능, wish는 가정·후회. wish 뒤에는 보통 가정법(could/would/had pp).','B1','emotion',1,0,'hopeful person wishing dream','I hope you have a great day!','좋은 하루 보내시길 바라요!','I wish I could fly.','날 수 있으면 좋겠어요.','I hope the weather stays nice for the picnic this weekend.','이번 주말 소풍 때 날씨가 계속 좋기를 바라요.','I hope it doesn''t rain; I wish I had brought an umbrella.','비가 안 오기를 바라요; 우산을 가져왔으면 좋았을 텐데요.','She hopes to pass the exam; he wishes he had studied harder.','그녀는 시험에 합격하기를 바라고, 그는 더 열심히 공부했더라면 좋았을 거라고 해요.'),
('nuc_emotion_15','like','love','adore','좋아하다','정말 좋아하다, 사랑하다','매우 좋아하다, 흠모하다','like < love < adore 강도 순. like는 호감, love는 깊은 애정, adore는 거의 숭배 수준의 애정.','like<love<adore. love는 가족·연인에 강력하고 적절, adore는 강한 애정 표현으로 약간 과장된 표현.','B1','emotion',1,0,'love affection heart relationships','I like coffee in the morning.','저는 아침에 커피를 좋아해요.','I love my family.','저는 제 가족을 사랑해요.','She adores her grandchildren.','그녀는 손주들을 무척 아껴요.','I like ice cream, love chocolate, and adore cheesecake.','아이스크림 좋아하고, 초콜릿 사랑하고, 치즈케이크는 정말 좋아해요.','He likes her, loves her cooking, and adores her laugh.','그는 그녀를 좋아하고, 그녀 요리를 사랑하고, 그녀 웃음을 흠모해요.'),
('nuc_emotion_17','a bit','a little','slightly','조금, 약간 (구어)','조금 (중립)','약간, 미세하게 (격식)','a bit과 a little은 거의 같음 (a bit이 더 캐주얼). slightly는 더 격식적이고 미세한 변화 강조.','a bit(캐주얼) ≤ a little(중립) ≤ slightly(격식). slightly는 신문·과학 글에서 자주 (slightly increased).','B1','emotion',1,0,'small amount degree little spice pinch','I''m a bit tired.','저는 조금 피곤해요.','I''m a little tired.','저는 약간 피곤해요.','I''m slightly tired.','저는 살짝 피곤해요.','Add a bit of salt; the soup needs a little more pepper; the broth is slightly warm.','소금 약간 넣고, 후추 좀 더 넣고, 국물이 살짝 따뜻해요.','I''m a bit annoyed, a little disappointed, and slightly amused.','좀 짜증나고, 조금 실망스럽고, 약간 재밌네요.'),
('nuc_emotion_05','excited','enthusiastic',NULL,'신이 난','열정적인',NULL,'excited는 특정 사건에 대한 흥분, enthusiastic은 어떤 일에 대한 지속적인 열정을 뜻해요.','excited는 순간적 감정, enthusiastic은 지속적 태도를 나타내요.','B2','emotion',1,5,'excitement enthusiasm energy','She was excited about the trip.','그녀는 여행에 대해 들떠 있었어요.','He is enthusiastic about teaching.','그는 가르치는 일에 열정적이에요.','I was excited for one concert, but she stays enthusiastic about music all year round.','저는 콘서트 하나에 들떴을 뿐이지만, 그녀는 일 년 내내 음악에 열정적이에요.','The kids were excited to open their birthday gifts.','아이들은 생일 선물을 열어보는 것에 신이 났어요.','He''s enthusiastic about cooking and learns a new recipe every week.','그는 요리에 열정적이어서 매주 새 요리법을 배워요.'),
('nuc_emotion_06','embarrassed','ashamed',NULL,'당황한 / 부끄러운','수치스러운',NULL,'embarrassed는 사회적 상황에서 느끼는 부끄러움, ashamed는 도덕적 잘못에서 오는 수치심이에요.','embarrassed는 실수, ashamed는 도덕·가치 위반과 관련돼요.','B2','emotion',1,6,'embarrassment shame emotion','I was embarrassed when I forgot her name.','그녀의 이름을 잊어버렸을 때 저는 당황했어요.','He was ashamed of his past behavior.','그는 자신의 과거 행동을 부끄러워했어요.','I was embarrassed by the typo, but truly ashamed of having lied about it.','오타 때문에 민망했지만, 그것에 대해 거짓말한 일은 정말로 부끄러웠어요.','I felt embarrassed when I tripped in front of everyone.','저는 모두 앞에서 넘어졌을 때 부끄러웠어요.','He was ashamed of the way he had spoken to her.','그는 그녀에게 말한 방식이 부끄러웠어요.'),
('nuc_emotion_07','worried','anxious',NULL,'걱정하는','불안한',NULL,'worried는 특정 문제에 대한 걱정, anxious는 막연한 불안 또는 간절히 원하는 느낌도 포함해요.','anxious는 "몹시 ~하고 싶어"라는 뜻으로도 쓰여요 (예: anxious to succeed).','B2','emotion',2,7,'worry anxiety stress','I''m worried about the exam results.','저는 시험 결과가 걱정돼요.','She was anxious to please her boss.','그녀는 상사를 만족시키려고 안달했어요.','I''m worried about tomorrow''s meeting, and the uncertainty makes me anxious all night.','저는 내일 회의가 걱정되고, 그 불확실함 때문에 밤새 불안해요.','We''re worried that the train might be cancelled.','우리는 기차가 취소될까 봐 걱정해요.','She felt anxious before her first day at the new job.','그녀는 새 직장 첫날 전에 불안했어요.'),
('nuc_emotion_09','jealous','envious',NULL,'질투하는','부러워하는',NULL,'jealous는 자기 것을 빼앗길까 두려운 감정, envious는 남의 것을 갖고 싶은 감정이에요.','jealous는 관계, envious는 소유·능력에 관한 감정이에요.','B2','emotion',2,9,'jealousy envy emotion relationship','He felt jealous when she talked to other men.','그녀가 다른 남자들과 이야기할 때 그는 질투를 느꼈어요.','I''m envious of her talent.','저는 그녀의 재능이 부러워요.','He grew jealous when his partner spent time with others, while I was merely envious of their freedom.','그는 파트너가 다른 사람들과 시간을 보내자 질투했고, 저는 그저 그들의 자유가 부러웠을 뿐이에요.','He''s jealous of the attention his sister gets.','그는 누나가 받는 관심을 질투해요.','I''m envious of how organized her closet is.','저는 그녀의 옷장이 얼마나 정리되어 있는지 부러워요.'),
('nuc_emotion_10','disappointed','discouraged',NULL,'실망한','낙담한',NULL,'disappointed는 기대가 충족되지 않은 실망, discouraged는 의욕을 잃은 낙담이에요.','disappointed는 결과에 대한 반응, discouraged는 계속하려는 의지가 꺾인 것이에요.','B2','emotion',1,10,'disappointment discouragement failure','She was disappointed by the result.','그녀는 결과에 실망했어요.','He felt discouraged after failing again.','그는 또 실패하고 나서 낙담했어요.','She was disappointed by the rejection, but not discouraged enough to stop trying.','그녀는 거절에 실망했지만, 시도를 멈출 만큼 낙담하지는 않았어요.','We were disappointed by the slow service at the restaurant.','우리는 식당의 느린 서비스에 실망했어요.','He felt discouraged but kept practicing every day.','그는 낙담했지만 매일 연습을 계속했어요.'),
('nuc_emotion_11','sympathy','empathy',NULL,'동정','공감',NULL,'sympathy는 타인의 고통을 가엽게 여기는 것, empathy는 그 감정을 함께 느끼는 것이에요.','empathy가 더 깊은 정서적 연결을 뜻해요 — 상담·리더십 문맥에서 중요해요.','C1','emotion',1,11,'empathy sympathy compassion','He expressed sympathy for the victims.','그는 피해자들에게 동정을 표했어요.','Good therapists show empathy toward clients.','훌륭한 치료사는 내담자에게 공감을 보여 줘요.','Sympathy lets us feel sorry for someone, while empathy lets us feel what they feel.','동정은 누군가를 안쓰럽게 여기게 하지만, 공감은 그 사람이 느끼는 것을 함께 느끼게 해 줘요.','We received many messages of sympathy after the loss.','상실 후 우리는 많은 동정의 메시지를 받았어요.','Empathy helps us truly understand other people''s experiences.','공감은 우리가 다른 사람의 경험을 진정으로 이해하는 데 도움이 돼요.'),
('nuc_emotion_12','melancholy','sorrow',NULL,'우울한 감성','슬픔 / 비탄',NULL,'melancholy는 이유 없이 스미는 우울한 기분, sorrow는 뚜렷한 이유가 있는 깊은 슬픔이에요.','melancholy는 시적 문맥에 자주 쓰이고, sorrow는 상실에 대한 비탄이에요.','C1','emotion',2,12,'melancholy sorrow sadness autumn','Autumn fills me with a quiet melancholy.','가을은 저를 잔잔한 우울감으로 가득 채워요.','His sorrow after the loss was immense.','상실 후 그의 슬픔은 어마어마했어요.','A sense of melancholy crept over her as the rain fell.','비가 내리자 그녀에게 우울감이 스며들었어요.','There was a quiet melancholy in the old photograph.','오래된 사진 속에 조용한 우울함이 있었어요.','The community shared in his sorrow at the funeral.','지역사회는 장례식에서 그의 슬픔을 함께했어요.'),
('nuc_emotion_13','elated','euphoric',NULL,'기분이 들뜬','황홀한 / 극도로 행복한',NULL,'elated는 매우 기쁘고 들뜬 상태, euphoric은 거의 비현실적으로 느껴질 만큼 황홀한 상태예요.','강도 순서: happy < elated < euphoric. euphoric은 극적인 상황에 써요.','C2','emotion',1,13,'elation euphoria happiness intense','She was elated by the good news.','그녀는 좋은 소식에 매우 기뻐했어요.','He felt euphoric after winning the championship.','그는 우승 후에 황홀감을 느꼈어요.','She was elated by the promotion, almost euphoric as she shared the news with her family.','그녀는 승진에 무척 기뻐했고, 가족에게 소식을 전하면서 거의 황홀할 정도였어요.','She was elated when she received the acceptance letter.','그녀는 합격 통지서를 받았을 때 들뜬 기분이었어요.','He felt euphoric after crossing the marathon finish line.','그는 마라톤 결승선을 넘은 후 황홀한 기분을 느꼈어요.'),
('nuc_environment_01','recycle','reuse',NULL,'재활용하다','재사용하다',NULL,'recycle은 소재를 분리해 새 제품으로 만드는 것, reuse는 그대로 다시 사용하는 것이에요.','reuse가 환경에 더 좋아요 — 에너지 소비 없이 다시 쓰니까요.','B1','environment',1,1,'recycle reuse environment green','Please recycle your plastic bottles.','플라스틱 병은 재활용해 주세요.','Bring a reusable bag to the store.','가게에 갈 때 재사용 가능한 가방을 가져오세요.','Most offices now recycle paper and cardboard separately.','요즘 대부분의 사무실에서는 종이와 골판지를 따로 재활용해요.','Sort plastics carefully before you recycle.','재활용하기 전에 플라스틱을 신중히 분류하세요.','Try to reuse jars and containers when you can.','가능할 때 병과 용기를 재사용해 보세요.'),
('nuc_environment_02','climate','weather',NULL,'기후 (장기)','날씨 (단기)',NULL,'weather는 오늘이나 이번 주의 날씨, climate는 수십 년에 걸친 기후 패턴이에요.','"Climate is what you expect, weather is what you get."라는 표현을 기억해요.','B1','environment',1,2,'climate weather environment global','Climate change is a global crisis.','기후 변화는 전 지구적 위기예요.','The weather today is sunny and mild.','오늘 날씨는 화창하고 온화해요.','The region''s climate is dry for most of the year.','그 지역의 기후는 일 년 중 대부분이 건조해요.','Climate change is already affecting daily life around the world.','기후 변화는 이미 전 세계 일상에 영향을 미치고 있어요.','The weather has been unusually warm this winter.','이번 겨울 날씨가 이례적으로 따뜻해요.'),
('nuc_environment_03','pollution','contamination',NULL,'오염 (환경)','오염 (특정 물질)',NULL,'pollution은 환경 전반의 오염, contamination은 특정 물질로 인한 오염이에요.','pollution은 넓은 개념, contamination은 특정 오염원이 있을 때 써요.','B1','environment',2,3,'pollution contamination environment water','Air pollution is a major problem in cities.','대기 오염은 도시의 큰 문제예요.','The river was contaminated with industrial chemicals.','그 강은 산업 화학 물질로 오염됐어요.','Plastic pollution is choking marine life in the oceans.','플라스틱 오염이 바다의 해양 생물을 질식시키고 있어요.','Air pollution levels are highest near busy roads.','대기 오염 수준은 번잡한 도로 근처에서 가장 높아요.','The water supply was contaminated by industrial runoff.','수돗물이 산업 폐수로 오염됐어요.'),
('nuc_environment_14','clean','pure',NULL,'깨끗한 (오염 없음)','순수한 (불순물 없음)',NULL,'clean은 오염·먼지가 없는 상태, pure는 다른 성분이 섞이지 않은 순수한 상태.','clean은 더러움이 없는 상태, pure는 다른 것이 섞이지 않은 상태. clean energy는 깨끗한 에너지, pure gold는 순금.','B1','environment',1,0,'clean pure water nature pristine','The river is clean again after the cleanup.','정화 작업 후에 강이 다시 깨끗해졌어요.','This water is pure and safe to drink.','이 물은 깨끗하고 마셔도 안전해요.','Please keep the kitchen clean after you cook.','요리한 뒤에는 주방을 깨끗하게 유지해 주세요.','Clean water has no pollution; pure water has no minerals.','깨끗한 물은 오염이 없고, 순수한 물은 미네랄도 없어요.','Clean the air; keep your intentions pure.','공기를 깨끗하게 하세요; 의도를 순수하게 유지하세요.'),
('nuc_environment_04','renewable','sustainable',NULL,'재생 가능한','지속 가능한',NULL,'renewable은 자원이 다시 생성될 수 있음을 뜻하고, sustainable은 장기적으로 유지 가능한 상태를 뜻해요.','renewable energy(재생에너지), sustainable development(지속 가능한 발전)이 자주 함께 쓰여요.','B2','environment',1,4,'renewable sustainable energy green','Solar energy is a renewable resource.','태양 에너지는 재생 가능한 자원이에요.','We need sustainable farming practices.','저희는 지속 가능한 농업 방식이 필요해요.','Wind power is one of the fastest-growing renewable sources.','풍력은 가장 빠르게 성장하는 재생 에너지원 중 하나예요.','Many countries are investing heavily in renewable energy.','많은 나라들이 재생에너지에 대규모로 투자하고 있어요.','Sustainable practices benefit both businesses and the planet.','지속 가능한 관행은 기업과 지구 모두에게 이로워요.'),
('nuc_environment_05','conservation','preservation',NULL,'보전 (지속적 관리)','보존 (원형 유지)',NULL,'conservation은 자원을 관리·사용하면서 보전하는 것, preservation은 손상 없이 원형 그대로 지키는 것이에요.','conservation은 관리·사용 포함, preservation은 변화 없이 유지하는 것이에요.','B2','environment',2,5,'conservation preservation nature wildlife','Wildlife conservation protects endangered species.','야생 동물 보호는 멸종 위기 종을 지켜요.','The building was preserved as a historical site.','그 건물은 역사적 유적지로 보존됐어요.','Water conservation becomes critical during long droughts.','물 절약은 긴 가뭄 동안 매우 중요해져요.','Wildlife conservation depends on community involvement.','야생동물 보전은 지역사회 참여에 달려 있어요.','Historic preservation has saved many beautiful buildings.','역사 보존은 많은 아름다운 건물을 살려왔어요.'),
('nuc_environment_06','emission','discharge',NULL,'배출 (가스)','방류 (액체·오염물)',NULL,'emission은 공기 중으로 가스·열이 나오는 것, discharge는 물이나 액체 오염물이 방류되는 것이에요.','carbon emission(탄소 배출), industrial discharge(공업 폐수 방류)로 구분해요.','B2','environment',1,6,'emission discharge pollution environment','Carbon emissions must be reduced dramatically.','탄소 배출량을 대폭 줄여야 해요.','The factory was fined for illegal discharge into the river.','그 공장은 강에 불법으로 방류한 혐의로 벌금을 물었어요.','Strict limits now apply to the discharge of chemicals from the plant.','이제 그 공장에서 나오는 화학 물질의 방류에 엄격한 제한이 적용돼요.','Reducing carbon emissions is a global priority.','탄소 배출량 감소는 세계적 우선과제예요.','The factory was fined for discharging waste into the river.','공장은 강에 폐기물을 방류한 혐의로 벌금을 받았어요.'),
('nuc_environment_07','deforestation','desertification',NULL,'삼림 벌채','사막화',NULL,'deforestation은 산림이 제거되는 것, desertification은 땅이 사막으로 변하는 것이에요.','deforestation(나무 사라짐) → soil erosion → desertification(사막화) 순서로 이어져요.','B2','environment',2,7,'deforestation desertification forest land','Deforestation in the Amazon threatens biodiversity.','아마존의 삼림 벌채는 생물 다양성을 위협해요.','Desertification is spreading in parts of Africa.','아프리카 일부 지역에서 사막화가 확산되고 있어요.','Illegal logging is the main driver of deforestation in the region.','불법 벌목이 그 지역 삼림 벌채의 주된 원인이에요.','Deforestation contributes significantly to climate change.','삼림 벌채는 기후 변화에 크게 기여해요.','Desertification is making farming impossible in some regions.','사막화로 일부 지역에서는 농사가 불가능해지고 있어요.'),
('nuc_environment_08','carbon footprint','ecological footprint',NULL,'탄소 발자국','생태 발자국',NULL,'carbon footprint는 온실가스 배출량, ecological footprint는 인간 활동에 필요한 자연 자원의 총량이에요.','carbon footprint는 CO₂ 중심, ecological footprint는 더 넓은 자원 소비예요.','C1','environment',1,8,'carbon footprint ecological environment impact','Flying increases your carbon footprint significantly.','비행기를 타면 탄소 발자국이 크게 늘어나요.','Our ecological footprint exceeds what Earth can sustain.','우리의 생태 발자국은 지구가 감당할 수 있는 한계를 넘어서요.','Switching to public transport can shrink your carbon footprint.','대중교통으로 바꾸면 탄소 발자국을 줄일 수 있어요.','Flying often increases your carbon footprint the most.','비행이 종종 탄소 발자국을 가장 많이 늘려요.','Our ecological footprint per person is unsustainable.','1인당 생태 발자국이 지속 불가능해요.'),
('nuc_environment_09','biodiversity','ecosystem',NULL,'생물 다양성','생태계',NULL,'biodiversity는 다양한 생물 종의 존재, ecosystem은 생물과 환경이 상호작용하는 시스템이에요.','ecosystem은 구조·시스템, biodiversity는 그 안의 다양성이에요.','C1','environment',2,9,'biodiversity ecosystem nature environment','Biodiversity loss threatens food security.','생물 다양성의 손실은 식량 안보를 위협해요.','The wetland ecosystem supports thousands of species.','그 습지 생태계는 수천 종의 생물을 지탱해요.','Protecting forests is one of the best ways to preserve biodiversity.','숲을 보호하는 것은 생물 다양성을 보존하는 가장 좋은 방법 중 하나예요.','Biodiversity is essential for healthy food systems.','생물 다양성은 건강한 식량 시스템에 필수적이에요.','The coral reef ecosystem supports an incredible variety of life.','산호초 생태계는 놀라운 다양한 생명을 지지해요.'),
('nuc_environment_10','mitigation','adaptation',NULL,'완화 (원인 줄이기)','적응 (결과에 대응)',NULL,'mitigation은 기후 변화 원인을 줄이는 것, adaptation은 이미 일어나는 변화에 적응하는 것이에요.','mitigation(원인 감소) + adaptation(결과 대응) 두 가지 전략이 필요해요.','C1','environment',1,10,'mitigation adaptation climate policy','Cutting CO₂ emissions is a form of climate mitigation.','이산화탄소 배출을 줄이는 건 기후 완화의 한 형태예요.','Building sea walls is a form of climate adaptation.','방파제를 세우는 건 기후 적응의 한 형태예요.','Effective mitigation requires governments and businesses to act together.','효과적인 완화를 위해서는 정부와 기업이 함께 행동해야 해요.','Mitigation strategies focus on reducing future emissions.','완화 전략은 미래 배출량을 줄이는 데 집중해요.','Climate adaptation includes building flood defenses.','기후 적응은 홍수 방지 시설 건설을 포함해요.'),
('nuc_environment_11','greenwashing','eco-friendly',NULL,'그린워싱 (위장 친환경)','친환경',NULL,'eco-friendly는 진정 환경에 이로운 것, greenwashing은 친환경인 척하는 위장 마케팅이에요.','마케팅에서 "green" 주장이 증거 없이 나오면 greenwashing일 수 있어요.','C1','environment',2,11,'greenwashing eco friendly marketing','That brand was accused of greenwashing.','그 브랜드는 그린워싱으로 비난을 받았어요.','We chose eco-friendly packaging for our products.','저희는 제품에 친환경 포장재를 선택했어요.','Vague labels like ''natural'' are sometimes just greenwashing.','''천연''처럼 모호한 표시는 때로는 그냥 그린워싱일 뿐이에요.','Critics accused the company of greenwashing its packaging claims.','비평가들은 회사가 포장 주장으로 그린워싱을 한다고 비난했어요.','We try to buy eco-friendly products whenever possible.','가능할 때마다 친환경 제품을 사려고 노력해요.'),
('nuc_environment_12','anthropogenic','natural',NULL,'인위적인 (인간 활동으로)','자연적인',NULL,'anthropogenic은 인간 활동으로 발생하는 것, natural은 자연 현상이에요.','anthropogenic climate change는 "인간이 유발한 기후 변화"를 가리켜요.','C2','environment',1,12,'anthropogenic natural climate change','Most climate change today is anthropogenic.','오늘날 대부분의 기후 변화는 인간이 일으킨 것이에요.','Volcanic eruptions are a natural source of CO₂.','화산 폭발은 이산화탄소의 자연적 발생원이에요.','Scientists distinguish anthropogenic emissions from natural ones.','과학자들은 인위적인 배출과 자연적인 배출을 구분해요.','Anthropogenic factors account for most recent warming.','인위적 요인들이 최근 온난화의 대부분을 차지해요.','Natural climate variability also plays a smaller role.','자연 기후 변동성도 작은 역할을 해요.'),
('nuc_environment_13','resilience','vulnerability',NULL,'회복력','취약성',NULL,'resilience는 충격을 견디고 회복하는 능력, vulnerability는 피해를 입기 쉬운 취약한 상태예요.','resilience와 vulnerability는 기후·재난 정책 문서에서 핵심 어휘예요.','C2','environment',2,13,'resilience vulnerability climate disaster','Coastal cities must build resilience against flooding.','해안 도시는 홍수에 대한 회복력을 길러야 해요.','Low-income communities show high vulnerability to climate change.','저소득 지역사회는 기후 변화에 높은 취약성을 보여요.','Diverse ecosystems tend to show greater resilience after disasters.','다양한 생태계는 재해 이후 더 큰 회복력을 보이는 경향이 있어요.','Cities are building resilience against extreme weather.','도시들은 극한 날씨에 대한 회복력을 쌓고 있어요.','Poor communities often have the highest vulnerability to disasters.','가난한 지역사회들이 재난에 대한 취약성이 가장 높은 경우가 많아요.'),
('nuc_family_01','house','home',NULL,'집 (건물)','집 (가정·보금자리)',NULL,'''house''는 물리적 건물을 뜻하고, ''home''은 가족과 함께하는 따뜻한 보금자리의 느낌을 담아요.','부동산·구조물은 ''house'', 정서적 보금자리는 ''home''으로 구분해서 써요.','B1','family',2,0,'house exterior cozy home interior','They bought a new house last year.','그들은 작년에 새 집을 샀어요.','Home is where the family is.','가족이 있는 곳이 곧 집이에요.','A house becomes a home once you fill it with people you love.','집은 사랑하는 사람들로 채워질 때 비로소 보금자리가 돼요.','We finally moved into the house we built ourselves.','우리는 마침내 직접 지은 그 집으로 이사했어요.','After years abroad, coming home felt warm and comforting.','수년간 외국에 있다가 집에 돌아오니 따뜻하고 포근하게 느껴졌어요.'),
('nuc_family_02','family','relatives',NULL,'가족 (직계)','친척 (확장된 가족)',NULL,'''family''는 보통 부모·자녀 등 가까운 직계, ''relatives''는 사촌·이모·삼촌 같은 확장된 친척이에요.','같이 사는 직계는 ''family'', 명절에 모이는 확장 친척은 ''relatives''로 써요.','B1','family',2,0,'nuclear family extended family gathering','I live with my family.','저는 가족과 함께 살아요.','My relatives came from all over for the holiday.','제 친척들이 명절을 맞아 곳곳에서 왔어요.','My whole family gathers for dinner every Sunday.','저희 가족은 매주 일요일에 다 같이 저녁을 먹어요.','We invite all our relatives to the wedding, not just our immediate family.','저희는 직계 가족뿐 아니라 모든 친척을 결혼식에 초대해요.','My family is small, but I have dozens of relatives across the country.','제 가족은 단출하지만, 전국에 수십 명의 친척이 있어요.'),
('nuc_family_03','marry','wed',NULL,'결혼하다 (일상)','결혼하다 (격식·언론)',NULL,'''marry''는 일상 회화의 자연스러운 표현, ''wed''는 신문 기사나 격식 있는 발표에 더 자주 써요.','일상 대화는 ''marry'', 뉴스·헤드라인이나 시적인 표현은 ''wed''로 써요.','B2','family',2,0,'wedding ceremony bride groom','They will marry next spring.','그들은 내년 봄에 결혼할 거예요.','The couple wed in a private ceremony.','그 커플은 비공개 예식으로 결혼했어요.','They decided to marry after dating for five years.','그들은 5년간 사귄 뒤에 결혼하기로 했어요.','She hopes to marry someone who shares her love of travel.','그녀는 여행을 향한 자신의 애정을 함께 나눌 사람과 결혼하기를 바라요.','The royal couple are due to wed at the cathedral this autumn.','그 왕실 부부는 올가을 대성당에서 결혼할 예정이에요.'),
('nuc_family_04','raise','bring up','rear','키우다 (미국식, 일반)','키우다 (영국식, 일상)','기르다 (격식·문어)','''raise''는 미국식·중립, ''bring up''은 영국식·일상, ''rear''는 문어적·격식 있는 표현이에요.','미국 영어는 ''raise'', 영국 영어 일상은 ''bring up'', 문어·격식은 ''rear''로 구분해요.','C1','family',2,0,'parent raising child generations','She raised her kids alone.','그녀는 혼자서 아이들을 키웠어요.','I was brought up in Seoul.','저는 서울에서 자랐어요.','The children were reared in the countryside.','그 아이들은 시골에서 자랐어요.','They chose to raise their children with both languages from birth.','그들은 태어날 때부터 두 언어로 아이들을 키우기로 했어요.','He was brought up to always say please and thank you.','그는 항상 부탁과 감사의 말을 하도록 자랐어요.'),
('nuc_family_05','siblings','brothers and sisters',NULL,'형제자매 (격식)','형제자매 (일상)',NULL,'''siblings''는 격식·서면, ''brothers and sisters''는 친근한 일상 표현이에요.','서류·면접에서는 ''siblings'', 가족 얘기 나누는 일상에는 ''brothers and sisters''를 써요.','C1','family',2,0,'siblings group photo','Do you have any siblings?','형제자매가 있으세요?','I have two brothers and a sister.','저는 형제 둘과 여동생 하나가 있어요.','As the eldest of five siblings, she learned to take charge early.','다섯 남매 중 맏이로서, 그녀는 일찍부터 책임지는 법을 배웠어요.','Please list the names and ages of all your siblings on the form.','양식에 형제자매 모두의 이름과 나이를 기재해 주세요.','Growing up with four brothers and sisters, the house was always lively.','형제자매 넷과 함께 자라서 집안은 늘 활기가 넘쳤어요.'),
('nuc_family_06','ancestor','forefather','predecessor','조상 (혈통)','선조 (역사·격식)','전임자 (직위·역할)','''ancestor''는 혈연 조상, ''forefather''는 민족·역사적 선조, ''predecessor''는 직위·자리를 물려준 사람이에요.','혈통은 ''ancestor'', 역사·민족은 ''forefather'', 직책·직업은 ''predecessor''로 정확히 구분해요.','C2','family',3,0,'old portrait lineage history','My ancestors came from Jeju Island.','제 조상들은 제주도 출신이에요.','Our forefathers founded this nation.','우리 선조들이 이 나라를 세웠어요.','She replaced her predecessor as CEO.','그녀는 전임자의 뒤를 이어 CEO가 됐어요.','Genetic testing revealed that her ancestors had migrated across three continents.','유전자 검사를 통해 그녀의 조상이 세 대륙을 거쳐 이주했음이 밝혀졌어요.','The new director continued the reforms her predecessor had begun.','신임 이사는 전임자가 시작한 개혁을 이어 갔어요.'),
('nuc_greeting_14','listen','hear',NULL,'듣다 (의식적 집중)','들리다 (수동적 수신)',NULL,'listen은 의도적으로 귀 기울이는 행위, hear는 그냥 소리가 들리는 수동적 수신.','listen은 의도적, hear는 우연적. "Listen!"은 집중 요청, "Did you hear that?"는 그냥 들렸냐는 확인.','A2','greeting',1,0,'listening attention focus headphones conversation','Please listen carefully.','잘 들어 주세요.','I heard a strange noise outside.','밖에서 이상한 소리가 들렸어요.','Listen to the instructions before you begin the test.','시험을 시작하기 전에 안내 사항을 잘 들으세요.','I was listening to music when I heard someone knock.','음악을 듣고 있는데 누가 노크하는 소리가 들렸어요.','You can hear without listening, but you can''t listen without hearing.','들리기만 할 수도 있지만, 들으려면 들려야 해요.'),
('nuc_greeting_15','look','see',NULL,'(의도적) 보다','(우연히/시각적으로) 보다',NULL,'look은 의식적으로 시선을 두는 행위, see는 시각적으로 인지·발견하는 결과.','look은 의도, see는 인지. "Look!"은 시선 끌기, "I see"는 이해/인지의 표현.','A2','greeting',1,0,'looking watching binoculars eyes attention','Look at this beautiful painting.','이 아름다운 그림을 보세요.','I see a bird outside the window.','창밖에 새 한 마리가 보여요.','Look both ways before you cross the street.','길을 건너기 전에 양쪽을 살펴보세요.','I looked everywhere but didn''t see my keys.','곳곳을 봤지만 열쇠가 보이지 않았어요.','Look at the sky — do you see the stars?','하늘을 봐요 — 별이 보여요?'),
('nuc_greeting_17','too','as well','also','~도 (문장 끝)','~도 (문장 끝, 더 격식)','~도 (조동사/be 뒤)','셋 다 "~도"라는 뜻. too/as well은 문장 끝, also는 조동사·be 동사 뒤 또는 문장 앞.','too/as well = 문장 끝, also = 동사 앞·조동사 뒤·문장 앞. "Also, I forgot..."도 자연스러워요.','A2','greeting',1,0,'addition too also as well plus including','I love pizza too.','저도 피자를 좋아해요.','I love pizza as well.','저도 피자를 좋아해요.','I also love pizza.','저 역시 피자를 좋아해요.','She came too, as well as her sister, and her mom also.','그녀도 왔고, 언니도 왔고, 엄마도 왔어요.','I''m tired too; I''m hungry as well; I''m also cold.','저도 피곤하고, 저도 배고프고, 저도 추워요.'),
('nuc_greeting_01','meet','see',NULL,'(처음) 만나다','(아는 사람을) 만나다',NULL,'meet는 보통 처음 만남을 뜻하고, see는 이미 아는 사람과의 만남을 뜻해요.','"Nice to meet you"는 처음 만날 때만, "Nice to see you"는 재회 시 사용해요.','B1','greeting',1,1,'meeting people handshake','Nice to meet you!','만나서 반가워요!','Nice to see you again!','다시 만나서 반가워요!','I''d love for you to meet my parents this weekend.','이번 주말에 저희 부모님을 꼭 만나 주셨으면 좋겠어요.','It''s lovely to meet you in person after so many emails.','그렇게 많은 이메일을 주고받은 후 직접 만나뵙게 되어 반가워요.','I hope to see you again at the next conference.','다음 컨퍼런스에서 다시 뵙기를 바라요.'),
('nuc_greeting_02','say','tell',NULL,'말하다 (내용 중심)','말하다 (상대 중심)',NULL,'say는 말한 내용에 초점을 두고, tell은 누구에게 말하는지 상대방에 초점을 둬요.','"Tell me" / "Say hello"처럼 tell 뒤에는 사람, say 뒤에는 내용이 와요.','B1','greeting',2,2,'conversation talking','She said goodbye.','그녀는 작별 인사를 했어요.','She told me to leave.','그녀는 저에게 떠나라고 했어요.','Please tell your sister I said hello.','여동생분께 제가 안부 전한다고 말해 주세요.','She told us a fascinating story over dinner.','그녀는 저녁 식사 중에 흥미로운 이야기를 들려줬어요.','Could you say that one more time, please?','한 번 더 말씀해 주시겠어요?'),
('nuc_greeting_03','speak','talk',NULL,'말하다 (공식적)','말하다 (대화하다)',NULL,'speak는 좀 더 공식적이거나 일방적인 말하기, talk는 서로 주고받는 대화를 강조해요.','공식 자리에서는 speak, 편한 대화에서는 talk가 자연스러워요.','B1','greeting',1,3,'speaking conversation formal','May I speak to the manager?','매니저와 통화할 수 있을까요?','Can we talk for a moment?','잠시 이야기 나눌 수 있을까요?','She was invited to speak at the annual conference.','그녀는 연례 콘퍼런스에서 연설하도록 초청받았어요.','I''d like to speak to someone in the finance department.','재무부서에 계신 분과 통화하고 싶어요.','We talked for hours about our weekend plans.','우리는 주말 계획에 대해 몇 시간 동안 이야기했어요.'),
('nuc_greeting_04','greet','welcome',NULL,'인사하다','환영하다',NULL,'greet는 만났을 때 인사하는 행위, welcome은 상대를 따뜻이 받아들이는 행위예요.','greet는 짧은 인사, welcome은 공간이나 상황에 받아들인다는 뉘앙스가 있어요.','B1','greeting',2,4,'welcome door arrival','She greeted every guest at the door.','그녀는 문 앞에서 모든 손님을 맞이했어요.','Welcome to our home!','저희 집에 오신 걸 환영해요!','The receptionist greeted me with a nod, then warmly welcomed me into the office.','접수원이 고갯짓으로 저를 맞이한 뒤, 따뜻하게 사무실로 맞아들였어요.','The teacher greeted every student by name.','선생님은 모든 학생을 이름으로 인사했어요.','They welcomed us with warm hugs at the airport.','그들은 공항에서 따뜻한 포옹으로 우리를 환영했어요.'),
('nuc_greeting_07','acquaintance','friend',NULL,'지인','친구',NULL,'acquaintance는 알고 있지만 친밀하지 않은 사람, friend는 친밀한 관계를 나타내요.','한국어 "아는 사람"은 acquaintance에 가깝고, 진짜 친한 사이가 friend예요.','B1','greeting',2,7,'friends acquaintance social','He''s just an acquaintance from work.','그는 그냥 직장에서 알고 지내는 사람이에요.','She''s my best friend.','그녀는 제 가장 친한 친구예요.','We''re acquaintances, not close friends, so I wouldn''t ask him for a favor.','우리는 가까운 친구가 아니라 그냥 아는 사이라서, 저는 그에게 부탁하지 않을 거예요.','I have a few acquaintances in the neighborhood.','저는 동네에 지인들이 몇 명 있어요.','A true friend listens without judging.','진정한 친구는 판단하지 않고 들어줘요.'),
('nuc_greeting_16','believe','trust',NULL,'믿다 (사실/존재)','신뢰하다 (사람·관계)',NULL,'believe는 어떤 사실/존재를 진실로 여기는 것, trust는 사람·관계를 신뢰하는 것 (의존 포함).','believe는 진위 판단, trust는 의존·신뢰. 사람에 대해서는 둘 다 가능하지만 의미 다름.','B1','greeting',1,0,'trust relationship handshake confidence','I believe in ghosts.','저는 유령이 있다고 믿어요.','I trust my best friend completely.','저는 제 가장 친한 친구를 완전히 신뢰해요.','I believe that hard work eventually pays off.','저는 노력이 결국 보답받는다고 믿어요.','I believe her story, but I don''t fully trust her yet.','그녀 이야기를 믿지만, 그녀를 완전히 신뢰하지는 않아요.','You can believe a fact, but you trust a person.','사실은 믿을 수 있지만, 사람은 신뢰해야 해요.'),
('nuc_greeting_05','introduce','present',NULL,'소개하다','발표하다 / 소개하다',NULL,'introduce는 사람을 서로 알게 해주는 것, present는 좀 더 격식 있는 자리에서 소개·발표하는 것이에요.','비즈니스 자리에서는 present, 일상 자리에서는 introduce가 더 자연스러워요.','B2','greeting',1,5,'introduction formal meeting','Let me introduce my colleague.','제 동료를 소개할게요.','Allow me to present our new director.','저희 새 이사님을 소개해 드리겠습니다.','Before the speech, the chairman will introduce the guest of honor.','연설 전에 의장님이 주빈을 소개하실 거예요.','May I introduce you to our project manager?','저희 프로젝트 매니저를 소개해 드릴게요.','She presented the award to last year''s winner.','그녀는 작년 수상자에게 상을 수여했어요.'),
('nuc_greeting_06','farewell','goodbye',NULL,'작별 (격식)','안녕히 가세요 (일상)',NULL,'farewell은 격식 있거나 오랜 이별 상황, goodbye는 일상적인 작별 인사에 써요.','farewell은 감정적·격식적 뉘앙스, goodbye는 가볍게 쓸 수 있어요.','B2','greeting',2,6,'goodbye farewell parting','It was a bittersweet farewell.','그것은 달콤씁쓸한 작별이었어요.','Goodbye! See you tomorrow.','안녕히 가세요! 내일 봬요.','The retiring professor gave a moving farewell speech to the whole faculty.','은퇴하시는 교수님께서 전 교직원에게 감동적인 고별 연설을 하셨어요.','They said a quiet farewell at the airport gate.','그들은 공항 게이트에서 조용한 작별 인사를 나눴어요.','Goodbye for now — see you next week!','오늘은 안녕히 가세요 — 다음 주에 봐요!'),
('nuc_greeting_08','familiar','intimate',NULL,'익숙한 / 친숙한','친밀한 / 각별한',NULL,'familiar는 알고 있어 낯설지 않은 느낌, intimate는 감정적으로 매우 가까운 관계를 뜻해요.','familiar는 인지적 친숙함, intimate는 감정적 친밀감을 강조해요.','B2','greeting',2,8,'familiarity friendship close','Her voice sounds familiar.','그녀의 목소리가 낯익게 들려요.','They have an intimate friendship.','그들은 친밀한 우정을 나누고 있어요.','His face looked familiar, but we weren''t close enough to share anything intimate.','그의 얼굴은 낯익었지만, 우리는 속마음을 나눌 만큼 가깝지는 않았어요.','The street felt familiar even after twenty years away.','20년 떠나 있었는데도 그 거리는 친숙하게 느껴졌어요.','They share an intimate bond after going through that together.','그 일을 함께 겪은 후 그들은 친밀한 유대를 나눠요.'),
('nuc_greeting_09','formal','polite',NULL,'격식 있는','정중한',NULL,'formal은 형식과 규칙을 따르는 것, polite는 예의 바른 태도 자체를 뜻해요.','formal은 복장·행사·언어 형식을 가리키고, polite는 행동 예절을 가리켜요.','B2','greeting',1,9,'formal polite manners','The ceremony was very formal.','그 행사는 매우 격식 있었어요.','He was polite to everyone.','그는 모두에게 정중했어요.','He stayed perfectly polite, though the meeting itself wasn''t particularly formal.','회의 자체는 특별히 격식 있지는 않았지만, 그는 시종일관 더없이 정중했어요.','The dinner was formal and required a black tie.','그 저녁 식사는 격식 있고 정장이 필요했어요.','She''s always polite, even when she disagrees.','그녀는 의견이 다를 때도 항상 정중해요.'),
('nuc_greeting_10','chat','converse',NULL,'잡담하다','대화하다 (격식)',NULL,'chat은 가벼운 수다, converse는 좀 더 진지하거나 격식 있는 대화를 뜻해요.','chat은 일상·온라인 대화, converse는 글·격식 문맥에서 자주 보여요.','B2','greeting',2,10,'chatting conversation casual','We chatted about the weather.','우리는 날씨에 대해 이야기를 나눴어요.','They conversed in fluent French.','그들은 유창한 프랑스어로 대화했어요.','They chatted casually at first, then began to converse seriously about the budget.','그들은 처음에는 가볍게 잡담하다가, 곧 예산에 대해 진지하게 대화하기 시작했어요.','We chatted briefly in the lobby before the meeting.','회의 전에 우리는 로비에서 잠깐 잡담을 나눴어요.','They conversed politely throughout the dinner.','그들은 저녁 식사 내내 정중하게 대화했어요.'),
('nuc_greeting_11','address','call',NULL,'~라고 부르다 (호칭)','~라고 부르다 (이름)',NULL,'address는 격식 있는 호칭 방식, call은 이름이나 별명으로 부르는 일상적 표현이에요.','공식 자리에서는 address, 편한 자리에서는 call을 써요.','C1','greeting',1,11,'name title address formal','Please address me as Dr. Kim.','저를 김 박사라고 불러 주세요.','Just call me Mike.','그냥 마이크라고 부르세요.','At the conference, please address senior staff by their titles rather than their first names.','콘퍼런스에서는 고위 직원을 이름이 아니라 직함으로 불러 주세요.','In formal letters, please address the recipient as "Dear Madam."','공식 편지에서는 수신자를 "Dear Madam"이라고 호칭하세요.','Everyone just calls him by his first name at the office.','사무실에서 모두가 그를 이름으로 불러요.'),
('nuc_greeting_12','cordial','warm',NULL,'정중하고 친절한','따뜻한',NULL,'cordial은 격식 있으면서도 친절한 뉘앙스, warm은 감정적으로 따뜻한 느낌을 줘요.','cordial은 비즈니스·공식 문맥, warm은 개인 감정 표현에 자주 써요.','C1','greeting',2,12,'warm cordial welcome hospitality','The host gave a cordial welcome.','주최자는 진심 어린 환영을 해 줬어요.','She has a warm personality.','그녀는 따뜻한 성격을 지녔어요.','We received a cordial invitation to the embassy reception.','우리는 대사관 리셉션에 정중한 초대를 받았어요.','The CEO gave a cordial response to the journalist''s questions.','CEO는 기자의 질문에 정중하고 친절하게 답했어요.','Her smile was so warm that it instantly relaxed everyone.','그녀의 미소가 너무 따뜻해서 즉시 모두를 편안하게 했어요.'),
('nuc_greeting_13','salutation','greeting',NULL,'(서신의) 인사말','인사 / 인사하기',NULL,'salutation은 편지·이메일 첫머리 인사말을 특별히 가리키고, greeting은 모든 종류의 인사를 포함해요.','salutation은 글쓰기에서, greeting은 구어·문어 모두에서 쓰여요.','C2','greeting',1,13,'letter salutation formal writing','The salutation in the email read "Dear Sir."','그 이메일의 첫인사는 "친애하는 선생님께"였어요.','A simple greeting can brighten someone''s day.','간단한 인사 한마디가 누군가의 하루를 밝게 해 줄 수 있어요.','A warm salutation at the top of an email can set a friendlier tone than a plain greeting.','이메일 상단의 따뜻한 첫인사는 평범한 인사보다 더 친근한 분위기를 만들 수 있어요.','The salutation in formal emails matters more than most people think.','공식 이메일의 인사말은 사람들이 생각하는 것보다 더 중요해요.','A simple greeting can change someone''s entire day.','간단한 인사가 누군가의 하루를 완전히 바꿀 수 있어요.'),
('nuc_health_14','hurt','pain',NULL,'아프다 (동사)','통증 (명사)',NULL,'hurt는 동사 (아프다, 다치게 하다), pain은 명사 (통증). 한국어는 둘 다 "아픔"이라 헷갈림.','hurt는 동사(아프다), pain은 명사(통증). "I have a pain"은 OK, "I have a hurt"는 어색.','A2','health',1,0,'pain headache hurt body health','My back hurts after sitting all day.','하루 종일 앉아 있었더니 허리가 아파요.','I have a sharp pain in my back.','허리에 날카로운 통증이 있어요.','My feet hurt after standing in line all afternoon.','오후 내내 줄을 서 있었더니 발이 아파요.','My head hurts; the pain is unbearable.','머리가 아파요; 통증이 참기 어려워요.','It hurts when I move; the pain comes and goes.','움직이면 아파요; 통증이 왔다 갔다 해요.'),
('nuc_health_01','sick','ill',NULL,'아픈 (일상)','아픈 (격식)',NULL,'sick은 미국식 일상 표현, ill은 영국식 또는 격식 표현이에요. 둘 다 몸이 아프다는 뜻이에요.','sick은 미국, ill은 영국에서 선호해요. ill이 좀 더 심각한 뉘앙스이기도 해요.','B1','health',1,1,'sick ill health medical','I feel sick today.','오늘 몸이 안 좋아요.','She was seriously ill in hospital.','그녀는 병원에서 심각하게 아팠어요.','In American English you''d say you feel sick, while in British English you''d say you feel ill.','미국 영어에서는 ''feel sick''이라고 하고, 영국 영어에서는 ''feel ill''이라고 해요.','She''s been sick with the flu for three days.','그녀는 3일째 독감으로 아파요.','He was too ill to attend the meeting.','그는 회의에 참석하기 너무 아팠어요.'),
('nuc_health_02','pain','ache',NULL,'통증 (갑작스럽고 강한)','통증 (지속적이고 은은한)',NULL,'pain은 급성이거나 강한 통증, ache는 두통이나 근육통처럼 지속적으로 은은하게 아픈 것이에요.','toothache, headache, stomachache처럼 -ache는 특정 부위 통증에 붙여요.','B1','health',1,2,'pain ache symptom body','I felt a sharp pain in my chest.','가슴에 날카로운 통증을 느꼈어요.','I have a headache and a backache.','저는 두통과 요통이 있어요.','A stabbing pain in his side sent him to the emergency room.','옆구리를 찌르는 듯한 통증 때문에 그는 응급실로 갔어요.','A sudden pain in my knee made me sit down.','무릎에 갑작스러운 통증이 와서 저는 앉았어요.','I''ve had a dull ache in my shoulder all day.','하루 종일 어깨에 은은한 통증이 있어요.'),
('nuc_health_03','symptom','sign',NULL,'증상','징후',NULL,'symptom은 환자가 느끼는 주관적 증상, sign은 의사가 관찰하는 객관적 징후예요.','symptom(증상)은 환자 관점, sign(징후)은 의사 관점이에요.','B1','health',2,3,'symptom sign medical health','Common symptoms include fever and fatigue.','흔한 증상으로는 발열과 피로가 있어요.','Swollen lymph nodes are a sign of infection.','림프절이 붓는 것은 감염의 징후예요.','A cough is a symptom the patient reports, while a rash is a sign the doctor can see.','기침은 환자가 호소하는 증상이고, 발진은 의사가 볼 수 있는 징후예요.','List your symptoms so the doctor can help.','의사가 도울 수 있도록 증상을 나열해 주세요.','A high fever can be a sign of infection.','고열은 감염의 징후일 수 있어요.'),
('nuc_health_15','recover','heal',NULL,'회복하다 (전체적)','낫다 (상처·신체)',NULL,'recover는 병·수술·심리에서 전체적으로 회복, heal은 주로 상처·뼈 등이 낫는 신체적 치유.','heal은 상처가 닫히고 낫는 것, recover는 병·상태로부터의 전반적 회복. 마음의 상처도 heal이 가능.','B1','health',1,0,'recovery healing wound bandage health','She''s recovering from surgery quickly.','그녀는 수술 후 빠르게 회복하고 있어요.','The wound healed in two weeks.','그 상처는 2주 만에 나았어요.','It took her months to recover from the illness.','그녀가 병에서 회복하는 데 몇 달이 걸렸어요.','My broken arm healed, and I''ve fully recovered.','부러진 팔이 나았고, 완전히 회복했어요.','It takes time to heal physically and recover emotionally.','신체적으로 낫는 데도, 감정적으로 회복하는 데도 시간이 필요해요.'),
('nuc_health_04','cure','treat',NULL,'완치하다','치료하다',NULL,'treat는 증상을 다스리는 치료, cure는 병을 완전히 고치는 완치예요.','treat는 과정, cure는 결과(완치)를 강조해요.','B2','health',1,4,'cure treat medicine hospital','There is no known cure for this disease.','이 병에는 알려진 치료법이 없어요.','The doctor treated my infection with antibiotics.','의사가 항생제로 제 감염을 치료했어요.','Doctors can treat the symptoms with medication, but they still can''t cure the illness itself.','의사들은 약으로 증상을 치료할 수는 있지만, 여전히 병 자체를 완치하지는 못해요.','Scientists are searching for a cure for the disease.','과학자들은 그 질병의 치료법을 찾고 있어요.','The clinic treats patients of all ages.','그 병원은 모든 연령의 환자를 치료해요.'),
('nuc_health_05','physician','doctor',NULL,'내과 의사 (격식)','의사 (일반)',NULL,'doctor는 일반적인 의사, physician은 특히 내과 전문의를 가리켜요.','physician assistant(PA)는 의사 보조사를 뜻하는 직함이에요.','B2','health',2,5,'physician doctor medical professional','Consult a physician before taking this medication.','이 약을 복용하기 전에 의사와 상담하세요.','My doctor advised me to rest.','제 의사는 저에게 쉬라고 조언했어요.','For a routine check-up I see my family doctor, but the hospital referred me to a specialist physician.','정기 검진은 가정의에게 받지만, 병원에서는 저를 전문의에게 의뢰했어요.','Please consult a physician about long-term medication.','장기 약물 복용에 대해서는 의사와 상의하세요.','My doctor recommended more exercise and better sleep.','의사가 더 많은 운동과 더 나은 수면을 권장했어요.'),
('nuc_health_06','diet','nutrition',NULL,'식단 / 다이어트','영양',NULL,'diet는 특정 목적을 위한 식단 또는 식습관, nutrition은 음식의 영양소와 건강 관계를 뜻해요.','diet는 뭘 먹느냐(선택), nutrition은 영양 성분·과학을 가리켜요.','B2','health',1,6,'diet nutrition food health','She''s on a low-carb diet.','그녀는 저탄수화물 식단을 하고 있어요.','Good nutrition is essential for children.','좋은 영양은 아이들에게 필수적이에요.','A trendy diet may help you lose weight, but it can lack the nutrition your body needs.','유행하는 다이어트는 살을 빼는 데 도움이 될 수 있지만, 몸에 필요한 영양이 부족할 수 있어요.','A balanced diet is more sustainable than extreme rules.','균형 잡힌 식단이 극단적인 규칙보다 지속 가능해요.','Good nutrition supports immune health.','좋은 영양 섭취가 면역 건강을 뒷받침해요.'),
('nuc_health_07','allergy','intolerance',NULL,'알레르기 (면역 반응)','불내성 (소화 문제)',NULL,'allergy는 면역계가 반응하는 것, intolerance는 소화 시스템이 특정 식품을 처리 못 하는 것이에요.','알레르기는 생명을 위협할 수 있어요. intolerance는 덜 심각하지만 불편해요.','B2','health',2,7,'allergy intolerance food health','She has a severe nut allergy.','그녀는 심한 견과류 알레르기가 있어요.','He has lactose intolerance.','그는 유당 불내증이 있어요.','A nut allergy can trigger a dangerous immune reaction, unlike a mild food intolerance.','견과류 알레르기는 가벼운 음식 불내증과 달리 위험한 면역 반응을 일으킬 수 있어요.','She has a severe peanut allergy and carries an EpiPen.','그녀는 심한 땅콩 알레르기가 있어 에피펜을 가지고 다녀요.','Many people have lactose intolerance without knowing it.','많은 사람들이 자기도 모르게 유당 불내성이 있어요.'),
('nuc_health_08','pharmacy','drugstore',NULL,'약국 (약 중심)','드럭스토어 (잡화 포함)',NULL,'pharmacy는 처방전 약을 조제하는 약국, drugstore는 약 외에도 화장품·잡화를 파는 곳이에요.','pharmacist는 약사, drugstore는 미국식 표현이에요.','B2','health',1,8,'pharmacy drugstore medicine prescription','Pick up the prescription at the pharmacy.','약국에서 처방약을 받아 오세요.','I got some cold medicine at the drugstore.','저는 약국에서 감기약을 좀 샀어요.','I dropped off my prescription at the pharmacy and grabbed some snacks at the drugstore next door.','저는 약국에 처방전을 맡기고, 옆 가게에서 간식을 좀 샀어요.','The pharmacy is open 24 hours near the hospital.','병원 근처 약국은 24시간 영업해요.','I picked up shampoo and ibuprofen at the drugstore.','저는 드럭스토어에서 샴푸와 이부프로펜을 샀어요.'),
('nuc_health_09','chronic','acute',NULL,'만성적인','급성의',NULL,'chronic은 장기간 지속되는 만성 상태, acute는 갑자기 심하게 나타나는 급성 상태예요.','chronic(만성) vs acute(급성)는 의료 문서·뉴스에서 자주 나와요.','C1','health',1,9,'chronic acute medical condition','He suffers from chronic back pain.','그는 만성 요통을 앓고 있어요.','She was admitted for acute appendicitis.','그녀는 급성 충수염으로 입원했어요.','An acute injury heals within weeks, but chronic pain can last for years.','급성 부상은 몇 주 안에 낫지만, 만성 통증은 몇 년이나 지속될 수 있어요.','He''s lived with chronic pain for years.','그는 수년간 만성 통증과 함께 살아왔어요.','Acute stress can affect your sleep quickly.','급성 스트레스는 수면에 빠르게 영향을 줄 수 있어요.'),
('nuc_health_10','epidemic','pandemic',NULL,'유행병 (지역)','팬데믹 (전세계)',NULL,'epidemic은 특정 지역·집단에서 빠르게 퍼지는 것, pandemic은 전 세계적으로 퍼진 것이에요.','pandemic > epidemic > endemic(풍토병) 순으로 확산 범위가 달라요.','C1','health',1,10,'epidemic pandemic disease spread','There was a flu epidemic in the region.','그 지역에 독감 유행이 있었어요.','COVID-19 became a global pandemic.','코로나19는 세계적 대유행이 됐어요.','Health officials worked quickly to contain the measles epidemic.','보건 당국은 홍역 유행을 억제하기 위해 신속하게 움직였어요.','The flu epidemic peaked in mid-January.','독감 유행이 1월 중순에 정점을 찍었어요.','The pandemic changed how the whole world worked.','팬데믹은 전 세계가 일하는 방식을 바꿨어요.'),
('nuc_health_11','diagnosis','prognosis',NULL,'진단','예후',NULL,'diagnosis는 병명을 찾는 진단, prognosis는 병의 경과·결과를 예측하는 예후예요.','diagnosis는 현재(뭔 병?), prognosis는 미래(어떻게 될까?)를 가리켜요.','C1','health',2,11,'diagnosis prognosis medical outcome','The diagnosis was Type 2 diabetes.','진단 결과는 제2형 당뇨병이었어요.','The prognosis for early-stage cancer is good.','초기 암의 예후는 좋아요.','After several tests, the doctor finally reached a diagnosis.','여러 검사를 거친 뒤 의사가 마침내 진단을 내렸어요.','A clear diagnosis can take several tests.','명확한 진단을 받으려면 여러 검사가 필요할 수 있어요.','The prognosis improved after the new treatment.','새 치료 후 예후가 개선됐어요.'),
('nuc_health_12','placebo','nocebo',NULL,'위약 효과 (긍정)','노시보 효과 (부정)',NULL,'placebo effect는 가짜 약을 진짜로 믿어 증상이 나아지는 것, nocebo는 반대로 나빠지는 것이에요.','placebo는 긍정적 심리 효과, nocebo는 부정적 심리 효과예요.','C2','health',1,12,'placebo nocebo psychology medicine','The placebo reduced pain in half the patients.','위약이 환자 절반의 통증을 줄여 주었어요.','The nocebo effect caused side effects even with sugar pills.','노시보 효과 때문에 가짜 약인데도 부작용이 나타났어요.','In the trial, the placebo group reported feeling better too.','그 임상시험에서 위약을 받은 그룹도 호전을 느꼈다고 보고했어요.','The placebo effect can be surprisingly strong in pain studies.','위약 효과는 통증 연구에서 놀랍게 강력할 수 있어요.','The nocebo effect explains how negative expectations cause real symptoms.','노시보 효과는 부정적 기대가 실제 증상을 일으키는 방식을 설명해요.'),
('nuc_health_13','rehabilitation','recovery',NULL,'재활','회복',NULL,'recovery는 건강이 돌아오는 과정 전반, rehabilitation은 기능 회복을 위한 체계적 프로그램이에요.','rehabilitation(재활)은 물리치료·전문 프로그램, recovery(회복)는 더 넓은 개념이에요.','C2','health',2,13,'rehabilitation recovery therapy physical','The athlete''s rehabilitation took six months.','그 선수의 재활은 6개월이 걸렸어요.','She made a full recovery after surgery.','그녀는 수술 후 완전히 회복했어요.','Recovery from the surgery was quick, but full rehabilitation of his knee took months of therapy.','수술 후 회복은 빨랐지만, 무릎을 완전히 재활하는 데는 몇 달간의 치료가 필요했어요.','Her rehabilitation included daily physical therapy.','그녀의 재활은 매일 물리치료를 포함했어요.','His recovery surprised even his doctors.','그의 회복은 의사들조차 놀라게 했어요.'),
('nuc_home_14','live','stay',NULL,'살다 (장기 거주)','머물다 (임시)',NULL,'live는 장기 거주(집), stay는 임시 체류(호텔·친구 집·여행).','live는 거주(영구·장기), stay는 머묾(임시). 호텔은 stay, 본인 집은 live.','A2','home',1,0,'home apartment travel hotel staying','I live in Seoul with my family.','저는 가족과 함께 서울에 살아요.','I''m staying at a hotel for the weekend.','저는 주말 동안 호텔에 묵고 있어요.','They''ve lived in the same apartment for over twenty years.','그들은 같은 아파트에서 20년 넘게 살아 왔어요.','I live in London but stay at my parents'' on holidays.','저는 런던에 살지만 휴가 때는 부모님 집에 머물러요.','She lives alone; he stays with her on weekends.','그녀는 혼자 살고, 그는 주말마다 그녀 집에 머물러요.'),
('nuc_home_15','big','large',NULL,'큰 (일상)','큰 (격식·면적)',NULL,'big과 large는 대부분 호환. big이 더 일상·구어체, large는 면적·격식 표현에 자주 쓰여요.','big은 일상, large는 측정·격식 (a large coffee, a large room). 가족·문제·차이는 보통 big.','A2','home',1,0,'big house spacious large room','That''s a big house!','집이 정말 크네요!','We need a large room for the event.','행사를 위해 큰 방이 필요해요.','Their new kitchen has a big island in the middle.','그들의 새 부엌에는 가운데에 큰 아일랜드 식탁이 있어요.','A big idea can require a large team.','큰 아이디어는 큰 팀이 필요할 수 있어요.','She has a big smile and a large suitcase.','그녀는 활짝 웃는 얼굴과 큰 가방을 가지고 있어요.'),
('nuc_home_01','house','home',NULL,'집 (건물)','집 (생활 공간)',NULL,'house는 건물 자체, home은 가족과 생활하는 공간으로 감정적 의미가 있어요.','"Make yourself at home"은 편하게 있으라는 표현이에요.','B1','home',1,1,'house home family building','They bought a house in the suburbs.','그들은 교외에 집을 샀어요.','I feel most relaxed at home.','저는 집에 있을 때 가장 편안해요.','It''s a lovely house on paper, but it never quite felt like home to us.','서류상으로는 멋진 집이지만, 우리에게는 결코 집처럼 느껴지지 않았어요.','They bought a beautiful old house by the lake.','그들은 호숫가의 아름다운 오래된 집을 샀어요.','No matter where I go, I always feel best at home.','어디를 가든 저는 항상 집에서 가장 편안하게 느껴져요.'),
('nuc_home_02','furniture','appliance',NULL,'가구','가전제품',NULL,'furniture는 소파·테이블 같은 가구, appliance는 냉장고·세탁기 같은 가전제품이에요.','furniture는 이동 가능한 가구, appliance는 전기를 사용하는 가전이에요.','B1','home',2,2,'furniture appliance interior home','We need to buy new furniture for the living room.','거실에 놓을 새 가구를 사야 해요.','The apartment comes with all major appliances.','그 아파트에는 주요 가전제품이 모두 갖춰져 있어요.','The flat already had the furniture we needed, but we still had to buy our own appliances.','그 집에는 우리가 필요한 가구는 이미 있었지만, 가전제품은 직접 사야 했어요.','They picked out cozy furniture for the new flat.','그들은 새 아파트를 위해 아늑한 가구를 골랐어요.','Modern appliances make daily chores much easier.','현대 가전제품이 일상 잡일을 훨씬 쉽게 만들어줘요.'),
('nuc_home_03','rent','lease',NULL,'임대하다 (단기)','임대하다 (계약)',NULL,'rent는 돈을 내고 사용하는 것 전반, lease는 계약서를 작성하는 더 공식적인 임대예요.','lease는 기간·조건이 명시된 계약, rent는 그 계약에 따라 돈을 내는 것이에요.','B1','home',1,3,'rent lease apartment contract','I rent a small apartment near the office.','저는 사무실 근처의 작은 아파트를 빌려요.','We signed a one-year lease.','우리는 1년 임대 계약에 서명했어요.','Before you sign the lease, read every clause carefully.','임대 계약서에 서명하기 전에, 모든 조항을 꼼꼼히 읽어 보세요.','She rents a small apartment downtown.','그녀는 시내에 작은 아파트를 임대해요.','They signed a two-year lease last week.','그들은 지난주 2년 임대 계약을 체결했어요.'),
('nuc_home_04','tidy','clean',NULL,'정돈된','청결한',NULL,'tidy는 물건이 제자리에 있는 정돈된 상태, clean은 먼지나 오염이 없는 청결한 상태예요.','tidy하지만 dirty할 수 있고, messy하지만 clean할 수도 있어요.','B1','home',2,4,'tidy clean room organized','Please keep your room tidy.','방을 깔끔하게 유지해 주세요.','The kitchen needs a good clean.','주방을 한번 제대로 청소해야 해요.','The desk was tidy with everything in its place, yet the keyboard wasn''t very clean.','책상은 모든 게 제자리에 있어 깔끔했지만, 키보드는 그다지 깨끗하지 않았어요.','My daughter''s room is always tidy and welcoming.','제 딸의 방은 항상 정돈되어 있고 따뜻해요.','The kitchen needs a deep clean after the party.','파티 후 주방은 대청소가 필요해요.'),
('nuc_home_06','neighbor','neighborhood',NULL,'이웃 (사람)','동네 (장소)',NULL,'neighbor는 근처에 사는 사람, neighborhood는 동네나 지역 자체를 가리켜요.','neighbor는 사람, neighborhood는 장소예요. 혼동하지 않게 주의해요.','B1','home',2,6,'neighbor neighborhood community area','My neighbor always says hello.','제 이웃은 항상 인사를 건네요.','It''s a quiet neighborhood with good schools.','좋은 학교들이 있는 조용한 동네예요.','My new neighbor invited me over for dinner last night.','새 이웃이 어젯밤에 저를 저녁 식사에 초대했어요.','My neighbor brought over freshly baked cookies.','제 이웃이 갓 구운 쿠키를 가져다 줬어요.','Our neighborhood has changed a lot in the last decade.','저희 동네는 지난 10년간 많이 변했어요.'),
('nuc_home_05','repair','renovate',NULL,'수리하다','개조·리모델링하다',NULL,'repair는 고장난 것을 고치는 것, renovate는 공간을 새롭게 꾸미거나 개조하는 것이에요.','repair는 기능 복구, renovate는 미적·구조적 업그레이드예요.','B2','home',1,5,'repair renovate home improvement','The landlord repaired the leaking pipe.','집주인이 새는 파이프를 수리했어요.','They renovated the kitchen completely.','그들은 부엌을 완전히 개조했어요.','We only meant to repair the bathroom, but ended up deciding to renovate the whole upstairs.','화장실만 수리하려고 했는데, 결국 위층 전체를 개조하기로 결정했어요.','We need to repair the leaky faucet this weekend.','이번 주말 새는 수도꼭지를 수리해야 해요.','They renovated the entire basement into a guest suite.','그들은 지하실 전체를 게스트 스위트룸으로 리모델링했어요.'),
('nuc_home_07','mortgage','loan',NULL,'주택 담보 대출','대출',NULL,'loan은 다목적 대출, mortgage는 특히 부동산을 담보로 하는 주택 대출이에요.','mortgage는 집을 담보로 잡힌 특수한 대출 형태예요.','B2','home',1,7,'mortgage loan bank property','They got a 30-year mortgage to buy the house.','그들은 집을 사려고 30년 만기 주택담보대출을 받았어요.','She took out a personal loan for the car.','그녀는 차를 사려고 개인 대출을 받았어요.','They took out a mortgage for the apartment and a separate loan to furnish it.','그들은 아파트를 위해 주택담보대출을 받고, 가구를 들이려고 별도의 대출을 받았어요.','They''re still paying off the mortgage on their first house.','그들은 첫 집의 주택 담보 대출을 아직 갚고 있어요.','She took out a small loan for her home renovation.','그녀는 집 리노베이션을 위해 작은 대출을 받았어요.'),
('nuc_home_08','cozy','cramped',NULL,'아늑한','비좁은',NULL,'cozy는 작지만 따뜻하고 편안한 느낌, cramped는 공간이 좁아 불편한 느낌이에요.','같은 작은 공간도 분위기에 따라 cozy 또는 cramped로 느껴질 수 있어요.','B2','home',2,8,'cozy cramped small space apartment','It''s a cozy little studio with warm lighting.','따뜻한 조명이 있는 아늑한 작은 원룸이에요.','The room felt cramped with five people inside.','다섯 명이 안에 있으니 방이 비좁게 느껴졌어요.','The cabin felt cozy with two of us, but downright cramped once the guests arrived.','그 오두막은 둘이 있을 땐 아늑했지만, 손님들이 오자 정말 비좁아졌어요.','It''s a cozy studio with great natural light.','자연 채광이 좋은 아늑한 스튜디오예요.','The apartment felt cramped with all the furniture.','모든 가구가 들어가니 아파트가 비좁게 느껴졌어요.'),
('nuc_home_09','landlord','tenant',NULL,'집주인','세입자',NULL,'landlord는 집을 빌려주는 주인, tenant는 집을 빌려 사는 사람이에요.','landlord-tenant 관계에서 양쪽의 의무를 알면 외국 생활이 편해요.','B2','home',1,9,'landlord tenant rent property','The landlord agreed to fix the heater.','집주인이 난방기를 고쳐 주기로 했어요.','The tenant paid rent on time every month.','세입자는 매달 제때 월세를 냈어요.','Our landlord raised the rent at the start of the year.','우리 집주인이 연초에 월세를 올렸어요.','My landlord responded quickly to the repair request.','저희 집주인은 수리 요청에 빠르게 응답했어요.','The tenant signed the lease and moved in the next day.','그 세입자는 계약서에 서명하고 다음 날 이사 들어왔어요.'),
('nuc_home_10','interior','exterior',NULL,'내부 / 인테리어','외부',NULL,'interior는 건물 내부와 인테리어, exterior는 건물 바깥 외관이에요.','interior design(실내 디자인) vs exterior renovation(외벽 공사)처럼 써요.','B2','home',2,10,'interior exterior design architecture','The interior designer changed the living room layout.','인테리어 디자이너가 거실 배치를 바꿨어요.','The exterior of the house needs repainting.','그 집의 외관은 다시 칠해야 해요.','They repainted the entire interior in soft neutral colors.','그들은 실내 전체를 부드러운 중간색으로 다시 칠했어요.','The interior is decorated in warm earth tones.','내부는 따뜻한 어스 톤으로 꾸며져 있어요.','The exterior could use a fresh coat of paint.','외부는 페인트 새로 칠하면 좋겠어요.'),
('nuc_home_11','utility','amenity',NULL,'공과금 / 유틸리티','편의시설',NULL,'utility는 전기·수도·가스 같은 공공서비스, amenity는 수영장·헬스장 등 편의시설이에요.','utilities included(관리비 포함), amenities(편의시설)는 부동산 광고에 자주 나와요.','C1','home',1,11,'utility amenity apartment building','Rent includes all utilities.','임대료에 모든 공과금이 포함되어 있어요.','The building has great amenities like a rooftop terrace.','이 건물에는 옥상 테라스 같은 좋은 편의 시설이 있어요.','The rent covers basic utilities like water and electricity, but the pool is a paid amenity.','임대료에는 수도와 전기 같은 기본 공과금이 포함되지만, 수영장은 별도 요금이 드는 편의 시설이에요.','Utilities and internet are included in the rent.','공과금과 인터넷은 임대료에 포함돼 있어요.','The building''s amenities include a small gym.','건물 편의시설로는 작은 헬스장이 있어요.'),
('nuc_home_12','vacant','vacant vs available',NULL,'비어 있는','이용 가능한',NULL,'vacant는 현재 아무도 살지 않아 비어 있는 상태, available은 임대·구매 가능한 상태예요.','부동산에서 vacant는 사실 묘사, available은 계약 가능 여부를 뜻해요.','C1','home',2,12,'vacant available property real estate','The apartment has been vacant for months.','그 아파트는 몇 달째 비어 있어요.','Is this unit still available?','이 세대는 아직 입주 가능한가요?','The flat is currently vacant, and the agent says it''s available from the first of the month.','그 집은 현재 비어 있고, 중개인 말로는 다음 달 1일부터 입주할 수 있다고 해요.','The third-floor flat has been vacant since spring.','3층 아파트는 봄부터 비어 있어요.','Is that two-bedroom unit still available for rent?','그 침실 두 개짜리 집은 아직 임대 가능한가요?'),
('nuc_home_13','dwelling','abode',NULL,'거처 (일반)','거처 (격식·문학)',NULL,'dwelling은 사람이 사는 공간의 공식·행정 용어, abode는 문학·격식 표현이에요.','"my humble abode"는 집을 겸손하게 부르는 관용구예요.','C2','home',1,13,'dwelling abode residence home','All dwellings in this area must meet safety codes.','이 지역의 모든 주거지는 안전 기준을 충족해야 해요.','Welcome to my humble abode.','누추한 제 집에 오신 걸 환영합니다.','The survey recorded every dwelling in the district, but the poet called the cottage her humble abode.','조사에서는 그 구역의 모든 주거지를 기록했지만, 시인은 그 오두막을 자신의 누추한 보금자리라고 불렀어요.','The new dwellings meet stricter safety standards.','새 거처들은 더 엄격한 안전 기준을 충족해요.','"Welcome to my humble abode," she said with a smile.','"제 누추한 거처에 오신 것을 환영해요," 그녀는 미소 지으며 말했어요.'),
('nuc_humanities_01','history','story',NULL,'역사','이야기',NULL,'history는 실제 과거 사실, story는 사실·허구 모두 가능한 이야기예요.','"History" 안에 "story"가 있지만 뜻은 달라요.','B1','humanities',1,1,'history story past narrative','Korean history spans over 5,000 years.','한국의 역사는 5,000년이 넘게 이어져요.','She told us a fascinating story about her childhood.','그녀는 자신의 어린 시절에 관한 흥미로운 이야기를 들려줬어요.','The museum exhibit traces the history of early human migration.','그 박물관 전시는 초기 인류 이주의 역사를 추적해요.','European history has shaped modern political thought.','유럽 역사는 현대 정치 사상을 형성해 왔어요.','She wrote a beautiful short story about her hometown.','그녀는 고향에 관한 아름다운 단편 소설을 썼어요.'),
('nuc_humanities_02','myth','legend',NULL,'신화','전설',NULL,'myth는 신·우주 창조 등 초자연적 이야기, legend는 역사적 인물·사건을 바탕으로 한 전설이에요.','myth는 신화·종교적, legend는 역사적 인물을 바탕으로 해요.','B1','humanities',2,2,'myth legend folklore story','Greek myths explain the origin of the world.','그리스 신화는 세상의 기원을 설명해요.','The legend of Robin Hood is beloved in England.','로빈 후드 전설은 영국에서 많은 사랑을 받아요.','Ancient myths often tried to explain natural disasters.','고대 신화는 종종 자연재해를 설명하려 했어요.','Norse myths influenced many modern fantasy stories.','북유럽 신화는 많은 현대 판타지 이야기에 영향을 줬어요.','The legend of King Arthur is told in many forms.','아서왕 전설은 여러 형태로 전해져요.'),
('nuc_humanities_03','art','craft',NULL,'예술','공예 / 기술',NULL,'art는 표현·미적 창의성, craft는 기술·숙련도로 만드는 공예나 기능이에요.','art는 창의·감성, craft는 기술·손기술을 강조해요.','B1','humanities',1,3,'art craft creative skills','Her paintings are considered fine art.','그녀의 그림들은 순수 예술로 여겨져요.','He learned the craft of pottery from his grandmother.','그는 할머니에게서 도예 기술을 배웠어요.','Calligraphy is a craft that takes years of patient practice to master.','서예는 숙달하기까지 수년간의 끈기 있는 연습이 필요한 기예예요.','Modern art often challenges what we consider beautiful.','현대 미술은 종종 우리가 아름답다고 여기는 것에 도전해요.','Pottery is an ancient craft with regional variations.','도자기는 지역적 변형이 있는 고대 공예예요.'),
('nuc_humanities_14','novel','fiction',NULL,'소설 (책 한 권)','허구·픽션 (장르 전체)',NULL,'novel은 소설책 한 권 (긴 산문 픽션), fiction은 허구·픽션 장르 전체 (소설, 단편, 동화 포함).','novel은 한 작품 (책 한 권), fiction은 장르. "fiction"은 셀 수 없는 명사, "novel"은 셀 수 있어요.','B1','humanities',1,0,'novel book fiction library reading','I read three novels this summer.','저는 이번 여름에 소설 세 권을 읽었어요.','I prefer fiction over non-fiction.','저는 논픽션보다 소설을 더 좋아해요.','Her debut novel is set in nineteenth-century London.','그녀의 데뷔 소설은 19세기 런던을 배경으로 해요.','A novel is a type of fiction.','소설은 픽션의 한 종류예요.','She writes novels; he reads science fiction.','그녀는 소설을 쓰고, 그는 SF 픽션을 읽어요.'),
('nuc_humanities_04','philosophy','ideology',NULL,'철학','이데올로기',NULL,'philosophy는 진리·존재를 탐구하는 학문, ideology는 정치·사회적 믿음 체계예요.','philosophy는 학문적 탐구, ideology는 실천적 믿음 체계예요.','B2','humanities',1,4,'philosophy ideology belief system','Socrates shaped Western philosophy.','소크라테스는 서양 철학을 형성했어요.','The party''s ideology is rooted in equality.','그 정당의 이념은 평등에 뿌리를 두고 있어요.','Greek philosophy still influences how we think about justice today.','그리스 철학은 오늘날에도 우리가 정의를 사고하는 방식에 영향을 미쳐요.','Eastern philosophy emphasizes harmony with nature.','동양 철학은 자연과의 조화를 강조해요.','A clear ideology drives the party''s policies.','명확한 이데올로기가 그 정당의 정책을 이끌어요.'),
('nuc_humanities_05','ethics','morality',NULL,'윤리학 / 윤리','도덕',NULL,'ethics는 철학적·직업적 기준의 윤리, morality는 옳고 그름에 대한 개인 또는 집단의 도덕이에요.','ethics는 체계적 원칙, morality는 개인적 도덕 감각이에요.','B2','humanities',2,5,'ethics morality right wrong philosophy','Medical ethics guide doctors'' decisions.','의료 윤리는 의사들의 결정을 이끌어요.','Our morality is shaped by culture and upbringing.','우리의 도덕성은 문화와 양육 환경에 의해 형성돼요.','Research ethics require scientists to protect their participants.','연구 윤리는 과학자들이 연구 참가자들을 보호하도록 요구해요.','Business ethics is a required course in most MBA programs.','경영 윤리는 대부분의 MBA 프로그램에서 필수 과목이에요.','Our sense of morality is partly shaped by family values.','우리의 도덕 감각은 부분적으로 가족 가치관으로 형성돼요.'),
('nuc_humanities_06','interpret','analyze',NULL,'해석하다','분석하다',NULL,'interpret는 의미를 풀이하는 것, analyze는 구성 요소를 나눠 자세히 살피는 것이에요.','interpret는 의미 부여, analyze는 구조·요소 분해를 강조해요.','B2','humanities',1,6,'interpret analyze literature humanities','How do you interpret this poem?','이 시를 어떻게 해석하시나요?','Let''s analyze the author''s use of symbolism.','작가의 상징 사용을 분석해 봅시다.','Readers often interpret the ending in completely opposite ways.','독자들은 종종 그 결말을 완전히 정반대로 해석해요.','Critics interpret the same novel in very different ways.','비평가들은 같은 소설을 매우 다른 방식으로 해석해요.','Students analyze the poem''s structure and imagery.','학생들은 시의 구조와 이미지를 분석해요.'),
('nuc_humanities_07','context','subtext',NULL,'맥락','함축된 의미 / 숨은 의미',NULL,'context는 배경·상황, subtext는 직접 표현되지 않은 숨겨진 의미나 감정이에요.','context는 배경 정보, subtext는 표면 아래 숨겨진 메시지예요.','B2','humanities',2,7,'context subtext meaning literature','Read the poem in its historical context.','그 시를 역사적 맥락 속에서 읽어 보세요.','The subtext of the novel is racial inequality.','그 소설의 숨은 의미는 인종 불평등이에요.','You can''t fully grasp the painting without knowing its social context.','그 그림은 사회적 맥락을 모르고는 온전히 이해할 수 없어요.','Knowing the historical context changes how we read the speech.','역사적 맥락을 아는 것이 우리가 그 연설을 읽는 방식을 바꿔요.','The subtext of the conversation revealed deep tension.','대화의 함의가 깊은 긴장을 드러냈어요.'),
('nuc_humanities_10','subjective','objective',NULL,'주관적인','객관적인',NULL,'subjective는 개인의 감정·관점에 기반한 것, objective는 사실·증거에 기반한 것이에요.','에세이·논문에서 objective를 유지하는 것이 학문적 글쓰기의 기본이에요.','B2','humanities',1,10,'subjective objective analysis writing','Art criticism is largely subjective.','미술 비평은 대체로 주관적이에요.','The report should be objective and fact-based.','그 보고서는 객관적이고 사실에 기반해야 해요.','Taste in music is deeply subjective and varies from person to person.','음악 취향은 매우 주관적이어서 사람마다 달라요.','My review of the book is necessarily subjective.','제 책 리뷰는 필연적으로 주관적이에요.','Scientific research aims for an objective view of nature.','과학 연구는 자연에 대한 객관적인 시각을 목표로 해요.'),
('nuc_humanities_08','allegory','metaphor',NULL,'우화 / 알레고리','은유',NULL,'metaphor는 표현 장치, allegory는 전체 이야기가 다른 의미를 상징하는 더 큰 형식이에요.','allegory는 작품 전체, metaphor는 문장·표현 단위의 비유예요.','C1','humanities',1,8,'allegory metaphor literature symbolism','"Animal Farm" is an allegory about Stalinism.','"동물 농장"은 스탈린주의에 관한 우화예요.','"Life is a journey" is a metaphor.','"인생은 여정이다"는 은유예요.','The fable works as an allegory for greed and its consequences.','그 우화는 탐욕과 그 결과에 대한 알레고리로 작동해요.','"The Lord of the Rings" can be read as an allegory of war.','"반지의 제왕"은 전쟁의 알레고리로 읽힐 수 있어요.','"Time is a river" is a beautiful metaphor.','"시간은 강이다"는 아름다운 은유예요.'),
('nuc_humanities_09','empiricism','rationalism',NULL,'경험론','이성론',NULL,'empiricism은 경험·감각이 지식의 근거, rationalism은 이성·논리가 지식의 근거라는 철학이에요.','empiricism(경험 우선) vs rationalism(이성 우선)은 인식론의 핵심 대립이에요.','C1','humanities',2,9,'empiricism rationalism philosophy knowledge','Locke and Hume are key figures in empiricism.','로크와 흄은 경험론의 핵심 인물이에요.','Descartes is the father of modern rationalism.','데카르트는 근대 합리론의 아버지예요.','Empiricism holds that knowledge comes mainly from observation.','경험론은 지식이 주로 관찰에서 나온다고 봐요.','Empiricism shaped much of modern scientific thinking.','경험론은 현대 과학적 사고의 많은 부분을 형성했어요.','Rationalism argues that reason alone can lead to truth.','이성론은 이성만으로 진리에 이를 수 있다고 주장해요.'),
('nuc_humanities_11','postmodern','modern',NULL,'포스트모던','모더니즘',NULL,'modern은 전통을 거부하고 혁신을 추구한 20세기 예술 사조, postmodern은 그 이후 다원성·해체를 강조해요.','modern art(모더니즘, ~1970s) → postmodern(1970s~)으로 사조가 이어져요.','C1','humanities',2,11,'postmodern modern art literature','Picasso is a key figure in modern art.','피카소는 현대 미술의 핵심 인물이에요.','Postmodern literature often breaks narrative conventions.','포스트모던 문학은 종종 서사의 관습을 깨요.','Modern architecture favored clean lines and rejected heavy ornament.','현대 건축은 깔끔한 선을 선호하고 과도한 장식을 거부했어요.','Modern art broke from realistic representation.','모더니즘 미술은 사실적 표현에서 벗어났어요.','Postmodern literature often plays with traditional storytelling.','포스트모던 문학은 종종 전통적인 스토리텔링을 가지고 놀아요.'),
('nuc_humanities_12','hermeneutics','semiotics',NULL,'해석학','기호학',NULL,'hermeneutics는 텍스트·의미를 해석하는 방법론, semiotics는 기호·언어·이미지의 의미 체계를 연구해요.','둘 다 의미 해석에 관한 학문이지만 접근 방식이 달라요.','C2','humanities',1,12,'hermeneutics semiotics meaning interpretation','Hermeneutics is central to biblical interpretation.','해석학은 성경 해석에서 핵심적이에요.','Semiotics examines how signs produce meaning.','기호학은 기호가 어떻게 의미를 만들어 내는지 살펴봐요.','The seminar applied hermeneutics to a medieval manuscript.','그 세미나는 중세 필사본에 해석학을 적용했어요.','Hermeneutics gives us tools to interpret ancient texts carefully.','해석학은 우리에게 고대 텍스트를 신중하게 해석할 도구를 줘요.','Semiotics is useful for analyzing advertising and design.','기호학은 광고와 디자인을 분석하는 데 유용해요.'),
('nuc_humanities_13','phenomenology','existentialism',NULL,'현상학','실존주의',NULL,'phenomenology는 의식 경험의 구조를 탐구, existentialism은 개인의 자유·책임·존재 의미를 탐구해요.','둘 다 20세기 철학의 핵심 사조로 인문학 글쓰기에서 자주 인용돼요.','C2','humanities',2,13,'phenomenology existentialism philosophy','Husserl founded modern phenomenology.','후설은 현대 현상학을 창시했어요.','Sartre is a central figure in existentialism.','사르트르는 실존주의의 중심 인물이에요.','Phenomenology examines how the world appears to our consciousness.','현상학은 세계가 우리의 의식에 어떻게 나타나는지를 탐구해요.','Phenomenology asks us to focus on lived experience.','현상학은 우리에게 살아 있는 경험에 집중하라고 해요.','Existentialism teaches that we create our own meaning.','실존주의는 우리가 스스로 의미를 만든다고 가르쳐요.'),
('nuc_media_14','post','publish',NULL,'(SNS에) 올리다','출판·발행하다 (정식)',NULL,'post는 SNS·블로그·게시판에 올리는 비공식 행위, publish는 책·기사·논문 등 정식 출판.','post는 캐주얼(SNS·게시판), publish는 공식·정식(책·논문·신문). 출판물은 publish.','A2','media',1,0,'social media post publishing book online','I posted a photo on Instagram.','저는 인스타그램에 사진을 올렸어요.','She published her first novel last year.','그녀는 작년에 첫 소설을 출간했어요.','He posts a new recipe video every Sunday evening.','그는 매주 일요일 저녁에 새 요리 영상을 올려요.','I post tweets daily, but I dream of publishing a book someday.','매일 트윗을 올리지만, 언젠가 책을 출간하는 게 꿈이에요.','Bloggers post articles; journalists publish stories.','블로거는 글을 올리고, 기자는 기사를 발행해요.'),
('nuc_media_01','watch','see',NULL,'(의도적으로) 보다','보다 (우연·경험)',NULL,'watch는 집중해서 의도적으로 시청하는 것, see는 우연히 보거나 경험한 것을 뜻해요.','"watch TV" / "see a movie"가 일반적인 사용 패턴이에요.','B1','media',1,1,'watch see screen media film','I watched the documentary last night.','저는 어젯밤에 그 다큐멘터리를 봤어요.','Have you seen the new Marvel movie?','새로 나온 마블 영화 보셨어요?','We watch the news together every evening after dinner.','우리는 매일 저녁 식사 후에 함께 뉴스를 봐요.','I watched two episodes before bed last night.','어젯밤 자기 전에 두 화를 봤어요.','Did you see that incredible play in the game?','경기에서 그 놀라운 플레이 봤어요?'),
('nuc_media_02','news','report',NULL,'뉴스','보도',NULL,'news는 새로운 정보나 사건 자체, report는 그것을 조사하고 전달하는 행위나 문서예요.','news는 내용, report는 형식과 행위를 가리켜요.','B1','media',2,2,'news report media journalism','Did you hear the news about the election?','선거에 관한 소식 들으셨어요?','The reporter filed a report from the scene.','기자가 현장에서 보도 기사를 송고했어요.','The breaking news interrupted our favorite show.','속보가 저희가 좋아하는 프로그램을 끊고 나왔어요.','I read the news every morning over coffee.','저는 매일 아침 커피 마시며 뉴스를 읽어요.','She wrote a detailed report on the local elections.','그녀는 지방 선거에 대한 자세한 보도를 썼어요.'),
('nuc_media_03','channel','platform',NULL,'채널 (TV)','플랫폼 (디지털)',NULL,'channel은 TV 방송 채널, platform은 YouTube·Netflix 같은 디지털 서비스 플랫폼이에요.','channel은 전통 방송, platform은 스트리밍·소셜 미디어에 써요.','B1','media',1,3,'channel platform streaming digital','Switch to channel 7 for the game.','경기를 보려면 7번 채널로 돌리세요.','Netflix is a popular streaming platform.','넷플릭스는 인기 있는 스트리밍 플랫폼이에요.','This channel only broadcasts documentaries in the evening.','이 채널은 저녁에 다큐멘터리만 방송해요.','I never watch live TV — I just stream channels online.','저는 실시간 TV를 보지 않고 — 온라인으로 채널을 스트리밍해요.','YouTube is the most popular video platform in many countries.','유튜브는 많은 나라에서 가장 인기 있는 동영상 플랫폼이에요.'),
('nuc_media_04','subscribe','follow',NULL,'구독하다','팔로우하다',NULL,'subscribe는 유료 또는 이메일 구독, follow는 소셜 미디어에서 계정을 팔로우하는 것이에요.','subscribe는 YouTube·뉴스레터, follow는 인스타·트위터에서 써요.','B1','media',2,4,'subscribe follow social media digital','Subscribe to our YouTube channel.','저희 유튜브 채널을 구독해 주세요.','Follow us on Instagram for updates.','최신 소식을 받으려면 인스타그램에서 저희를 팔로우하세요.','I decided to subscribe to a streaming service for the winter.','저는 겨울 동안 스트리밍 서비스를 구독하기로 했어요.','Subscribe to the newsletter to get weekly updates.','주간 업데이트를 받으려면 뉴스레터를 구독하세요.','Thousands of people follow her cooking account.','수천 명이 그녀의 요리 계정을 팔로우해요.'),
('nuc_media_15','share','distribute',NULL,'공유하다 (SNS·비공식)','배포하다 (공식·대규모)',NULL,'share는 친구·SNS에서 공유하는 비공식적인 행위, distribute는 공식·대규모로 배포하는 행위.','share는 개인 단위, distribute는 공식·대규모 단위. 전단지·상품은 distribute, 링크·소식은 share.','B1','media',1,0,'sharing distributing online viral link','I shared the article with my friends.','저는 그 기사를 친구들과 공유했어요.','The company distributes products worldwide.','그 회사는 전 세계에 제품을 유통해요.','Feel free to share this post with anyone who''s interested.','관심 있는 누구에게나 이 게시물을 자유롭게 공유하세요.','She shared the post; the news outlet distributed it widely.','그녀는 그 게시물을 공유했고, 그 매체가 이를 광범위하게 배포했어요.','Share with one; distribute to many.','한 명과 공유하고, 다수에게 배포하세요.'),
('nuc_media_05','advertisement','commercial',NULL,'광고 (넓은 의미)','광고 (TV·라디오)',NULL,'advertisement는 모든 매체의 광고, commercial은 특히 TV·라디오 광고를 가리켜요.','ad/advertisement는 모든 미디어, commercial은 방송 광고를 가리켜요.','B2','media',1,5,'advertisement commercial advertising TV','The advertisement appeared in the newspaper.','그 광고가 신문에 실렸어요.','The commercial aired during the Super Bowl.','그 광고는 슈퍼볼 중에 방송되었어요.','They placed an advertisement for the new product online.','그들은 신제품 광고를 온라인에 게재했어요.','I saw the advertisement on the side of a bus.','저는 버스 옆면의 광고를 봤어요.','A 30-second commercial during the playoffs is expensive.','플레이오프 중 30초 광고는 비싸요.'),
('nuc_media_06','live','recorded',NULL,'생방송','녹화 방송',NULL,'live는 실시간으로 방송되는 것, recorded는 미리 촬영해 방영하는 것이에요.','live broadcast(생방송)에서 실수는 그대로 나가요.','B2','media',2,6,'live recorded broadcast streaming','The concert was broadcast live.','그 콘서트는 생중계되었어요.','The interview was recorded last week.','그 인터뷰는 지난주에 녹화되었어요.','Watching the match live is far more exciting than the highlights.','경기를 생중계로 보는 게 하이라이트보다 훨씬 더 재미있어요.','The interview was streamed live to millions of viewers.','인터뷰는 수백만 명의 시청자에게 생방송으로 스트리밍됐어요.','The recorded podcast goes out every Tuesday morning.','녹화된 팟캐스트는 매주 화요일 아침에 나가요.'),
('nuc_media_07','viral','trending',NULL,'바이럴 (빠른 전파)','트렌딩 (현재 화제)',NULL,'viral은 폭발적으로 공유·전파되는 것, trending은 현재 인기 있는 화제를 뜻해요.','viral은 공유 속도, trending은 현재 인기 순위를 강조해요.','B2','media',1,7,'viral trending social media internet','The video went viral overnight.','그 영상은 하룻밤 사이에 입소문이 났어요.','That hashtag is trending on Twitter.','그 해시태그가 트위터에서 인기를 끌고 있어요.','A short clip from the concert went viral within hours.','콘서트의 짧은 영상이 몇 시간 만에 입소문이 났어요.','The dance went viral on multiple platforms in two days.','그 춤은 이틀 만에 여러 플랫폼에서 입소문이 났어요.','That song is trending in five different countries right now.','그 노래는 지금 다섯 개 다른 나라에서 트렌딩이에요.'),
('nuc_media_08','bias','perspective',NULL,'편향','관점',NULL,'bias는 한쪽으로 치우친 편견, perspective는 특정 입장에서 바라보는 시각이에요.','bias는 왜곡된 시각, perspective는 다양한 시각 중 하나예요.','B2','media',2,8,'bias perspective journalism media','The article showed a clear political bias.','그 기사는 명백한 정치적 편향을 보였어요.','The documentary offers multiple perspectives.','그 다큐멘터리는 다양한 관점을 제시해요.','It''s hard to write about politics without revealing your own bias.','자신의 편향을 드러내지 않고 정치에 대해 쓰기는 어려워요.','Every news source has some kind of bias.','모든 뉴스 출처에는 어떤 종류의 편향이 있어요.','Hearing different perspectives helps you understand the issue.','다양한 관점을 듣는 것이 문제를 이해하는 데 도움이 돼요.'),
('nuc_media_09','censorship','regulation',NULL,'검열','규제',NULL,'censorship은 특정 콘텐츠를 억압·삭제하는 것, regulation은 법적 기준으로 통제하는 것이에요.','censorship은 내용 억압, regulation은 공정한 기준 적용이에요.','C1','media',1,9,'censorship regulation media freedom','The film was banned due to censorship.','그 영화는 검열 때문에 상영이 금지되었어요.','Media regulation ensures fair broadcasting.','미디어 규제는 공정한 방송을 보장해요.','Strict censorship prevented the journalists from reporting the truth.','엄격한 검열 때문에 기자들이 진실을 보도할 수 없었어요.','Censorship of social media is a sensitive topic.','소셜 미디어 검열은 민감한 주제예요.','Better regulation could protect users without limiting speech.','더 나은 규제는 발언을 제한하지 않으면서 사용자를 보호할 수 있어요.'),
('nuc_media_10','satire','parody',NULL,'풍자','패러디',NULL,'satire는 사회·정치를 비판하는 것, parody는 특정 작품을 흉내 내어 웃음을 주는 것이에요.','satire는 비판 목적, parody는 흉내 내기·코미디 목적이에요.','C1','media',2,10,'satire parody comedy humor','The show is a political satire.','그 프로그램은 정치 풍자예요.','The video was a parody of a famous music video.','그 영상은 유명한 뮤직비디오의 패러디였어요.','The novel uses satire to mock the greed of the wealthy.','그 소설은 풍자를 사용해 부유층의 탐욕을 조롱해요.','The late-night show is famous for political satire.','그 심야 쇼는 정치 풍자로 유명해요.','Their parody of the music video got a million views.','그들의 뮤직비디오 패러디가 백만 뷰를 기록했어요.'),
('nuc_media_11','narrative','discourse',NULL,'서사 / 이야기','담론',NULL,'narrative는 이야기 구조와 전달 방식, discourse는 사회적 대화와 논의 전반이에요.','narrative는 스토리텔링, discourse는 사회적 토론·논의예요.','C1','media',1,11,'narrative discourse media society','The media shaped the public narrative about the event.','언론이 그 사건에 대한 대중의 이야기를 형성했어요.','Public discourse on climate change has intensified.','기후 변화에 대한 공적 담론이 격화되었어요.','Historians often question the dominant narrative of past wars.','역사가들은 종종 과거 전쟁에 대한 지배적인 서사에 의문을 제기해요.','The film follows a clear three-act narrative.','그 영화는 명확한 3막 서사를 따라가요.','Public discourse on AI is growing more nuanced.','AI에 대한 공개 담론이 점점 더 섬세해지고 있어요.'),
('nuc_media_12','propaganda','disinformation',NULL,'선전 (의도적 편향)','허위 정보 (의도적 거짓)',NULL,'propaganda는 특정 이념을 위해 편향된 정보, disinformation은 의도적으로 퍼뜨리는 거짓 정보예요.','misinformation(비의도적 오정보) vs disinformation(의도적 허위 정보)도 구분해요.','C2','media',1,12,'propaganda disinformation media truth','The regime used propaganda to control public opinion.','그 정권은 여론을 통제하기 위해 선전을 이용했어요.','Disinformation spread rapidly during the election.','선거 기간에 허위 정보가 빠르게 퍼졌어요.','State-run channels broadcast nothing but propaganda.','국영 채널들은 오직 선전만 방송했어요.','Wartime propaganda often relies on simple visual symbols.','전시 선전은 종종 단순한 시각 상징에 의존해요.','Disinformation can spread faster than the truth on social media.','허위 정보는 소셜 미디어에서 진실보다 빠르게 퍼질 수 있어요.'),
('nuc_media_13','semiotics','iconography',NULL,'기호학','도상학',NULL,'semiotics는 기호·언어·이미지의 의미를 연구하는 학문, iconography는 이미지·상징의 의미 체계예요.','미디어 분석에서 semiotics와 iconography를 알면 이미지 의미를 깊이 읽을 수 있어요.','C2','media',2,13,'semiotics iconography symbol media','Semiotics studies how signs create meaning in media.','기호학은 미디어에서 기호가 어떻게 의미를 만드는지 연구해요.','The iconography of the film draws on religious symbols.','그 영화의 도상은 종교적 상징을 활용해요.','Advertisers rely on semiotics to make brands feel desirable.','광고주들은 브랜드를 매력적으로 보이게 하려고 기호학에 의존해요.','Semiotics helps us understand why certain symbols feel powerful.','기호학은 특정 상징이 왜 강력하게 느껴지는지 이해하는 데 도움이 돼요.','Religious iconography shapes much of Western art history.','종교 도상학이 서양 미술사의 많은 부분을 형성해요.'),
('nuc_negotiation_01','offer','propose',NULL,'제안하다 (구체)','제안하다 (공식)',NULL,'offer는 구체적인 조건을 제시하는 것, propose는 더 공식적으로 아이디어나 조건을 제안하는 것이에요.','offer는 즉각적·구체적, propose는 검토를 요청하는 공식 제안이에요.','B1','negotiation',1,1,'offer propose negotiation business','I''ll offer you 10% off.','10퍼센트 할인을 제안해 드릴게요.','We propose a three-month trial period.','우리는 3개월 시험 기간을 제안해요.','They offered to cover the shipping costs to close the sale.','그들은 거래를 성사시키려고 배송비를 부담하겠다고 제안했어요.','They offered a generous discount to close the deal.','그들은 거래를 성사시키기 위해 넉넉한 할인을 제안했어요.','I propose we meet again next Tuesday to finalize the terms.','조건을 마무리하기 위해 다음 주 화요일에 다시 만날 것을 제안해요.'),
('nuc_negotiation_02','accept','agree',NULL,'수락하다','동의하다',NULL,'accept는 제안·조건을 받아들이는 것, agree는 의견이나 제안에 동의하는 것이에요.','accept는 제안을 받아들이는 행위, agree는 합의에 이르는 과정이에요.','B1','negotiation',2,2,'accept agree deal negotiation','She accepted the job offer.','그녀는 그 일자리 제안을 수락했어요.','We agreed on the final terms.','우리는 최종 조건에 합의했어요.','After reviewing the terms, the company accepted the supplier''s proposal.','조건을 검토한 후 그 회사는 공급업체의 제안을 수락했어요.','She accepted the offer after a day of thought.','그녀는 하루의 고민 끝에 제안을 수락했어요.','We finally agreed on a delivery timeline.','우리는 마침내 배송 일정에 합의했어요.'),
('nuc_negotiation_03','demand','request',NULL,'요구하다','요청하다',NULL,'demand는 강하게 요구하는 것, request는 정중하게 부탁하는 것이에요.','demand는 강압적, request는 협력적 뉘앙스예요. 비즈니스에서는 request가 좋아요.','B1','negotiation',1,3,'demand request negotiation business','Workers demanded higher wages.','노동자들은 임금 인상을 요구했어요.','We politely requested a deadline extension.','저희는 정중하게 마감 연장을 요청했어요.','The customers demanded a full refund for the faulty product.','고객들은 결함 있는 제품에 대해 전액 환불을 요구했어요.','They demanded a clear explanation for the delay.','그들은 지연에 대한 명확한 설명을 요구했어요.','She politely requested a copy of the contract.','그녀는 정중하게 계약서 사본을 요청했어요.'),
('nuc_negotiation_15','might','may',NULL,'~할지도 (덜 확실, 일상)','~할 수도 (격식, 허락)',NULL,'might는 더 덜 확실한 가능성, may는 약간 더 확실 또는 허락의 의미.','might는 가능성이 약한 추측, may는 격식·허락 ("May I?" = 허락 요청). 일상에서는 might가 더 자연스러워요.','B1','negotiation',1,0,'maybe possibility uncertainty modal hesitant','It might rain later.','이따가 비가 올지도 몰라요.','It may rain later.','이따가 비가 올 수도 있어요.','We might need to reschedule if the client is unavailable.','고객이 시간이 안 되면 일정을 다시 잡아야 할 수도 있어요.','You might be right, but you may need more evidence.','당신이 맞을지도 모르지만, 더 많은 증거가 필요할 수도 있어요.','I might come tomorrow; may I come tomorrow?','내일 갈지도 몰라요; 내일 가도 될까요?'),
('nuc_negotiation_16','could','might',NULL,'~할 수도 있다 (능력+가능)','~할지도 모른다 (순수 가능)',NULL,'could는 능력·가능성 모두, might는 순수 가능성 (might가 더 약한 추측).','could는 능력+가능, might는 순수 가능(약한 추측). past form인 could는 was/were able to 의미도 있음.','B1','negotiation',1,0,'possibility chance maybe could might modal','He could be home by now.','그는 지금쯤 집에 있을 수도 있어요.','He might be home by now.','그는 지금쯤 집에 있을지도 몰라요.','With more funding, the project could finish ahead of schedule.','자금이 더 있으면 그 프로젝트는 예정보다 일찍 끝날 수도 있어요.','It could rain; it might rain — both express possibility.','비가 올 수도 있어요; 비가 올지도 모르고요 — 둘 다 가능성 표현.','You could win, but you might lose.','이길 수도 있지만, 질지도 몰라요.'),
('nuc_negotiation_04','deadline','timeline',NULL,'마감 기한','일정 / 타임라인',NULL,'deadline은 절대 넘지 말아야 할 마감, timeline은 각 단계의 일정 흐름이에요.','deadline은 최종 기한, timeline은 프로세스 전체 일정이에요.','B2','negotiation',2,4,'deadline timeline project schedule','We must meet the deadline or face penalties.','우리는 마감 기한을 지켜야 해요. 그러지 않으면 위약금을 물게 돼요.','Let''s review the project timeline together.','프로젝트 일정을 함께 검토해 봐요.','Missing the deadline could cost us the entire contract.','마감 기한을 놓치면 계약 전체를 잃을 수도 있어요.','The deadline for offers is this Friday.','제안 마감은 이번 금요일이에요.','Let''s map out the project timeline together.','함께 프로젝트 일정을 그려봐요.'),
('nuc_negotiation_05','concession','trade-off',NULL,'양보','절충',NULL,'concession은 한쪽이 양보하는 것, trade-off는 양쪽이 무언가를 주고받는 교환이에요.','concession은 한쪽이 포기, trade-off는 양쪽이 교환하는 개념이에요.','B2','negotiation',1,5,'concession trade-off negotiation deal','The buyer made a concession on the delivery date.','구매자는 배송 날짜에서 양보했어요.','There''s always a trade-off between speed and quality.','속도와 품질 사이에는 늘 절충이 있어요.','As a concession, the seller agreed to cover the shipping costs.','양보의 표시로 판매자는 배송비를 부담하기로 동의했어요.','They made small concessions to keep the deal alive.','그들은 거래를 살리기 위해 작은 양보를 했어요.','There''s always a trade-off between cost and quality.','비용과 품질 사이에는 항상 절충이 있어요.'),
('nuc_negotiation_06','leverage','bargaining power',NULL,'협상 레버리지','협상력',NULL,'leverage는 협상에서 자신에게 유리한 우위, bargaining power는 협상 가능한 힘이에요.','leverage는 구체적 우위 요소, bargaining power는 힘의 균형이에요.','B2','negotiation',2,6,'leverage bargaining power negotiation','Having multiple offers gives you leverage in negotiation.','여러 제안을 가지고 있으면 협상에서 우위를 점할 수 있어요.','Small firms often have little bargaining power with large retailers.','소규모 기업들은 대형 소매업체와의 협상력이 약한 경우가 많아요.','Owning the patent gave the startup huge leverage over its rivals.','그 특허를 보유한 덕분에 그 스타트업은 경쟁사들에 대해 막대한 우위를 갖게 됐어요.','Having competing offers gave her real leverage.','경쟁 제안들이 그녀에게 진정한 협상 우위를 줬어요.','Workers gain bargaining power when they unite.','근로자들은 단결할 때 협상력을 얻어요.'),
('nuc_negotiation_07','contract','agreement',NULL,'계약서 (법적 구속)','합의 (광범위)',NULL,'contract는 법적으로 구속력 있는 계약서, agreement는 더 넓게 서로 동의한 상태예요.','contract는 법적 구속력, agreement는 구두 합의도 포함해요.','B2','negotiation',1,7,'contract agreement legal business','Both parties signed the contract.','양측이 계약서에 서명했어요.','We reached an informal agreement over the phone.','저희는 전화로 비공식적인 합의에 이르렀어요.','Read the contract carefully before you commit to anything.','무언가에 약속하기 전에 계약서를 꼼꼼히 읽으세요.','They signed the contract after months of negotiation.','몇 달의 협상 끝에 그들은 계약서에 서명했어요.','We reached a verbal agreement that still needs to be put in writing.','우리는 구두 합의에 이르렀지만 서면화가 필요해요.'),
('nuc_negotiation_14','compromise','settle',NULL,'타협하다 (서로 양보)','합의·해결하다 (마무리)',NULL,'compromise는 서로 양보해 중간점 찾기, settle은 분쟁·이슈를 최종 해결하는 마무리.','compromise는 양보·중간점, settle은 최종 해결. settle a bill은 청구서 정산, settle down은 안정.','B2','negotiation',1,0,'handshake agreement compromise negotiation business','We compromised on the price.','저희는 가격에서 절충했어요.','They settled the dispute out of court.','그들은 그 분쟁을 법정 밖에서 해결했어요.','Neither side was willing to compromise on the deadline.','양쪽 다 마감일에 대해서는 양보하려 하지 않았어요.','After compromising on several points, they settled the deal.','여러 부분에서 타협한 후 거래를 마무리 지었어요.','You compromise to reach an agreement; you settle the matter.','합의에 이르려면 타협하고, 사안을 마무리하세요.'),
('nuc_negotiation_08','mediate','arbitrate',NULL,'중재하다 (자발적)','중재하다 (공식·구속)',NULL,'mediate는 제3자가 협상을 돕는 것, arbitrate는 제3자가 구속력 있는 결정을 내리는 것이에요.','mediation은 자발적 타협, arbitration은 공식·구속력 있는 판정이에요.','C1','negotiation',1,8,'mediate arbitrate dispute resolution','A counselor mediated the dispute.','한 상담사가 그 분쟁을 중재했어요.','The case went to arbitration after talks failed.','협상이 결렬된 후 그 사건은 중재 절차로 넘어갔어요.','A neutral colleague offered to mediate between the two departments.','한 중립적인 동료가 두 부서 사이를 중재해 주겠다고 제안했어요.','A trained mediator helped them find common ground.','훈련된 중재자가 그들이 공통점을 찾도록 도왔어요.','Disputes that can''t be resolved often go to arbitration.','해결되지 않는 분쟁은 종종 중재로 가게 돼요.'),
('nuc_negotiation_09','bottom line','walkaway point',NULL,'최저 수용 조건','협상 철수 한계선',NULL,'"bottom line"은 절대 양보 못 하는 최소 조건, "walkaway point"는 협상을 그만두는 한계점이에요.','협상 전 bottom line과 walkaway point를 미리 정해두는 게 중요해요.','C1','negotiation',2,9,'bottom line walkaway negotiation strategy','Our bottom line is a 5% margin.','우리의 최저선은 5%의 마진이에요.','If they go below our walkaway point, we leave the table.','그들이 우리의 협상 결렬 지점 아래로 내려가면 우리는 협상 테이블을 떠날 거예요.','We won''t sign anything that falls below our bottom line.','우리는 최저선에 못 미치는 그 어떤 것에도 서명하지 않을 거예요.','Be clear about your bottom line before walking into the room.','회의실에 들어가기 전에 최저 수용 조건을 명확히 하세요.','Knowing your walkaway point keeps you from settling for less.','협상 철수 한계선을 알면 못한 조건에 만족하지 않게 돼요.'),
('nuc_negotiation_10','BATNA','ZOPA',NULL,'최선 대안 (협상 안 될 때)','합의 가능 영역',NULL,'BATNA(Best Alternative to Negotiated Agreement)는 협상 실패 시 최선책, ZOPA(Zone of Possible Agreement)는 합의 가능한 범위예요.','BATNA와 ZOPA는 협상론의 핵심 개념이에요.','C1','negotiation',1,10,'BATNA ZOPA negotiation strategy','Knowing your BATNA gives you more confidence.','당신의 BATNA(최선의 대안)를 아는 것은 더 큰 자신감을 줘요.','If a ZOPA exists, a deal is possible.','ZOPA(협상 가능 영역)가 존재한다면 거래가 가능해요.','Calculating your BATNA before talks helps you decide when to walk away.','협상 전에 당신의 BATNA를 계산하면 언제 협상에서 물러날지 결정하는 데 도움이 돼요.','A strong BATNA gives you confidence at the table.','강한 BATNA는 협상 자리에서 자신감을 줘요.','If the ZOPA is too narrow, you won''t reach a deal.','합의 가능 영역이 너무 좁으면 거래에 이르지 못해요.'),
('nuc_negotiation_11','principled','positional',NULL,'원칙 기반 협상','입장 기반 협상',NULL,'positional bargaining은 입장만 고수하는 방식, principled negotiation은 이해관계를 파악해 해결하는 방식이에요.','하버드 협상 모델은 positional → principled 전환을 강조해요.','C2','negotiation',1,11,'principled positional negotiation Harvard','Principled negotiation led to a win-win outcome.','원칙에 입각한 협상이 모두에게 이로운 결과로 이어졌어요.','Positional bargaining often results in deadlock.','입장 중심의 흥정은 종종 교착 상태로 이어져요.','By staying principled, the team built trust with the other side.','원칙을 지킴으로써 그 팀은 상대방과 신뢰를 쌓았어요.','Principled negotiation focuses on interests, not positions.','원칙 기반 협상은 입장이 아닌 이해관계에 집중해요.','Positional bargaining can turn quickly into a deadlock.','입장 기반 협상은 빠르게 교착 상태로 변할 수 있어요.'),
('nuc_negotiation_12','ratify','endorse',NULL,'비준하다 / 공식 승인','지지하다 / 승인하다',NULL,'ratify는 공식적으로 문서·조약을 비준하는 것, endorse는 지지·추천하는 것이에요.','ratify는 공식 문서 승인, endorse는 지지 표명이에요.','C2','negotiation',2,12,'ratify endorse approval business','The board ratified the new contract.','이사회는 새 계약을 비준했어요.','The CEO endorsed the partnership publicly.','CEO는 그 파트너십을 공개적으로 지지했어요.','Parliament must ratify the treaty before it takes effect.','그 조약은 효력을 발휘하기 전에 의회의 비준을 받아야 해요.','The agreement was ratified at the next meeting.','그 합의는 다음 회의에서 비준됐어요.','The mayor publicly endorsed the new community plan.','시장은 새 지역사회 계획을 공개적으로 지지했어요.'),
('nuc_negotiation_13','impasse','deadlock',NULL,'교착 상태','데드락 (완전 정지)',NULL,'impasse와 deadlock 모두 협상이 막힌 상태지만, deadlock은 완전히 진행이 불가능한 상태를 강조해요.','impasse는 진전 없음, deadlock은 양측이 완전히 움직이지 않는 상태예요.','C2','negotiation',1,13,'impasse deadlock negotiation stalemate','Talks reached an impasse over the price.','협상이 가격 문제로 교착 상태에 빠졌어요.','The negotiations ended in a complete deadlock.','협상은 완전한 교착 상태로 끝났어요.','After weeks of stalemate, the talks finally reached an impasse.','몇 주간의 교착 끝에 협상은 결국 막다른 골목에 이르렀어요.','Talks reached an impasse over the issue of overtime pay.','협상이 초과 근무 수당 문제로 교착 상태에 빠졌어요.','The complete deadlock surprised everyone in the room.','완전한 데드락이 회장 모두를 놀라게 했어요.'),
('nuc_news_01','headline','title',NULL,'헤드라인 (기사 제목)','제목 (일반)',NULL,'headline은 뉴스 기사의 굵은 제목, title은 책·영화·문서 등의 제목이에요.','headline은 뉴스 전용, title은 모든 매체의 제목에 써요.','B1','news',1,1,'headline title news media','The headline read: "Economy Grows 4%."','헤드라인에는 "경제 4% 성장"이라고 쓰여 있었어요.','The title of the novel is "The Guest."','그 소설의 제목은 "손님"이에요.','That misleading headline didn''t match the actual story.','그 오해를 부르는 헤드라인은 실제 기사 내용과 맞지 않았어요.','The morning headline was about the new government policy.','아침 헤드라인은 새 정부 정책에 관한 것이었어요.','The book''s title gives away the central mystery.','그 책의 제목이 중심 미스터리를 미리 알려줘요.'),
('nuc_news_02','journalist','reporter',NULL,'저널리스트 (직업)','기자 (현장)',NULL,'journalist는 뉴스를 취재·작성하는 직업인, reporter는 특히 현장에서 취재하는 기자예요.','journalist는 넓은 직업 범주, reporter는 현장 취재 역할을 강조해요.','B1','news',2,2,'journalist reporter media news','She is a respected journalist with 20 years of experience.','그녀는 20년 경력의 존경받는 기자예요.','The reporter was live at the scene.','그 기자는 현장에서 생방송으로 보도하고 있었어요.','As a freelance journalist, she writes for several international magazines.','프리랜서 기자로서 그녀는 여러 국제 잡지에 글을 써요.','She''s an award-winning journalist who covers human rights.','그녀는 인권을 취재하는 수상 경력의 저널리스트예요.','The reporter was sent overseas to cover the conflict.','기자는 분쟁을 취재하기 위해 해외로 파견됐어요.'),
('nuc_news_03','fact','opinion',NULL,'사실','의견',NULL,'fact는 검증된 사실, opinion은 개인의 생각이나 관점이에요.','뉴스 리터러시의 핵심: fact(사실)와 opinion(의견)을 구분하는 것이에요.','B1','news',1,3,'fact opinion news media literacy','The Earth orbits the Sun — that is a fact.','지구는 태양 주위를 돌아요. 그건 사실이에요.','In my opinion, the policy needs revision.','제 생각에는 그 정책을 수정해야 해요.','It''s a scientific fact that water boils at 100 degrees at sea level.','해수면 높이에서 물이 100도에 끓는다는 건 과학적 사실이에요.','Always check the source before sharing a "fact" online.','온라인에서 "사실"을 공유하기 전에 항상 출처를 확인하세요.','That''s just my personal opinion, not professional advice.','그건 전문가 조언이 아닌 그저 제 개인적 의견이에요.'),
('nuc_news_04','breaking news','developing story',NULL,'속보','진행 중인 뉴스',NULL,'"breaking news"는 방금 발생한 긴급 뉴스, "developing story"는 상황이 계속 변하는 뉴스예요.','breaking news는 발생 즉시, developing story는 계속 업데이트되는 뉴스예요.','B1','news',2,4,'breaking news developing story media','Breaking news: a major earthquake has struck.','속보입니다. 대규모 지진이 발생했어요.','This is a developing story — more details to follow.','이것은 진행 중인 사건이에요. 더 많은 정보가 이어질 거예요.','The anchor cut to breaking news about the election results.','앵커는 선거 결과에 관한 속보로 화면을 전환했어요.','Breaking news interrupted the regular broadcast.','속보가 정규 방송을 중단시켰어요.','This is a developing story — details may change quickly.','이것은 진행 중인 뉴스예요 — 세부 사항이 빠르게 바뀔 수 있어요.'),
('nuc_news_15','cover','report',NULL,'(현장을) 취재하다','(정리해서) 보도하다',NULL,'cover는 사건 현장을 취재하는 폭넓은 활동, report는 정리해서 보도하는 결과.','cover는 취재 활동(현장 포함), report는 정리·전달. 같은 사건도 cover는 "다룬다", report는 "전한다".','B1','news',1,0,'journalist reporter coverage news camera','She covered the election for CNN.','그녀는 CNN에서 선거를 취재했어요.','He reported the news from the scene.','그는 현장에서 뉴스를 보도했어요.','Our team will cover the festival from start to finish.','우리 팀이 축제를 처음부터 끝까지 취재할 거예요.','Journalists cover events and report findings.','기자들은 사건을 취재하고 결과를 보도해요.','They covered the war zone and reported casualties daily.','그들은 전쟁 지역을 취재하고 매일 사상자를 보도했어요.'),
('nuc_news_05','source','reference',NULL,'출처 / 정보 제공자','참고자료',NULL,'source는 정보를 제공한 사람이나 문서, reference는 글에서 인용하는 자료예요.','source는 정보 출처, reference는 학술·공식 인용에 써요.','B2','news',1,5,'source reference journalism research','The journalist protected the identity of her source.','그 기자는 자신의 취재원 신원을 보호했어요.','Please provide references for your claims.','당신의 주장에 대한 출처를 제시해 주세요.','A good reporter always verifies a story with more than one source.','좋은 기자는 언제나 둘 이상의 취재원으로 기사를 확인해요.','Reliable sources are critical to good journalism.','신뢰할 만한 출처는 좋은 저널리즘에 결정적이에요.','List your references at the end of the report.','보고서 끝에 참고자료를 나열하세요.'),
('nuc_news_06','editorial','article',NULL,'사설 / 칼럼','기사',NULL,'editorial은 신문사의 공식 의견이나 칼럼, article은 취재 기반 보도 기사예요.','editorial은 의견, article은 사실 보도가 주목적이에요.','B2','news',2,6,'editorial article opinion news','The editorial criticized the new legislation.','그 사설은 새로운 법안을 비판했어요.','The article covered the protest in detail.','그 기사는 시위를 자세히 다뤘어요.','The newspaper published an editorial supporting the mayor''s plan.','그 신문은 시장의 계획을 지지하는 사설을 실었어요.','The editorial argued for stronger environmental laws.','사설은 더 강력한 환경법을 주장했어요.','The article won an award for investigative reporting.','그 기사는 탐사 보도 상을 받았어요.'),
('nuc_news_07','anonymous','confidential',NULL,'익명의','기밀의',NULL,'anonymous는 신원이 밝혀지지 않은 것, confidential은 비밀로 유지해야 할 정보예요.','anonymous는 신원 비공개, confidential은 내용 비공개예요.','B2','news',1,7,'anonymous confidential privacy news','The tip came from an anonymous source.','그 제보는 익명의 출처에서 나왔어요.','The document was marked confidential.','그 문서에는 기밀이라고 표시돼 있었어요.','The witness asked to remain anonymous out of fear of retaliation.','그 목격자는 보복이 두려워 익명으로 남기를 요청했어요.','The tip came from an anonymous caller.','제보는 익명 전화에서 왔어요.','Please keep this conversation confidential.','이 대화를 기밀로 유지해 주세요.'),
('nuc_news_08','allegation','accusation',NULL,'혐의 / 주장','고소 / 고발',NULL,'allegation은 아직 증명되지 않은 주장, accusation은 누군가를 잘못했다고 직접 고발하는 것이에요.','allegation은 주장 단계, accusation은 더 공식적이고 직접적이에요.','B2','news',2,8,'allegation accusation legal news','The allegation has not been proven.','그 의혹은 아직 입증되지 않았어요.','She made a formal accusation against her employer.','그녀는 고용주를 상대로 공식적인 고발을 했어요.','The company strongly denied the allegations of fraud.','그 회사는 사기 의혹을 강하게 부인했어요.','The allegations are serious but still need investigation.','그 혐의는 심각하지만 아직 조사가 필요해요.','She filed an accusation of harassment with HR.','그녀는 인사팀에 괴롭힘 고발을 접수했어요.'),
('nuc_news_14','announce','declare',NULL,'발표하다 (정보 공개)','선언하다 (공식·강력)',NULL,'announce는 정보를 공개적으로 알리는 것, declare는 공식적·강력하게 선언하는 것 (전쟁, 독립, 의지).','announce는 일반 발표, declare는 강한 공식 선언. 결혼 발표는 announce, 전쟁 선포는 declare.','B2','news',1,0,'announcement declaration podium speech press','The CEO announced new policies today.','CEO가 오늘 새 정책을 발표했어요.','The country declared independence in 1948.','그 나라는 1948년에 독립을 선언했어요.','The airline announced delays due to the heavy snow.','항공사가 폭설로 인한 지연을 발표했어요.','They announced the merger; he declared his support publicly.','그들은 합병을 발표했고, 그는 공개적으로 지지를 선언했어요.','Announce a birthday party; declare a state of emergency.','생일 파티를 알리세요; 비상사태를 선포하세요.'),
('nuc_news_09','circulation','readership',NULL,'발행 부수','독자 수',NULL,'circulation은 인쇄 매체가 배포되는 부수, readership은 실제 읽는 독자의 수예요.','circulation은 배포량, readership은 실제 독자 규모예요.','C1','news',1,9,'circulation readership newspaper media','The newspaper has a circulation of one million copies.','그 신문은 백만 부의 발행 부수를 기록하고 있어요.','Online readership has grown significantly.','온라인 독자 수가 크게 늘었어요.','At its peak, the magazine reached a circulation of two million.','전성기에 그 잡지는 이백만 부의 발행 부수에 이르렀어요.','The newspaper''s circulation has dropped as readers move online.','독자들이 온라인으로 이동하면서 신문 발행 부수가 줄었어요.','Their digital readership doubled in just two years.','그들의 디지털 독자 수가 단 2년 만에 두 배가 됐어요.'),
('nuc_news_10','investigative','analytical',NULL,'탐사 (보도)','분석 (보도)',NULL,'investigative journalism은 숨겨진 사실을 파헤치는 취재, analytical journalism은 사건의 의미와 맥락을 분석해요.','investigative는 사실 발굴, analytical은 의미 해석이 목적이에요.','C1','news',2,10,'investigative analytical journalism reporting','Investigative reporting uncovered the corruption scandal.','탐사 보도가 그 부패 스캔들을 밝혀냈어요.','The analytical piece explained the economic impact of the strike.','그 분석 기사는 파업의 경제적 영향을 설명했어요.','Investigative reporters spent months gathering documents for the exposé.','탐사 기자들은 폭로 기사를 위해 몇 달간 문서를 수집했어요.','Investigative journalism shines light on issues others ignore.','탐사 저널리즘은 다른 사람들이 무시하는 문제에 빛을 비춰요.','An analytical piece can help readers make sense of complex events.','분석 기사는 독자들이 복잡한 사건을 이해하는 데 도움이 될 수 있어요.'),
('nuc_news_11','libel','slander',NULL,'문서 명예훼손','구두 명예훼손',NULL,'libel은 글·출판물로 명예를 훼손하는 것, slander는 말로 명예를 훼손하는 것이에요.','libel(written) vs slander(spoken)으로 기억해요.','C1','news',1,11,'libel slander defamation legal media','The article was found to be libel.','그 기사는 명예 훼손인 것으로 밝혀졌어요.','He sued her for slander after her false statements.','그는 그녀의 허위 발언으로 인해 그녀를 명예 훼손으로 고소했어요.','The newspaper retracted the story to avoid a libel suit.','그 신문사는 명예 훼손 소송을 피하려고 기사를 철회했어요.','The publication apologized after the libel was proven.','문서 명예훼손이 입증된 후 그 출판물은 사과했어요.','Spoken slander is harder to prove than written libel.','구두 명예훼손은 문서 명예훼손보다 입증하기 어려워요.'),
('nuc_news_12','objectivity','impartiality',NULL,'객관성 (사실 기반)','공정성 (균형)',NULL,'objectivity는 개인 의견 없이 사실을 전달하는 것, impartiality는 모든 편을 공정하게 다루는 것이에요.','objectivity는 사실 중심, impartiality는 양쪽 입장의 균형이에요.','C2','news',1,12,'objectivity impartiality journalism media','Good journalism aims for objectivity.','좋은 저널리즘은 객관성을 지향해요.','The broadcaster is required to maintain impartiality.','방송사는 공정성을 유지해야 해요.','Striving for objectivity means setting aside your own preferences when reporting.','객관성을 추구한다는 것은 보도할 때 자신의 선호를 제쳐 두는 것을 의미해요.','True objectivity in reporting is hard but worth aiming for.','보도의 진정한 객관성은 어렵지만 추구할 가치가 있어요.','Public broadcasters are expected to maintain impartiality.','공영 방송은 공정성을 유지해야 해요.'),
('nuc_news_13','framing','priming',NULL,'프레이밍 (맥락 설정)','프라이밍 (선행 노출)',NULL,'framing은 이슈를 어떤 맥락으로 제시하는지, priming은 특정 주제에 노출시켜 판단에 영향 주는 것이에요.','미디어 심리학에서 framing과 priming은 핵심 개념이에요.','C2','news',2,13,'framing priming media psychology influence','The way the story was framed influenced public opinion.','그 사건이 보도된 방식이 여론에 영향을 미쳤어요.','News coverage primed voters to think about the economy.','뉴스 보도는 유권자들이 경제에 대해 생각하도록 유도했어요.','Careful framing can make the same statistic feel positive or alarming.','신중한 프레이밍은 같은 통계를 긍정적으로도, 불안하게도 느껴지게 할 수 있어요.','How a story is framed shapes how readers feel about it.','기사가 어떻게 프레이밍되는지가 독자들이 어떻게 느끼는지를 형성해요.','Repeated coverage primes the public to focus on certain issues.','반복적인 보도는 대중이 특정 문제에 집중하도록 유도해요.'),
('nuc_presentation_14','show','display',NULL,'보여주다 (일상)','전시·표시하다 (격식·시각적)',NULL,'show는 일반적인 "보여주다", display는 진열·전시하거나 화면에 표시하는 좀 더 시각적·격식 표현.','show는 일상·동작, display는 시각적·격식. 가게 진열·화면 표시는 display, 그냥 보여주기는 show.','A2','presentation',1,0,'presentation slide showing display screen','Let me show you the report.','제가 보고서를 보여 드릴게요.','The museum displays ancient artifacts.','그 박물관은 고대 유물을 전시해요.','Could you show me how to use this feature?','이 기능을 어떻게 쓰는지 보여 주실 수 있어요?','I''ll show you the slide where the data is displayed.','데이터가 표시된 슬라이드를 보여 드릴게요.','The store displays new items; staff show customers around.','매장은 신상품을 진열하고, 직원은 고객을 안내해요.'),
('nuc_presentation_16','so','such',NULL,'너무, 정말 (형용사·부사 앞)','정말 (명사 앞)',NULL,'so는 형용사·부사 앞 (so good, so quickly), such는 (관사+) 명사 앞 (such a good day).','so + 형용사/부사, such + (a/an) + (형용사) + 명사. "so good"="such a good thing" 구조 차이.','A2','presentation',1,0,'emphasis exclamation impressive amazing','It''s so cold today.','오늘 정말 추워요.','It''s such a cold day.','정말 추운 날이에요.','The presentation went so smoothly that everyone was impressed.','발표가 너무 매끄럽게 진행되어서 모두가 감탄했어요.','The food was so delicious that we ordered such large portions.','음식이 너무 맛있어서 우리는 정말 큰 양을 주문했어요.','She''s so smart; he''s such a smart person.','그녀는 정말 똑똑해요; 그는 정말 똑똑한 사람이에요.'),
('nuc_presentation_01','present','present vs report',NULL,'발표하다 (설득)','보고하다 (사실)',NULL,'present는 정보를 설득력 있게 전달하는 것, report는 사실을 객관적으로 전달하는 것이에요.','present는 설득, report는 사실 전달이 주 목적이에요.','B1','presentation',1,1,'present report business presentation','She presented the proposal to the board.','그녀는 이사회에 제안서를 발표했어요.','He reported the quarterly sales figures.','그는 분기별 매출 수치를 보고했어요.','Tomorrow she will present the marketing plan to potential investors.','내일 그녀는 잠재 투자자들에게 마케팅 계획을 발표할 거예요.','She presented her findings clearly and persuasively.','그녀는 자기 연구 결과를 명확하고 설득력 있게 발표했어요.','He reported the team''s progress to the executives.','그는 임원진에게 팀의 진행 상황을 보고했어요.'),
('nuc_presentation_02','outline','summary',NULL,'개요','요약',NULL,'outline은 구조와 주요 항목을 보여주는 개요, summary는 내용을 짧게 압축한 요약이에요.','outline은 구조 중심, summary는 내용 압축이에요.','B1','presentation',2,2,'outline summary structure presentation','Let me give you an outline of today''s presentation.','오늘 발표의 개요를 말씀드릴게요.','Here is a brief summary of the findings.','여기 연구 결과에 대한 간략한 요약이 있어요.','Before writing, sketch a rough outline of your main sections.','글을 쓰기 전에 주요 섹션의 대략적인 개요를 그려 보세요.','Let me give you a quick outline of the agenda.','안건의 빠른 개요를 알려드릴게요.','Here is a one-page summary of the main findings.','주요 결과의 한 페이지 요약이 여기 있어요.'),
('nuc_presentation_03','slide','handout',NULL,'슬라이드','유인물',NULL,'slide는 화면에 표시하는 발표 자료, handout은 청중에게 나눠주는 인쇄 자료예요.','slide는 시각 보조 자료, handout은 청중이 보관하는 자료예요.','B1','presentation',1,3,'slide handout presentation visual','Can you go back to the previous slide?','이전 슬라이드로 돌아가 주시겠어요?','Please refer to the handout for the details.','자세한 내용은 유인물을 참고해 주세요.','He spent the whole evening designing the opening slide.','그는 저녁 내내 첫 슬라이드를 디자인하는 데 시간을 보냈어요.','Can we go back to the second slide for a moment?','잠시 두 번째 슬라이드로 돌아갈 수 있어요?','Please take a handout from the table on your way in.','들어오는 길에 테이블에서 유인물 한 부 가져가세요.'),
('nuc_presentation_15','demonstrate','explain',NULL,'시연하다 (보여주며 증명)','설명하다 (말로)',NULL,'demonstrate는 행동·예시로 보여주며 증명, explain은 말로 풀어 설명.','demonstrate는 행동·시각적 증명, explain은 언어·논리적 풀이. 실험·기능은 demonstrate가 효과적.','B1','presentation',1,0,'demonstration product showing presentation hands-on','Let me demonstrate how this app works.','이 앱이 어떻게 작동하는지 시연해 드릴게요.','Let me explain how this app works.','이 앱이 어떻게 작동하는지 설명해 드릴게요.','The chef demonstrated the technique in front of the class.','셰프가 수업 앞에서 그 기법을 시연했어요.','I''ll explain the concept and demonstrate it step by step.','개념을 설명하고 단계별로 시연할게요.','She demonstrated the product while he explained its features.','그녀는 제품을 시연하고, 그는 기능을 설명했어요.'),
('nuc_presentation_04','introduce','conclude',NULL,'도입하다','결론 짓다',NULL,'introduce는 주제나 발표를 시작하는 것, conclude는 핵심을 정리하며 마무리하는 것이에요.','introduce(도입) → body(본론) → conclude(결론) 구조로 발표를 구성해요.','B2','presentation',1,4,'introduce conclude presentation structure','Let me introduce our topic for today.','오늘의 주제를 소개해 드릴게요.','To conclude, we recommend the second option.','결론적으로, 저희는 두 번째 방안을 추천해요.','She will introduce the new product line at the conference.','그녀는 학회에서 새 제품 라인을 소개할 거예요.','Let me introduce today''s key questions briefly.','오늘의 핵심 질문들을 간단히 도입할게요.','To conclude, we recommend a three-step approach.','결론적으로 우리는 3단계 접근법을 권장해요.'),
('nuc_presentation_05','engage','interact',NULL,'참여시키다','상호작용하다',NULL,'engage는 청중의 관심과 집중을 유도하는 것, interact는 서로 주고받는 상호작용이에요.','engage는 일방적 관심 유도도 포함, interact는 양방향 교류를 강조해요.','B2','presentation',2,5,'engage interact audience presentation','Good presenters engage the audience from the start.','훌륭한 발표자는 처음부터 청중의 관심을 끌어요.','We invited the audience to interact during the Q&A.','저희는 Q&A 시간에 청중이 참여하도록 했어요.','A surprising story is one of the best ways to engage a tired audience.','놀라운 이야기는 지친 청중의 관심을 끄는 가장 좋은 방법 중 하나예요.','She engaged the audience by asking thoughtful questions.','그녀는 사려 깊은 질문으로 청중을 참여시켰어요.','Workshops let participants interact in small groups.','워크숍은 참가자들이 소그룹으로 상호작용하게 해줘요.'),
('nuc_presentation_06','emphasize','highlight',NULL,'강조하다','부각시키다',NULL,'emphasize는 중요성을 말로 강조하는 것, highlight는 시각적으로 또는 특별히 주목하게 만드는 것이에요.','emphasize는 구어·문어, highlight는 시각 자료나 특정 부분 부각에 써요.','B2','presentation',1,6,'emphasize highlight key point','I want to emphasize the importance of this point.','이 점의 중요성을 강조하고 싶어요.','The chart highlights the upward trend.','그 도표는 상승 추세를 잘 보여 줘요.','I''d like to emphasize how tight our deadline really is.','저희 마감이 얼마나 빡빡한지 강조하고 싶어요.','I''d like to emphasize that this is just the first phase.','이건 첫 단계일 뿐이라는 점을 강조하고 싶어요.','The graph highlights the biggest changes from last year.','그래프는 작년 대비 가장 큰 변화를 부각시켜요.'),
('nuc_presentation_07','clarify','elaborate',NULL,'명확히 하다','자세히 설명하다',NULL,'clarify는 혼란을 없애고 명확하게 하는 것, elaborate는 더 자세한 정보를 추가하는 것이에요.','clarify는 이해 해소, elaborate는 내용 확장이에요.','B2','presentation',2,7,'clarify elaborate explanation detail','Let me clarify what I mean by that.','제가 말하는 의미를 명확히 설명해 드릴게요.','Could you elaborate on your second point?','두 번째 논점을 좀 더 자세히 설명해 주시겠어요?','Let me clarify the timeline so there''s no confusion later.','나중에 혼란이 없도록 일정을 명확히 짚어 드릴게요.','Could you clarify what you mean by "user-first"?','"사용자 우선"이 무슨 의미인지 명확히 해주실 수 있어요?','Could you elaborate on the budget assumptions?','예산 가정에 대해 자세히 설명해 주실 수 있어요?'),
('nuc_presentation_17','exactly','precisely',NULL,'정확히 (일반)','정밀하게 (격식·과학)',NULL,'exactly와 precisely는 거의 동의어. exactly가 일상, precisely가 격식·과학적 정확성 강조.','exactly는 일상·구어, precisely는 격식·과학. 측정·시간은 둘 다 가능, 학술적 글은 precisely.','B2','presentation',1,0,'exactly precise measurement ruler accurate','It''s exactly 3 o''clock.','정확히 3시예요.','The temperature is precisely 22 degrees.','기온은 정확히 22도예요.','That''s exactly the kind of feedback I was hoping for.','그게 바로 제가 바라던 종류의 피드백이에요.','That''s exactly what I meant — precisely my point.','그게 정확히 제가 의도한 거예요 — 정확히 제 요점이에요.','I want exactly two scoops; measure precisely 250 ml.','정확히 두 스푼이요; 정밀하게 250ml 측정하세요.'),
('nuc_presentation_18','especially','particularly',NULL,'특히 (일반·구어)','특히 (격식)',NULL,'especially와 particularly는 동의어. especially가 일상, particularly가 격식·강조 (영국·학술).','especially는 친근, particularly는 격식. "particularly important"는 격식·강조에서 자주 쓰여요.','B2','presentation',1,0,'special highlight emphasis particular focus','I love fruits, especially mangoes.','저는 과일을, 특히 망고를 좋아해요.','She''s talented, particularly in math.','그녀는 재능이 있는데, 특히 수학에 그래요.','The museum is worth visiting, especially on a rainy day.','그 박물관은 가 볼 만한데, 특히 비 오는 날에 그래요.','I enjoy reading, especially novels — particularly historical ones.','책 읽기를 좋아하고, 특히 소설을, 그 중에서도 역사 소설을 좋아해요.','It''s especially cold today; particularly windy in the evening.','오늘 특히 춥고, 저녁에 특히 바람 많아요.'),
('nuc_presentation_08','coherent','cohesive',NULL,'논리적으로 일관된','유기적으로 연결된',NULL,'coherent는 논리가 명확하게 이어지는 것, cohesive는 각 부분이 유기적으로 잘 연결된 것이에요.','coherent는 논리적 명확성, cohesive는 구조적 연결성을 강조해요.','C1','presentation',1,8,'coherent cohesive structure argument','The presentation was coherent and easy to follow.','그 발표는 논리 정연해서 따라가기 쉬웠어요.','A cohesive argument ties all points together.','응집력 있는 주장은 모든 논점을 하나로 묶어줘요.','For your essay to feel coherent, each paragraph must lead logically to the next.','에세이가 논리 정연하게 느껴지려면 각 문단이 다음 문단으로 자연스럽게 이어져야 해요.','A coherent argument is easier for the audience to follow.','논리적으로 일관된 주장이 청중이 따라가기 더 쉬워요.','The slides were beautifully cohesive in style.','슬라이드는 스타일이 아름답게 유기적으로 연결돼 있었어요.'),
('nuc_presentation_09','persuasive','informative',NULL,'설득력 있는','정보 전달형',NULL,'persuasive presentation은 행동 변화를 이끌고, informative는 지식·사실 전달이 목적이에요.','목적에 따라 발표 스타일을 persuasive 또는 informative로 맞춰요.','C1','presentation',2,9,'persuasive informative presentation purpose','The sales pitch was persuasive and compelling.','그 영업 발표는 설득력 있고 인상적이었어요.','The training session was highly informative.','그 교육 세션은 매우 유익했어요.','A persuasive closing line can convince the audience to take action.','설득력 있는 마무리 문장은 청중이 행동에 나서도록 설득할 수 있어요.','The pitch was persuasive enough to win the contract.','그 피치는 계약을 따낼 만큼 설득력이 있었어요.','The training session was informative and well-paced.','교육 세션은 정보가 풍부하고 진행 속도가 좋았어요.'),
('nuc_presentation_10','anecdote','statistic',NULL,'일화 / 사례','통계',NULL,'anecdote는 개인 경험 이야기로 청중을 공감시키는 방법, statistic은 데이터로 주장을 뒷받침해요.','anecdote(감성) + statistic(이성)을 함께 쓰면 강력한 발표가 돼요.','C1','presentation',1,10,'anecdote statistic evidence presentation','She opened with a personal anecdote to connect with the audience.','그녀는 청중과 교감하기 위해 개인적인 일화로 발표를 시작했어요.','The statistic showed a 30% increase in productivity.','그 통계는 생산성이 30% 증가했음을 보여 주었어요.','A well-chosen anecdote can make a dry topic memorable.','잘 고른 일화는 딱딱한 주제를 기억에 남게 만들 수 있어요.','She opened with a moving anecdote about her grandmother.','그녀는 할머니에 관한 감동적인 일화로 시작했어요.','A single striking statistic can change the room.','단 하나의 강력한 통계가 회장 분위기를 바꿀 수 있어요.'),
('nuc_presentation_11','posture','gesture',NULL,'자세','제스처',NULL,'posture는 서 있는 자세, gesture는 손·몸짓으로 의미를 전달하는 것이에요.','posture(자세)와 gesture(몸짓) 모두 비언어 소통(nonverbal communication)이에요.','C1','presentation',2,11,'posture gesture body language speaking','Good posture projects confidence on stage.','바른 자세는 무대에서 자신감을 보여줘요.','He used hand gestures to emphasize key points.','그는 핵심을 강조하기 위해 손동작을 사용했어요.','Standing tall with open posture helps you look relaxed and in control.','허리를 곧게 펴고 열린 자세로 서면 여유롭고 통제력 있어 보여요.','Good posture sends a message of confidence.','좋은 자세는 자신감의 메시지를 전달해요.','His hand gestures helped emphasize each key point.','그의 손짓이 각 핵심 요점을 강조하는 데 도움이 됐어요.'),
('nuc_presentation_12','ethos','pathos',NULL,'에토스 (신뢰성)','파토스 (감성 호소)',NULL,'ethos는 신뢰와 권위로 설득하는 것, pathos는 감정에 호소하는 설득 방법이에요.','Aristotle의 설득 3요소: ethos(신뢰) + pathos(감성) + logos(논리)예요.','C2','presentation',1,12,'ethos pathos logos rhetoric persuasion','The doctor''s ethos made the audience trust her claims.','그 의사의 인격적 신뢰감이 청중이 그녀의 주장을 믿게 만들었어요.','The charity video used pathos to inspire donations.','그 자선 영상은 감정에 호소해 기부를 이끌어냈어요.','A speaker''s ethos grows stronger when the audience knows her track record.','청중이 화자의 이력을 알게 되면 그 화자의 인격적 신뢰감은 더 강해져요.','Her ethos as a researcher made the audience trust the data.','연구자로서의 그녀의 신뢰성이 청중이 데이터를 신뢰하게 만들었어요.','The film''s pathos moved many viewers to tears.','영화의 감성 호소가 많은 시청자를 눈물 짓게 했어요.'),
('nuc_presentation_13','prosody','intonation',NULL,'운율 (말의 리듬·강세)','억양 (음의 높낮이)',NULL,'prosody는 발화의 리듬·강세·속도 전체, intonation은 음의 높낮이 변화에 특화된 표현이에요.','intonation은 prosody의 한 요소예요. 둘 다 스피킹 수업에서 중요해요.','C2','presentation',2,13,'prosody intonation speech language speaking','Skilled speakers use prosody to keep audiences engaged.','능숙한 연사들은 운율을 활용해 청중의 관심을 유지해요.','Rising intonation signals a question in English.','영어에서 올라가는 억양은 의문을 나타내요.','Without varied prosody, even an interesting talk can sound dull.','운율의 변화가 없으면 흥미로운 강연도 지루하게 들릴 수 있어요.','Good prosody can turn a flat speech into an engaging one.','좋은 운율은 평이한 연설을 매력적인 연설로 만들 수 있어요.','Rising intonation at the end signals a question.','끝의 상승 억양은 질문을 나타내요.'),
('nuc_shopping_14','choose','select',NULL,'고르다 (일상)','선택하다 (격식·정확)',NULL,'choose는 일상적·일반적, select는 좀 더 격식·정확한 선택 (메뉴, 옵션, 후보 등).','choose는 자유로운 선택, select는 정해진 옵션에서 골라내는 느낌. UI 버튼은 보통 "Select".','A2','shopping',1,0,'choosing selecting options shopping decision','I choose chocolate over vanilla.','저는 바닐라보다 초콜릿을 선택해요.','Please select your preferred language.','원하시는 언어를 선택해 주세요.','It was hard to choose between the two jackets.','두 재킷 중에서 고르기가 어려웠어요.','I chose the red shirt after selecting from 10 options.','10가지 옵션에서 고른 끝에 빨간 셔츠를 선택했어요.','Choose carefully; select the best candidate.','신중하게 고르세요; 최고의 후보자를 선택하세요.'),
('nuc_shopping_15','borrow','lend',NULL,'빌리다 (받는 입장)','빌려주다 (주는 입장)',NULL,'borrow는 빌려서 받는 행위, lend는 빌려주는 행위. 한국어는 둘 다 "빌리다"라 자주 헷갈림.','borrow는 받는 쪽(나에게로), lend는 주는 쪽(나로부터). "Can I borrow X?"가 "Can you lend X?"보다 더 자주 쓰여요.','A2','shopping',1,0,'lending borrowing book money exchange','Can I borrow your pen?','펜 좀 빌릴 수 있을까요?','Could you lend me your pen?','펜 좀 빌려주시겠어요?','May I borrow your charger until the end of the day?','오늘 하루만 충전기를 빌려도 될까요?','I borrowed her book; she lent it to me.','저는 그녀 책을 빌렸고, 그녀가 저에게 빌려줬어요.','Borrow money from a bank; the bank lends you money.','은행에서 돈을 빌리세요; 은행이 당신에게 돈을 빌려줘요.'),
('nuc_shopping_18','some','any',NULL,'어떤·약간 (긍정문)','어떤·전혀 (의문/부정)',NULL,'some은 긍정문에서, any는 의문문·부정문에서 주로 사용. 단, 제안·요청은 의문문에도 some 가능.','some=긍정/제안, any=의문/부정. 제안할 때(Would you like some?)는 의문문도 some.','A2','shopping',1,0,'some any apples shopping basket choosing','I have some apples.','저는 사과가 좀 있어요.','I don''t have any apples. / Do you have any apples?','저는 사과가 하나도 없어요. / 사과 있으세요?','Could I have some water, please?','물 좀 주실 수 있어요?','I bought some milk, but didn''t get any bread.','우유는 좀 샀는데 빵은 안 샀어요.','Would you like some coffee? (제안) / Is there any coffee left? (확인)','커피 좀 드릴까요? / 커피 좀 남았나요?'),
('nuc_shopping_01','buy','purchase',NULL,'사다 (일상)','구매하다 (격식)',NULL,'buy는 일상 대화에서 쓰는 표현, purchase는 더 격식 있는 서면이나 공식 상황에서 써요.','purchase는 계약서·영수증·공식 안내문에서 자주 보여요.','B1','shopping',1,1,'shopping buying retail store','I''m going to buy a new jacket.','저는 새 재킷을 살 거예요.','Please purchase tickets online.','티켓은 온라인으로 구매해 주세요.','Where did you buy those headphones?','그 헤드폰은 어디서 사셨어요?','I''m going to buy some bread on the way home.','저는 집에 가는 길에 빵을 좀 사려고 해요.','You can purchase tickets in advance through the app.','앱으로 미리 티켓을 구매하실 수 있어요.'),
('nuc_shopping_02','cheap','inexpensive',NULL,'싼 (부정적)','저렴한 (중립)',NULL,'cheap은 가격이 낮지만 품질도 낮다는 부정적 뉘앙스가 있고, inexpensive는 중립적으로 저렴하다는 뜻이에요.','품질을 낮게 보이지 않게 하려면 cheap 대신 inexpensive나 affordable을 써요.','B1','shopping',1,2,'price cheap quality value','This bag looks really cheap.','이 가방은 정말 싸구려처럼 보여요.','This bag is inexpensive but well-made.','이 가방은 저렴하지만 잘 만들어졌어요.','I avoid cheap chargers because they break so easily.','싸구려 충전기는 너무 쉽게 고장 나서 저는 피해요.','The shoes were cheap, but they fell apart in a month.','신발은 쌌지만 한 달 만에 망가졌어요.','This restaurant is surprisingly inexpensive and delicious.','이 식당은 놀라울 정도로 저렴하고 맛있어요.'),
('nuc_shopping_03','discount','sale',NULL,'할인','세일',NULL,'discount는 정가에서 깎아주는 것, sale은 특정 기간 여러 상품을 할인 판매하는 행사예요.','"on sale"은 할인 중이라는 뜻, "for sale"은 판매 중이라는 뜻이에요.','B1','shopping',2,3,'discount sale promotion shopping','Can I get a discount on this item?','이 상품 할인받을 수 있을까요?','The store is having a big sale this weekend.','그 가게는 이번 주말에 큰 세일을 해요.','During the summer sale, members also get an extra discount at checkout.','여름 세일 기간에는 회원에게 결제 시 추가 할인도 제공돼요.','Students get a discount with a valid ID.','학생들은 유효한 학생증으로 할인을 받아요.','Everything in the shop is on sale this week.','이번 주에는 매장 모든 것이 세일이에요.'),
('nuc_shopping_04','refund','exchange',NULL,'환불','교환',NULL,'refund는 돈을 돌려받는 것, exchange는 다른 상품으로 교환하는 것이에요.','매장 정책에 따라 환불(refund)이 안 될 수도 있으니 exchange를 먼저 물어볼 수 있어요.','B1','shopping',2,4,'refund exchange return policy','I''d like a refund for this product.','이 제품을 환불하고 싶어요.','Can I exchange this for a different size?','이것을 다른 사이즈로 교환할 수 있을까요?','If you''d rather not get a refund, you can exchange it for another colour.','환불을 원하지 않으시면, 다른 색상으로 교환하실 수 있어요.','I''d like a refund — the item was faulty.','환불받고 싶어요 — 물건에 결함이 있었어요.','Can I exchange this jacket for a smaller size?','이 재킷을 더 작은 사이즈로 교환할 수 있어요?'),
('nuc_shopping_16','all','whole','entire','모든 (개별 합)','전체 (덩어리)','전체 (강조)','all + 복수/불가산 (all the books), whole + 단수 (the whole book), entire는 whole의 격식·강조.','all = 여러 개 모두 (the + 복수), whole = 하나 전체 (단수), entire = whole의 격식·강조형.','B1','shopping',1,0,'whole entire all together complete totality','I read all the books.','저는 그 책들을 다 읽었어요.','I read the whole book.','저는 그 책 전체를 읽었어요.','I read the entire book in one day.','저는 그 책 전부를 하루 만에 읽었어요.','All my friends came; the whole family came; the entire neighborhood came.','제 친구 다 왔고, 가족 전체 왔고, 동네 전체가 왔어요.','She ate all the cookies, drank the whole milk, and used the entire box of cereal.','그녀는 쿠키 다 먹고, 우유 전체 마시고, 시리얼 한 통 다 썼어요.'),
('nuc_shopping_17','each','every',NULL,'각각 (개별 강조)','모든 (전체 강조)',NULL,'each는 개별 하나하나에 초점, every는 전체로서 모든 것에 초점. each = 2개 이상 가능, every = 3개 이상.','each는 개별 (2개~), every는 집단적 (3개~). "each of"는 가능하지만 "every of"는 안 됨.','B1','shopping',1,0,'individual each every single multiple items','Each student has a different style.','학생마다 각자 다른 스타일을 가지고 있어요.','Every student must pass the exam.','모든 학생이 시험에 통과해야 해요.','Each guest received a small gift at the door.','손님마다 문 앞에서 작은 선물을 받았어요.','I checked each item, and every box was correct.','각 항목을 확인했고, 모든 상자가 맞았어요.','Each candidate spoke; every candidate had three minutes.','각 후보가 발언했고, 모든 후보가 3분씩 받았어요.'),
('nuc_shopping_19','enough','sufficient',NULL,'충분한 (일상)','충분한 (격식)',NULL,'enough와 sufficient는 동의어. enough가 일상·구어, sufficient가 격식·문어체.','enough는 일상, sufficient는 격식 (보고서·계약·과학). "enough"는 부사·형용사로 다 쓰이는데, sufficient는 형용사만.','B1','shopping',1,0,'enough sufficient amount adequate satisfied','Do we have enough time?','우리에게 시간이 충분히 있나요?','Is there sufficient evidence?','증거가 충분한가요?','We didn''t bring enough chairs for all the guests.','우리는 모든 손님에게 줄 의자를 충분히 가져오지 못했어요.','We have enough food, but not sufficient funds for the project.','음식은 충분한데 프로젝트 자금은 부족해요.','She earned enough money; he provided sufficient documentation.','그녀는 충분한 돈을 벌었고, 그는 충분한 서류를 제출했어요.'),
('nuc_shopping_05','price','cost','fee','가격','비용','수수료 / 요금','price는 상품의 표시 가격, cost는 총 드는 비용, fee는 서비스·전문직에 대한 요금이에요.','price는 물건, fee는 서비스, cost는 포괄적 비용에 써요.','B2','shopping',1,5,'price cost fee payment','What''s the price of this dress?','이 원피스 가격이 얼마예요?','The total cost including tax is high.','세금을 포함한 총비용이 높아요.','There is a service fee for delivery.','배송에는 서비스 수수료가 있어요.','The price of vegetables has gone up sharply.','채소 가격이 가파르게 올랐어요.','The cost of living is high in big cities.','대도시의 생활비가 높아요.'),
('nuc_shopping_06','bargain','negotiate',NULL,'흥정하다 / 싸게 산 것','협상하다',NULL,'bargain은 싸게 잘 샀다는 의미나 흥정 행위, negotiate는 공식적으로 조건을 협상하는 것이에요.','재래시장에서는 bargain, 비즈니스·계약에서는 negotiate가 자연스러워요.','B2','shopping',2,6,'bargain negotiate price market','That coat was a real bargain!','그 코트는 정말 횡재였어요!','You can negotiate the price at the market.','시장에서는 가격을 흥정할 수 있어요.','I managed to bargain at the flea market, though you can''t negotiate prices in a department store.','벼룩시장에서는 흥정할 수 있었지만, 백화점에서는 가격을 흥정할 수 없어요.','I got a real bargain at the antique fair last weekend.','지난 주말 골동품 박람회에서 정말 싸게 잘 샀어요.','You can negotiate the price if you''re buying in bulk.','대량으로 구매한다면 가격을 협상할 수 있어요.'),
('nuc_shopping_07','receipt','invoice',NULL,'영수증 (소비자용)','청구서 (사업용)',NULL,'receipt는 결제 후 받는 영수증, invoice는 대금 청구를 위한 공식 청구서예요.','invoice는 B2B 거래에서, receipt는 소비자 쇼핑에서 써요.','B2','shopping',1,7,'receipt invoice payment document','Keep your receipt for a possible return.','반품할 수도 있으니 영수증을 보관하세요.','The vendor sent us an invoice for the order.','판매처에서 주문에 대한 청구서를 보냈어요.','Customers get a receipt at the till, but suppliers receive a formal invoice instead.','고객은 계산대에서 영수증을 받지만, 공급업체는 대신 정식 청구서를 받아요.','Always keep your receipt in case of returns.','반품에 대비해 항상 영수증을 보관하세요.','The invoice will be sent to your email after payment.','결제 후 청구서가 이메일로 발송돼요.'),
('nuc_shopping_08','browse','search',NULL,'둘러보다','검색하다',NULL,'browse는 특정 목적 없이 구경하는 것, search는 원하는 것을 찾아 탐색하는 것이에요.','"Just browsing"은 "그냥 구경 중이에요"라는 표현으로 점원에게 자주 써요.','B2','shopping',2,8,'browse search online shopping','I was just browsing the store.','저는 그냥 가게를 둘러보고 있었어요.','I searched online for the best deal.','저는 가장 좋은 조건을 찾으려고 온라인에서 검색했어요.','I''ll just browse for a while before I search for anything specific.','저는 특정한 걸 검색하기 전에 잠시 그냥 둘러볼게요.','I was just browsing — nothing in particular caught my eye.','그냥 구경 중이었어요 — 특별히 눈에 띄는 건 없었어요.','She searched online for the best price.','그녀는 최고의 가격을 찾으려 온라인에서 검색했어요.'),
('nuc_shopping_09','wholesale','retail',NULL,'도매','소매',NULL,'wholesale은 대량으로 싸게 사는 도매, retail은 소비자에게 파는 소매예요.','retail price(소비자가)는 wholesale price(도매가)보다 비싼 게 일반적이에요.','B2','shopping',1,9,'wholesale retail price trade','He buys goods wholesale and resells them.','그는 물건을 도매로 사서 되팔아요.','The retail price is twice the wholesale price.','소매가는 도매가의 두 배예요.','They buy fruit wholesale from farmers and sell it at retail in their shop.','그들은 농부에게서 과일을 도매로 사서 가게에서 소매로 팔아요.','They sell fabric wholesale to local designers.','그들은 지역 디자이너들에게 원단을 도매로 팔아요.','Retail prices vary widely between stores.','소매 가격은 매장마다 크게 달라요.'),
('nuc_shopping_10','counterfeit','fake',NULL,'위조품','가짜',NULL,'fake는 진짜가 아닌 모든 것, counterfeit는 특히 상표·화폐를 불법으로 위조한 것이에요.','counterfeit는 법적·공식 맥락, fake는 일상 구어에서 써요.','C1','shopping',1,10,'counterfeit fake brand luxury','Police seized counterfeit designer bags.','경찰이 가짜 명품 가방을 압수했어요.','That smile looks fake.','저 미소는 가식적으로 보여요.','He was fined for selling counterfeit watches online.','그는 온라인에서 가짜 시계를 판매해 벌금을 물었어요.','Authorities seized large amounts of counterfeit goods at the border.','당국은 국경에서 대량의 위조품을 압수했어요.','The reviews seemed fake, so I checked more sources.','리뷰가 가짜 같아서 더 많은 출처를 확인했어요.'),
('nuc_shopping_11','impulse','spontaneous',NULL,'충동 (소비)','자발적인',NULL,'impulse buying은 계획 없이 충동적으로 구매하는 것, spontaneous는 즉흥적이지만 부정적 뉘앙스가 없어요.','impulse는 쇼핑에서 부정적 뉘앙스, spontaneous는 즉흥적이지만 긍정적 느낌이에요.','C1','shopping',2,11,'impulse buying spontaneous decision','She made an impulse purchase at the checkout.','그녀는 계산대에서 충동구매를 했어요.','It was a spontaneous decision to go shopping.','쇼핑하러 가기로 한 건 즉흥적인 결정이었어요.','It was a spontaneous trip downtown, but the impulse buying afterward emptied my wallet.','시내로 간 건 즉흥적인 나들이였지만, 그 후의 충동구매로 지갑이 텅 비었어요.','She made an impulse purchase she later regretted.','그녀는 나중에 후회한 충동 구매를 했어요.','It was a spontaneous decision to fly somewhere warm.','따뜻한 곳으로 비행기를 타기로 한 즉흥적인 결정이었어요.'),
('nuc_shopping_12','frugal','stingy',NULL,'검소한','인색한',NULL,'frugal은 절약하는 긍정적 태도, stingy는 지나치게 아끼는 부정적 표현이에요.','frugal은 칭찬, stingy는 비판이에요 — 뉘앙스 차이가 커요.','C1','shopping',2,12,'frugal stingy saving money','She''s frugal and saves half her income.','그녀는 검소해서 수입의 절반을 저축해요.','He''s so stingy he never buys lunch for others.','그는 너무 인색해서 다른 사람에게 점심 한번 사지 않아요.','She''s frugal and shops wisely, but she''s never stingy when a friend is in need.','그녀는 검소하게 현명하게 쇼핑하지만, 친구가 어려울 때는 결코 인색하지 않아요.','She lives a frugal life and saves most of her salary.','그녀는 검소한 삶을 살며 월급의 대부분을 저축해요.','He''s known for being stingy with tips at restaurants.','그는 식당 팁에 인색한 것으로 알려져 있어요.'),
('nuc_shopping_13','consumer','customer',NULL,'소비자 (경제 주체)','고객 (특정 가게)',NULL,'customer는 특정 가게·서비스를 이용하는 사람, consumer는 경제적 의미의 소비 주체예요.','consumer rights(소비자 권리), customer service(고객 서비스)처럼 각각 관용 표현이 있어요.','C2','shopping',1,13,'consumer customer retail economics','Consumer spending rose last quarter.','지난 분기에 소비자 지출이 늘었어요.','The customer asked for a refund.','그 고객은 환불을 요청했어요.','Modern consumers care more about how products are made.','요즘 소비자들은 제품이 어떻게 만들어지는지에 더 신경 써요.','Consumers expect transparency about product ingredients.','소비자들은 제품 성분에 대한 투명성을 기대해요.','The customer asked for a recommendation from the staff.','그 고객은 직원에게 추천을 부탁했어요.'),
('nuc_sports_14','run','jog',NULL,'뛰다 (속도·강도)','조깅하다 (느린 걸음으로 뛰다)',NULL,'run은 일반적인 "뛰다" (속도 빠름), jog는 운동 목적으로 느리게 뛰는 행위.','run > jog 속도. 무릎 부담은 jog가 적어서 일상 운동으로 인기. 마라톤은 run.','A2','sports',1,0,'running jogging exercise park morning','I run sprints at the track.','저는 트랙에서 단거리 전력 질주를 해요.','I jog in the park every morning.','저는 매일 아침 공원에서 조깅을 해요.','He likes to run hard until he''s completely out of breath.','그는 완전히 숨이 찰 때까지 힘껏 달리는 걸 좋아해요.','I jog three times a week and run a marathon once a year.','일주일에 세 번 조깅하고, 일 년에 한 번 마라톤을 뛰어요.','Running burns more calories; jogging is easier on the knees.','뛰기는 칼로리 소모가 더 크고, 조깅은 무릎에 더 부담이 적어요.'),
('nuc_sports_01','match','game',NULL,'경기 (대결)','게임 / 경기 (일반)',NULL,'match는 두 팀·선수가 겨루는 경기, game은 더 넓게 경기·게임을 뜻해요.','축구·테니스에서는 match, 야구·농구에서는 game을 더 자주 써요.','B1','sports',1,1,'match game sports competition','The tennis match lasted three sets.','그 테니스 경기는 세 세트 동안 이어졌어요.','Tonight''s game is between Brazil and Korea.','오늘 밤 경기는 브라질과 한국의 대결이에요.','The final match of the tournament drew a huge crowd.','그 토너먼트의 결승전은 엄청난 관중을 끌어모았어요.','The boxing match went all twelve rounds.','권투 경기는 12라운드 끝까지 갔어요.','Tonight''s baseball game starts at seven.','오늘 밤 야구 경기는 7시에 시작해요.'),
('nuc_sports_02','win','beat',NULL,'이기다 (결과)','이기다 (상대를)',NULL,'win은 경기에서 승리하는 것, beat는 특정 상대를 이기는 것이에요.','win the game / beat the opponent처럼 목적어가 달라요.','B1','sports',2,2,'win beat victory sports','We won the championship!','우리가 우승했어요!','We beat the strongest team in the league.','우리는 리그에서 가장 강한 팀을 이겼어요.','If we win our next two games, we''ll qualify for the finals.','다음 두 경기를 이기면, 우리는 결승에 진출하게 돼요.','We won the local league for the first time.','저희가 지역 리그에서 처음으로 우승했어요.','She beat the defending champion in straight sets.','그녀는 디펜딩 챔피언을 스트레이트 세트로 이겼어요.'),
('nuc_sports_03','practice','train',NULL,'연습하다','훈련하다',NULL,'practice는 기술을 반복 연습하는 것, train은 체계적인 훈련으로 능력을 키우는 것이에요.','practice는 기술 연습, train은 체력·전략 훈련을 강조해요.','B1','sports',1,3,'practice train sports athlete','She practices free throws every morning.','그녀는 매일 아침 자유투를 연습해요.','He trains six days a week with his coach.','그는 코치와 함께 일주일에 엿새를 훈련해요.','They practice their serves together after class.','그들은 수업이 끝난 후 함께 서브를 연습해요.','I practice the piano for an hour every day.','저는 매일 한 시간씩 피아노를 연습해요.','He trains hard during the off-season to stay in shape.','그는 비시즌에 컨디션 유지를 위해 열심히 훈련해요.'),
('nuc_sports_04','score','point',NULL,'점수를 내다 / 점수','포인트 (단위)',NULL,'score는 득점 행위나 점수 전체, point는 개별 점수 단위예요.','score a goal(골 넣다), earn points(점수 얻다)처럼 써요.','B1','sports',2,4,'score point game sports','She scored twice in the second half.','그녀는 후반전에 두 골을 넣었어요.','You need 21 points to win this set.','이 세트를 이기려면 21점이 필요해요.','The home team scored just before the final whistle.','홈 팀이 경기 종료 휘슬 직전에 득점했어요.','She scored the winning goal in the last minute.','그녀는 마지막 1분에 결승 골을 넣었어요.','A perfect game in bowling is 300 points.','볼링에서 퍼펙트 게임은 300점이에요.'),
('nuc_sports_05','foul','penalty',NULL,'반칙','패널티 / 벌칙',NULL,'foul은 규칙을 어기는 반칙 행위, penalty는 그에 따른 벌칙이에요.','foul이 원인, penalty가 결과예요.','B2','sports',1,5,'foul penalty referee sports rules','The referee called a foul on the defender.','심판이 수비수에게 파울을 선언했어요.','The team was awarded a penalty kick.','그 팀에게 페널티킥이 주어졌어요.','His reckless foul earned him a yellow card.','그의 무모한 파울로 인해 옐로카드를 받았어요.','The referee called a foul on the goalkeeper.','심판이 골키퍼에게 반칙을 선언했어요.','They were given a penalty after the late tackle.','늦은 태클 후 그들은 페널티를 받았어요.'),
('nuc_sports_06','coach','trainer',NULL,'코치 (전략)','트레이너 (체력)',NULL,'coach는 팀 전술·전략을 이끄는 감독·코치, trainer는 체력·부상 관리를 담당하는 사람이에요.','head coach는 경기 전략, personal trainer는 체력 훈련을 담당해요.','B2','sports',2,6,'coach trainer sports team management','The head coach changed the team''s formation.','수석 코치가 팀의 포메이션을 바꿨어요.','The trainer helped the player recover from injury.','트레이너가 그 선수의 부상 회복을 도왔어요.','The coach studied hours of footage to plan the next match.','그 코치는 다음 경기를 준비하려고 몇 시간 분량의 영상을 분석했어요.','The coach motivated the players with a powerful speech.','코치는 강력한 연설로 선수들에게 동기를 부여했어요.','Her personal trainer designed a recovery program after the injury.','그녀의 개인 트레이너가 부상 후 회복 프로그램을 짜줬어요.'),
('nuc_sports_07','amateur','professional',NULL,'아마추어','프로 / 전문가',NULL,'amateur는 취미로 하는 것, professional은 돈을 받고 직업으로 하는 것이에요.','amateur spirit(스포츠 정신), professional athlete(직업 선수)로 구분해요.','B2','sports',1,7,'amateur professional athlete sports career','She plays tennis as an amateur.','그녀는 아마추어로 테니스를 쳐요.','He signed a professional contract at age 18.','그는 18세에 프로 계약을 맺었어요.','Many amateur athletes compete purely for the love of the sport.','많은 아마추어 선수들이 순전히 스포츠에 대한 사랑으로 경쟁해요.','He started boxing as an amateur in his teens.','그는 십대 때 아마추어로 권투를 시작했어요.','She turned professional after winning the national title.','그녀는 전국 타이틀을 따낸 후 프로로 전향했어요.'),
('nuc_sports_08','stamina','endurance',NULL,'체력 / 지구력','인내력 / 지속력',NULL,'stamina는 오랫동안 활동할 수 있는 신체 능력, endurance는 고통이나 어려움을 견디는 것이에요.','stamina는 신체 에너지, endurance는 고통을 견디는 정신·신체적 능력이에요.','B2','sports',2,8,'stamina endurance fitness athlete','Marathon runners need incredible stamina.','마라톤 선수들은 엄청난 지구력이 필요해요.','Rock climbing tests your strength and endurance.','암벽 등반은 당신의 힘과 지구력을 시험해요.','Cyclists need both stamina and strong legs to climb steep hills.','사이클 선수들은 가파른 언덕을 오르려면 지구력과 튼튼한 다리가 모두 필요해요.','Long-distance runners build stamina over many months.','장거리 주자들은 몇 달에 걸쳐 체력을 쌓아요.','Endurance training helps her finish strong races.','지구력 훈련이 그녀가 어려운 경주를 끝까지 마치는 데 도움이 돼요.'),
('nuc_sports_09','champion','winner',NULL,'챔피언 (대회 우승)','승자 (경기 승리)',NULL,'winner는 한 경기에서 이긴 사람, champion은 전체 대회·시즌을 제패한 사람이에요.','winner는 단판 승리, champion은 전체 우승을 뜻해요.','B2','sports',1,9,'champion winner trophy sports','She is the current world champion.','그녀는 현 세계 챔피언이에요.','The winner of today''s match advances to the final.','오늘 경기의 승자가 결승에 진출해요.','After winning three titles, she''s regarded as a true champion.','세 개의 타이틀을 차지한 후, 그녀는 진정한 챔피언으로 여겨져요.','He is the reigning world champion in chess.','그는 체스의 현 세계 챔피언이에요.','The winner of the local race got a small trophy.','지역 경주의 승자는 작은 트로피를 받았어요.'),
('nuc_sports_10','spectator','fan',NULL,'관중 / 관람객','팬 / 열성 응원자',NULL,'spectator는 경기를 관람하는 사람, fan은 특정 팀·선수를 열정적으로 응원하는 사람이에요.','spectator는 중립적 관람, fan은 지지하는 팀이 있는 응원자예요.','B2','sports',2,10,'spectator fan stadium audience sports','Spectators filled the stadium.','관중들이 경기장을 가득 채웠어요.','Fans stayed until the final whistle.','팬들은 마지막 휘슬이 울릴 때까지 남아 있었어요.','A few curious spectators paused to watch the street game.','호기심 많은 몇몇 구경꾼이 길거리 경기를 보려고 걸음을 멈췄어요.','Thousands of spectators cheered from the stands.','수천 명의 관중이 관중석에서 응원했어요.','She''s been a loyal fan since she was a child.','그녀는 어렸을 때부터 충성스러운 팬이었어요.'),
('nuc_sports_11','sportsmanship','gamesmanship',NULL,'스포츠맨십 (공정)','게임즈맨십 (심리전)',NULL,'sportsmanship은 공정하고 존중하는 태도, gamesmanship은 규칙 내에서 상대를 심리적으로 흔드는 전술이에요.','sportsmanship은 긍정적 가치, gamesmanship은 윤리적으로 논란이 있을 수 있어요.','C1','sports',1,11,'sportsmanship gamesmanship fair play ethics','He showed excellent sportsmanship by comforting the opponent.','그는 상대 선수를 위로하며 훌륭한 스포츠맨십을 보여 줬어요.','Some players use gamesmanship to distract rivals.','일부 선수들은 상대를 방해하려고 심리전을 써요.','True sportsmanship means congratulating the team that beat you.','진정한 스포츠맨십은 자신을 이긴 팀을 축하해 주는 거예요.','Real sportsmanship means winning and losing with grace.','진정한 스포츠맨십은 우아하게 이기고 지는 것을 의미해요.','Some athletes use gamesmanship to gain a psychological edge.','어떤 선수들은 심리적 우위를 얻기 위해 게임즈맨십을 사용해요.'),
('nuc_sports_12','doping','performance enhancement',NULL,'도핑 (금지 약물)','경기력 향상 (포괄)',NULL,'doping은 금지 약물을 사용하는 것, performance enhancement는 합법·불법 방법 모두를 포함해요.','doping은 불법, altitude training·nutrition은 합법적 performance enhancement예요.','C1','sports',2,12,'doping performance sports ethics drug','The athlete was disqualified for doping.','그 선수는 도핑으로 실격됐어요.','Altitude training is a legal method of performance enhancement.','고지대 훈련은 합법적인 경기력 향상 방법이에요.','Anti-doping agencies test athletes randomly throughout the season.','도핑 방지 기구는 시즌 내내 선수들을 무작위로 검사해요.','The runner was banned after testing positive for doping.','그 주자는 도핑 양성 판정 후 출전 정지를 받았어요.','Good nutrition is a key form of performance enhancement.','좋은 영양 섭취는 경기력 향상의 핵심 방법이에요.'),
('nuc_sports_13','kinesthesia','proprioception',NULL,'운동 감각','고유 감각',NULL,'kinesthesia는 움직임을 인식하는 감각, proprioception은 몸의 위치·균형을 감지하는 감각이에요.','운동 훈련에서 둘 다 중요하지만, proprioception이 부상 예방에 특히 강조돼요.','C2','sports',1,13,'kinesthesia proprioception movement athlete','Dancers rely on kinesthesia to move fluidly.','무용수는 유연하게 움직이기 위해 운동감각에 의존해요.','Athletes train proprioception to prevent ankle injuries.','운동선수는 발목 부상을 막기 위해 고유 수용 감각을 훈련해요.','A keen sense of kinesthesia lets gymnasts judge each twist in midair.','예민한 운동감각 덕분에 체조 선수는 공중에서 각 회전을 가늠할 수 있어요.','Dancers develop kinesthesia through years of training.','무용수들은 몇 년의 훈련을 통해 운동 감각을 개발해요.','Good proprioception helps athletes stay balanced.','좋은 고유 감각은 운동선수들이 균형을 유지하는 데 도움이 돼요.'),
('nuc_technology_14','click','tap',NULL,'클릭하다 (마우스)','탭하다 (터치 화면)',NULL,'click은 마우스로 누르는 동작, tap은 터치 화면을 손가락으로 누르는 동작.','click은 마우스·트랙패드, tap은 터치 화면. 더블 클릭 = double-click, 두 번 탭 = double-tap.','A2','technology',1,0,'phone tap click finger screen mouse','Click the link to continue.','계속하려면 링크를 클릭하세요.','Tap the icon to open the app.','앱을 열려면 아이콘을 누르세요.','Just click ''Save'' before you close the document.','문서를 닫기 전에 ''저장''을 꼭 클릭하세요.','On a computer, click; on a phone, tap.','컴퓨터에서는 클릭하고, 휴대폰에서는 탭하세요.','I clicked the button and then tapped Send on my phone.','버튼을 클릭한 다음 휴대폰에서 보내기를 탭했어요.'),
('nuc_technology_01','hardware','software',NULL,'하드웨어','소프트웨어',NULL,'hardware는 컴퓨터의 물리적 부품, software는 프로그램·운영체제 등 논리적 구성이에요.','hardware는 만질 수 있는 것, software는 만질 수 없는 프로그램이에요.','B1','technology',1,1,'hardware software computer technology','We need to upgrade the hardware to run this program.','이 프로그램을 돌리려면 하드웨어를 업그레이드해야 해요.','The software was updated to fix bugs.','버그를 고치기 위해 소프트웨어가 업데이트되었어요.','Without the right hardware, even great software runs slowly.','적절한 하드웨어가 없으면 좋은 소프트웨어도 느리게 돌아가요.','New hardware was needed to run the simulation.','시뮬레이션 실행에 새 하드웨어가 필요했어요.','The software runs smoothly on most devices.','그 소프트웨어는 대부분의 기기에서 부드럽게 작동해요.'),
('nuc_technology_02','upload','download',NULL,'업로드 (올리기)','다운로드 (내려받기)',NULL,'upload는 기기에서 서버·클라우드로 파일을 올리는 것, download는 서버에서 기기로 내려받는 것이에요.','upload(서버로 올리기) ↔ download(서버에서 받기)로 방향이 반대예요.','B1','technology',2,2,'upload download cloud internet','Upload your photo to the cloud.','당신의 사진을 클라우드에 업로드하세요.','Download the app from the store.','스토어에서 그 앱을 다운로드하세요.','It took ages to upload the high-resolution video to the server.','고해상도 영상을 서버에 업로드하는 데 한참 걸렸어요.','Upload your file before the deadline at midnight.','자정 마감 전에 파일을 업로드하세요.','I''ll download the report and read it offline.','저는 보고서를 다운로드해서 오프라인에서 읽을게요.'),
('nuc_technology_03','update','upgrade',NULL,'업데이트 (보완)','업그레이드 (향상)',NULL,'update는 버그 수정·보안 패치, upgrade는 새 기능 추가나 더 나은 버전으로 올라가는 것이에요.','update는 같은 버전 내 수정, upgrade는 더 높은 버전·등급으로 이동이에요.','B1','technology',1,3,'update upgrade version software','Please update your browser for security.','보안을 위해 브라우저를 업데이트해 주세요.','She upgraded her phone to the latest model.','그녀는 휴대폰을 최신 모델로 업그레이드했어요.','The latest update fixed the crashing problem on older phones.','최신 업데이트가 구형 휴대폰의 충돌 문제를 해결했어요.','I update my password every six months.','저는 6개월마다 비밀번호를 업데이트해요.','It''s time to upgrade my laptop — this one is too slow.','이제 노트북을 업그레이드할 때예요 — 이건 너무 느려요.'),
('nuc_technology_04','connect','sync',NULL,'연결하다','동기화하다',NULL,'connect는 기기나 네트워크를 연결하는 것, sync는 데이터를 여러 기기에서 일치시키는 것이에요.','sync는 데이터를 최신 상태로 일치시키는 것, connect는 물리·무선 연결이에요.','B2','technology',2,4,'connect sync device data cloud','Connect your phone to the Wi-Fi.','휴대폰을 와이파이에 연결하세요.','Sync your contacts across all devices.','모든 기기에서 연락처를 동기화하세요.','You first need to connect to the network before logging in.','로그인하기 전에 먼저 네트워크에 연결해야 해요.','Connect your headphones via Bluetooth.','블루투스로 헤드폰을 연결하세요.','My calendar syncs automatically across all devices.','제 캘린더는 모든 기기에서 자동으로 동기화돼요.'),
('nuc_technology_05','privacy','security',NULL,'개인 정보 보호','보안',NULL,'privacy는 개인 정보의 통제권, security는 외부 공격·침해로부터 데이터를 지키는 것이에요.','privacy는 어떤 정보를 공유하느냐, security는 어떻게 보호하느냐예요.','B2','technology',1,5,'privacy security data protection','Read the app''s privacy policy before signing up.','가입하기 전에 그 앱의 개인정보 처리방침을 읽으세요.','Enable two-factor authentication for better security.','더 나은 보안을 위해 이중 인증을 활성화하세요.','Many users worry about their privacy when apps track location.','많은 사용자가 앱이 위치를 추적할 때 개인정보를 걱정해요.','Privacy concerns are growing as more devices collect data.','더 많은 기기가 데이터를 수집하면서 개인 정보 보호 우려가 커지고 있어요.','Strong security keeps user accounts safe from hackers.','강력한 보안이 사용자 계정을 해커로부터 안전하게 지켜요.'),
('nuc_technology_06','algorithm','code',NULL,'알고리즘','코드',NULL,'algorithm은 문제 해결의 논리적 절차, code는 그것을 컴퓨터가 이해하도록 작성한 프로그램이에요.','algorithm은 아이디어·절차, code는 그 아이디어를 구현한 것이에요.','B2','technology',2,6,'algorithm code programming technology','The recommendation algorithm suggests content you might like.','추천 알고리즘은 당신이 좋아할 만한 콘텐츠를 제안해요.','She wrote the code in Python.','그녀는 파이썬으로 그 코드를 작성했어요.','A good sorting algorithm can handle millions of records quickly.','좋은 정렬 알고리즘은 수백만 건의 기록을 빠르게 처리할 수 있어요.','The algorithm decides what posts you see on social media.','알고리즘이 당신이 소셜 미디어에서 어떤 게시물을 볼지 결정해요.','She learned to write code in just three months.','그녀는 단 3개월 만에 코드를 작성하는 법을 배웠어요.'),
('nuc_technology_07','bug','glitch',NULL,'버그 (오류)','글리치 (일시적 오작동)',NULL,'bug는 코드 오류로 생긴 지속적 문제, glitch는 일시적이고 짧은 오작동이에요.','bug는 수정이 필요한 오류, glitch는 곧 사라지는 일시적 문제예요.','B2','technology',1,7,'bug glitch error software','The developer fixed the bug in the app.','그 개발자가 앱의 버그를 고쳤어요.','The video call had a brief glitch.','영상 통화에 잠깐 오류가 있었어요.','A tiny bug in the code caused the whole app to freeze.','코드의 작은 버그 하나가 앱 전체를 멈추게 했어요.','Developers fixed a major bug in the latest patch.','개발자들이 최신 패치에서 주요 버그를 수정했어요.','The system had a small glitch during the live stream.','시스템이 라이브 스트리밍 중에 작은 글리치가 있었어요.'),
('nuc_technology_08','artificial intelligence','machine learning',NULL,'인공지능 (AI)','머신러닝',NULL,'AI는 인간 지능을 모방하는 기술 전반, machine learning은 AI의 한 분야로 데이터로 스스로 학습해요.','machine learning은 AI의 하위 개념이에요: AI ⊃ ML ⊃ deep learning.','B2','technology',2,8,'artificial intelligence machine learning AI','AI is transforming many industries.','AI는 많은 산업을 변화시키고 있어요.','Machine learning powers image recognition systems.','머신러닝은 이미지 인식 시스템을 작동시켜요.','Many people use artificial intelligence without even realizing it.','많은 사람들이 자신도 모르게 인공지능을 사용해요.','Artificial intelligence is now part of everyday apps.','인공지능은 이제 일상 앱의 일부예요.','Machine learning helps doctors detect early signs of disease.','머신러닝은 의사들이 질병의 초기 징후를 발견하는 데 도움이 돼요.'),
('nuc_technology_09','encrypt','compress',NULL,'암호화하다','압축하다',NULL,'encrypt는 데이터를 코드로 변환해 보호하는 것, compress는 파일 크기를 줄이는 것이에요.','encrypt는 보안 목적, compress는 저장·전송 효율 목적이에요.','C1','technology',1,9,'encrypt compress data security file','All messages are end-to-end encrypted.','모든 메시지는 종단 간 암호화돼요.','Compress the video file before sending.','보내기 전에 영상 파일을 압축하세요.','Banks encrypt your data to keep it safe from hackers.','은행은 해커로부터 데이터를 안전하게 지키기 위해 당신의 정보를 암호화해요.','Most messaging apps now encrypt messages by default.','대부분의 메시지 앱이 이제 기본적으로 메시지를 암호화해요.','You can compress a folder before sharing it by email.','이메일로 공유하기 전에 폴더를 압축할 수 있어요.'),
('nuc_technology_10','server','cloud',NULL,'서버 (물리적)','클라우드 (인터넷 기반)',NULL,'server는 실제 물리적 컴퓨터, cloud는 인터넷을 통해 접근하는 분산 서버 네트워크예요.','cloud computing은 인터넷을 통해 서버 자원을 빌려 쓰는 것이에요.','C1','technology',2,10,'server cloud computing storage','The company runs its own servers on-site.','그 회사는 자체 서버를 사내에서 운영해요.','We moved all data to the cloud last year.','저희는 작년에 모든 데이터를 클라우드로 옮겼어요.','When the server crashed, the entire website went offline.','서버가 다운되었을 때 웹사이트 전체가 오프라인이 되었어요.','The new server can handle thousands of users at once.','새 서버는 한 번에 수천 명의 사용자를 처리할 수 있어요.','Storing files in the cloud lets you access them anywhere.','클라우드에 파일을 저장하면 어디서나 접근할 수 있어요.'),
('nuc_technology_11','latency','bandwidth',NULL,'지연 시간','대역폭 (전송 용량)',NULL,'latency는 데이터 전송의 지연 시간, bandwidth는 한 번에 전송할 수 있는 데이터의 양이에요.','latency는 속도(빠름/느림), bandwidth는 용량(많음/적음)이에요.','C1','technology',1,11,'latency bandwidth network internet speed','High latency causes lag in online games.','높은 지연 시간은 온라인 게임에서 렉을 유발해요.','Streaming 4K requires high bandwidth.','4K 스트리밍에는 높은 대역폭이 필요해요.','Even a small increase in latency can ruin a video call.','지연 시간이 조금만 늘어나도 영상 통화를 망칠 수 있어요.','Low latency is essential for fast-paced online games.','빠른 온라인 게임에는 낮은 지연 시간이 필수예요.','You need enough bandwidth to stream 4K video smoothly.','4K 영상을 부드럽게 스트리밍하려면 충분한 대역폭이 필요해요.'),
('nuc_technology_12','open source','proprietary',NULL,'오픈소스','독점 소프트웨어',NULL,'open source는 소스코드가 공개돼 누구나 수정 가능한 것, proprietary는 특정 회사가 소유·통제하는 것이에요.','open source는 커뮤니티 기반, proprietary는 라이선스 구매가 필요해요.','C2','technology',1,12,'open source proprietary software development','Linux is a popular open source operating system.','리눅스는 인기 있는 오픈 소스 운영 체제예요.','Microsoft Windows is proprietary software.','마이크로소프트 윈도우는 독점 소프트웨어예요.','Companies sometimes release open source tools to attract developers.','기업들은 때때로 개발자를 끌어들이기 위해 오픈 소스 도구를 공개해요.','Many developers contribute to open source projects.','많은 개발자들이 오픈소스 프로젝트에 기여해요.','Proprietary software often comes with strict licensing.','독점 소프트웨어는 종종 엄격한 라이선스가 붙어요.'),
('nuc_technology_13','interoperability','scalability',NULL,'상호운용성','확장성',NULL,'interoperability는 서로 다른 시스템이 함께 작동하는 능력, scalability는 규모가 커져도 성능을 유지하는 능력이에요.','interoperability는 시스템 호환성, scalability는 성장에 따른 안정성이에요.','C2','technology',2,13,'interoperability scalability system design','Interoperability between platforms is essential for digital health.','플랫폼 간의 상호 운용성은 디지털 헬스에 필수적이에요.','The app was built for scalability to handle millions of users.','그 앱은 수백만 명의 사용자를 처리할 수 있도록 확장성을 고려해 설계됐어요.','Poor interoperability forces staff to re-enter the same data twice.','상호 운용성이 떨어지면 직원들은 같은 데이터를 두 번 다시 입력해야 해요.','Interoperability between systems saves users a lot of time.','시스템 간 상호운용성은 사용자에게 많은 시간을 절약해 줘요.','Scalability matters when your user base grows quickly.','사용자가 빠르게 늘면 확장성이 중요해져요.'),
('nuc_transport_14','bring','take',NULL,'가져오다 (이쪽으로)','가져가다 (저쪽으로)',NULL,'bring은 화자/청자가 있는 곳으로 가져오는 것, take는 다른 곳으로 가져가는 것. 방향이 핵심.','bring은 화자·청자 쪽으로, take는 다른 곳으로. 헷갈리면 "to here = bring, away = take"로 기억.','A2','transport',1,0,'bringing taking direction moving carrying','Bring your umbrella to the party.','파티에 우산을 가져오세요.','Take your umbrella when you leave.','나갈 때 우산을 챙기세요.','Don''t forget to bring your passport to the airport.','공항에 여권 가져오는 걸 잊지 마세요.','Please bring me the book; I''ll take it to the library.','저에게 책을 가져다 주세요; 제가 도서관에 가져갈게요.','Bring snacks to my place; take leftovers home.','우리 집에 간식 가져오세요; 남은 음식은 집에 가져가세요.'),
('nuc_transport_15','arrive','reach',NULL,'도착하다 (장소)','도달하다 (목표·장소)',NULL,'arrive는 일반적 "도착", reach는 (특히 노력 후) "도달했다"는 성취 느낌이 있어요.','arrive는 "도착" 자체, reach는 "닿다·도달"의 뉘앙스. arrive at(작은 곳)/in(큰 곳), reach는 전치사 없이 reach + 목적어.','A2','transport',1,0,'arrival airport destination journey ending','We arrived at the airport at 6.','우리는 6시에 공항에 도착했어요.','It took hours to reach the summit.','정상에 도달하는 데 몇 시간이 걸렸어요.','What time does the train arrive at the central station?','그 기차는 몇 시에 중앙역에 도착하나요?','They arrived in the city safely and reached their hotel by 8.','그들은 도시에 무사히 도착했고 8시까지 호텔에 도달했어요.','I arrived at the meeting; we reached an agreement.','회의에 도착했고, 합의에 도달했어요.'),
('nuc_transport_01','ride','drive',NULL,'(타다) 승객으로','운전하다',NULL,'ride는 버스·택시 등을 타는 것(승객), drive는 직접 운전하는 것이에요.','ride a bus/taxi (타다), drive a car (운전하다)처럼 구분해요.','B1','transport',1,1,'ride drive car bus transport','I''ll take a ride to the station.','역까지 차를 타고 갈게요.','She drives to work every day.','그녀는 매일 차로 출근해요.','I''d rather ride the train into the city than drive through all that traffic.','그 모든 교통 체증을 뚫고 운전하느니 기차를 타고 도심으로 가는 게 나아요.','I ride my bike to school every day.','저는 매일 자전거를 타고 학교에 가요.','She drives a small electric car for her commute.','그녀는 작은 전기차로 출퇴근해요.'),
('nuc_transport_02','on time','in time',NULL,'정시에','시간 안에',NULL,'"on time"은 약속된 시간에 정확히, "in time"은 마감 시간 내에 (여유 있게) 도착하는 것이에요.','"on time" = 정시 도착, "in time" = 늦지 않게 도착 (차이 기억!))','B1','transport',1,2,'on time in time schedule transport','The train arrived on time.','기차가 정시에 도착했어요.','We got there just in time to board.','우리는 탑승하기에 딱 맞춰 도착했어요.','The meeting started right on time, but luckily I arrived just in time to catch the introductions.','회의는 정시에 시작했지만, 다행히 저는 소개 부분에 딱 맞춰 도착했어요.','The bus is rarely on time during rush hour.','버스는 출퇴근 시간에 거의 정시에 오지 않아요.','I made it in time for the last train home.','저는 마지막 귀가 기차를 놓치지 않게 도착했어요.'),
('nuc_transport_03','ticket','pass',NULL,'표 (1회용)','패스 (정기·다회)',NULL,'ticket은 1회 또는 특정 승차용, pass는 기간·횟수 무제한 이용권이에요.','single ticket(1회권), return ticket(왕복권), season pass(정기권)을 구분해요.','B1','transport',2,3,'ticket pass transit bus train','I bought a one-way ticket to Busan.','저는 부산행 편도 티켓을 샀어요.','I use a monthly bus pass.','저는 월간 버스 정기권을 사용해요.','A single ticket is fine for one trip, but a weekly pass is cheaper if you travel daily.','한 번만 이동할 때는 1회권이면 되지만, 매일 다닌다면 주간 정기권이 더 저렴해요.','I lost my ticket somewhere on the platform.','저는 플랫폼 어디선가 표를 잃어버렸어요.','A monthly pass saves a lot of money if you ride daily.','매일 타신다면 월 정기권이 돈을 많이 절약해 줘요.'),
('nuc_transport_04','delay','cancel',NULL,'지연','취소',NULL,'delay는 예정 시간보다 늦는 것, cancel은 완전히 취소하는 것이에요.','공항에서 delayed와 cancelled를 모니터로 꼭 확인해야 해요.','B1','transport',2,4,'delay cancel flight train schedule','The flight was delayed by two hours.','항공편이 두 시간 지연됐어요.','The service was cancelled due to the storm.','폭풍 때문에 운행이 취소됐어요.','At first the train was only delayed, but eventually they had to cancel it altogether.','처음에는 기차가 지연되기만 했지만, 결국 완전히 취소해야 했어요.','Our flight was delayed by an hour due to weather.','저희 비행기가 날씨로 한 시간 지연됐어요.','They had to cancel the trip because of the typhoon.','태풍 때문에 그들은 여행을 취소해야 했어요.'),
('nuc_transport_05','fare','toll',NULL,'운임 (교통)','통행료 (도로)',NULL,'fare는 버스·지하철·택시 요금, toll은 고속도로·교량 통행료예요.','fare는 대중교통, toll은 도로 이용요금에 써요.','B2','transport',1,5,'fare toll transportation fee road','The bus fare is 1,500 won.','버스 요금은 1,500원이에요.','There''s a toll on this highway.','이 고속도로에는 통행료가 있어요.','You can pay the train fare with a contactless card.','기차 요금은 비접촉식 카드로 결제할 수 있어요.','The bus fare has gone up by 20% this year.','버스 요금이 올해 20% 올랐어요.','There''s a toll booth just before the bridge.','다리 직전에 통행료 부스가 있어요.'),
('nuc_transport_06','transfer','transit',NULL,'환승하다','통과 / 경유',NULL,'transfer는 다른 노선·교통수단으로 갈아타는 것, transit는 목적지로 가는 중간 경유를 뜻해요.','in transit는 경유 중이라는 뜻, transit visa는 경유 비자예요.','B2','transport',1,6,'transfer transit connection hub','Transfer to Line 2 at Hongik station.','홍익역에서 2호선으로 갈아타세요.','We have a two-hour transit in Singapore.','싱가포르에서 두 시간 경유해요.','During our transit through Tokyo, we had to transfer to a different airline.','도쿄를 경유하는 동안 다른 항공사로 갈아타야 했어요.','You can transfer to the green line at the next stop.','다음 정류장에서 녹색 노선으로 환승할 수 있어요.','We''re in transit and our luggage is on the next plane.','저희는 경유 중이고 짐은 다음 비행기에 있어요.'),
('nuc_transport_07','board','embark',NULL,'탑승하다 (일반)','탑승하다 (격식)',NULL,'board는 일상적으로 비행기·배·버스에 탑승하는 것, embark는 좀 더 격식 있거나 항해 시작 뉘앙스예요.','공항 안내방송에서는 board, 문학·격식 글에서는 embark를 자주 써요.','B2','transport',2,7,'board embark flight ship departure','Passengers, please board through gate 3.','승객 여러분, 3번 게이트로 탑승해 주세요.','The ship was about to embark on a long voyage.','그 배는 긴 항해를 막 시작하려던 참이었어요.','Tourists simply board the ferry, while the explorers prepared to embark on their expedition.','관광객들은 그저 페리에 탑승하지만, 탐험가들은 원정을 떠날 준비를 했어요.','Passengers will begin to board in five minutes.','승객들은 5분 안에 탑승을 시작합니다.','The crew prepared to embark on the long voyage.','승무원들은 긴 항해를 떠날 준비를 했어요.'),
('nuc_transport_08','traffic','congestion',NULL,'교통 (흐름)','교통 체증',NULL,'traffic은 도로의 차량 흐름 전반, congestion은 막혀서 정체된 상태를 뜻해요.','traffic jam / heavy traffic / congestion 모두 막힌 교통을 뜻해요.','B2','transport',2,8,'traffic congestion road delay','The traffic was heavy this morning.','오늘 아침엔 교통이 혼잡했어요.','Road congestion caused a two-hour delay.','도로 정체로 두 시간 지연됐어요.','The traffic flows smoothly at dawn, but severe congestion builds up by eight o''clock.','새벽에는 차들이 잘 흐르지만, 여덟 시쯤이면 심한 정체가 생겨요.','There''s always heavy traffic in the city centre after five.','시내 중심부에는 5시 이후 항상 교통량이 많아요.','Congestion charges are common in many large cities now.','많은 대도시에서 이제 혼잡 통행료가 흔해요.'),
('nuc_transport_09','commute','travel',NULL,'통근하다','여행하다',NULL,'commute는 매일 집과 직장을 오가는 것, travel은 목적지로 이동하는 더 넓은 개념이에요.','commute는 반복적 일상 이동, travel은 새로운 장소로의 이동이에요.','B2','transport',1,9,'commute travel daily work journey','She commutes two hours each way.','그녀는 편도로 두 시간씩 통근해요.','He travels to different countries for work.','그는 업무 때문에 여러 나라를 다녀요.','I commute to the office on weekdays and travel abroad whenever I get a long holiday.','저는 평일에는 사무실로 통근하고, 긴 휴가가 생길 때마다 해외로 여행을 가요.','Her daily commute takes about an hour each way.','그녀의 매일 통근은 편도 약 한 시간이 걸려요.','They travel to a different city every weekend.','그들은 매 주말 다른 도시로 여행해요.'),
('nuc_transport_10','detour','shortcut',NULL,'우회로','지름길',NULL,'detour는 원래 경로를 피해 돌아가는 길, shortcut은 더 빨리 가는 지름길이에요.','detour는 어쩔 수 없이 돌아가는 것, shortcut은 의도적으로 빠르게 가는 것이에요.','B2','transport',2,10,'detour shortcut route road','We took a detour due to road works.','도로 공사 때문에 우회했어요.','I know a shortcut through the park.','저는 공원을 가로지르는 지름길을 알아요.','Instead of the usual detour around the river, the locals take a hidden shortcut through the woods.','현지인들은 강을 도는 평소의 우회로 대신, 숲을 가로지르는 숨겨진 지름길로 가요.','We had to take a long detour because of the closure.','폐쇄로 우리는 긴 우회로를 가야 했어요.','She always takes a shortcut through the back streets.','그녀는 항상 뒷길로 지름길을 가요.'),
('nuc_transport_11','itinerary','schedule',NULL,'여행 일정표','일정 / 스케줄',NULL,'itinerary는 여행 경로와 일정이 담긴 계획서, schedule은 더 넓은 일정표예요.','itinerary는 여행에 특화된 표현, schedule은 모든 종류의 일정에 써요.','C1','transport',1,11,'itinerary schedule travel plan','The tour operator sent us a detailed itinerary.','여행사에서 우리에게 상세한 일정표를 보내 줬어요.','What''s the bus schedule on Sundays?','일요일 버스 시간표가 어떻게 되나요?','We changed the itinerary to spend an extra day in Rome.','우리는 로마에서 하루 더 머물기 위해 일정을 변경했어요.','Our travel agent sent us a beautifully detailed itinerary.','여행사가 아름답게 자세한 일정표를 보내줬어요.','The bus schedule is posted at every stop.','버스 시간표가 모든 정류장에 게시되어 있어요.'),
('nuc_transport_12','hail','flag down',NULL,'(택시를) 손짓으로 부르다','(차를) 손을 흔들어 세우다',NULL,'"hail a cab"은 도로에서 택시를 부르는 표현, "flag down"은 손을 흔들어 차를 세우는 표현이에요.','"hail a cab"은 뉴욕 영어에서 특히 자주 쓰여요.','C1','transport',2,12,'taxi hail flag street transport','She tried to hail a taxi in the rain.','그녀는 빗속에서 택시를 잡으려 했어요.','He flagged down a passing bus.','그는 지나가는 버스를 세웠어요.','In the city center, it''s still common to hail a cab from the curb.','도심에서는 길가에서 택시를 잡는 것이 여전히 흔해요.','It took twenty minutes to hail a taxi during the storm.','폭풍 동안 택시를 잡는 데 20분이 걸렸어요.','He flagged down a bus that wasn''t on his usual line.','그는 평소 노선이 아닌 버스를 손짓으로 세웠어요.'),
('nuc_transport_13','infrastructure','logistics',NULL,'(교통) 인프라','물류',NULL,'infrastructure는 도로·철도 등 기반 시설, logistics는 사람과 화물의 이동 계획·관리예요.','infrastructure는 하드웨어(시설), logistics는 소프트웨어(운영·계획)에 가까워요.','C2','transport',1,13,'infrastructure logistics transport network','The country is investing in transport infrastructure.','그 나라는 교통 기반 시설에 투자하고 있어요.','Efficient logistics reduced delivery times.','효율적인 물류로 배송 시간이 줄었어요.','Better road infrastructure alone won''t help unless the company''s logistics improve too.','회사의 물류도 개선되지 않으면 도로 기반 시설을 좋게 해도 소용없어요.','The city is upgrading its transport infrastructure.','도시가 교통 인프라를 업그레이드하고 있어요.','Strong logistics make next-day delivery possible.','강력한 물류 시스템 덕분에 익일 배송이 가능해요.'),
('nuc_travel_14','pack','prepare',NULL,'짐을 싸다','준비하다 (일반)',NULL,'pack은 짐(가방)을 싸는 행위에 한정, prepare는 일반적인 모든 준비.','pack은 짐 싸기에 한정, prepare는 광범위 (정신적·물리적 준비 모두). 식사 준비는 prepare a meal.','A2','travel',1,0,'packing suitcase luggage preparing trip','I need to pack for my trip.','저는 여행 짐을 싸야 해요.','I need to prepare for my trip.','저는 여행을 준비해야 해요.','Remember to pack a warm jacket for the mountains.','산에 갈 때 따뜻한 재킷을 꼭 챙기세요.','First prepare a list, then pack accordingly.','먼저 목록을 준비하고, 그에 맞춰 짐을 싸세요.','She prepared snacks and packed them in her bag.','그녀는 간식을 준비하고 가방에 짐을 쌌어요.'),
('nuc_travel_01','trip','journey','voyage','여행 (짧은)','여행 (과정)','항해','trip은 짧은 여행, journey는 시간이 걸리는 이동 과정, voyage는 배로 하는 긴 항해예요.','trip은 목적지, journey는 이동 과정, voyage는 바다 여행에 초점을 둬요.','B1','travel',1,1,'trip journey voyage travel','We took a short trip to Jeju.','우리는 제주로 짧은 여행을 다녀왔어요.','The journey from Seoul to London takes 12 hours.','서울에서 런던까지 가는 데 12시간이 걸려요.','The ship set sail on a 90-day voyage.','그 배는 90일간의 항해를 떠났어요.','We''re taking a short trip to the countryside this weekend.','이번 주말 시골로 짧은 여행을 가요.','The long journey home felt even longer in traffic.','집에 가는 긴 여정은 교통 체증 속에서 더 길게 느껴졌어요.'),
('nuc_travel_02','luggage','baggage',NULL,'수하물 (영국)','수하물 (미국)',NULL,'luggage는 영국 영어에서, baggage는 미국 영어에서 더 자주 쓰지만 둘 다 짐을 뜻해요.','공항 표지판에서는 baggage claim(수하물 찾는 곳)이 일반적으로 쓰여요.','B1','travel',1,2,'luggage baggage airport suitcase','Please keep your luggage with you at all times.','항상 짐을 몸에 지니고 계세요.','Check your baggage at the counter.','카운터에서 수하물을 맡기세요.','In British English you''d label your luggage, while Americans would tag their baggage.','영국 영어에서는 ''luggage''에 이름표를 붙이고, 미국인들은 ''baggage''에 태그를 달아요.','My luggage was too heavy to lift onto the train.','제 짐이 너무 무거워서 기차에 올리기 힘들었어요.','We''ll collect our baggage at carousel three.','저희는 3번 컨베이어에서 짐을 찾을 거예요.'),
('nuc_travel_03','passport','visa',NULL,'여권','비자',NULL,'passport는 신분을 증명하는 여권, visa는 특정 국가 입국 허가 스탬프·서류예요.','passport는 자국 발급, visa는 목적지 국가가 허가하는 것이에요.','B1','travel',2,3,'passport visa travel document','Make sure your passport is valid for six months.','여권이 6개월 이상 유효한지 확인하세요.','You need a visa to enter that country.','그 나라에 입국하려면 비자가 필요해요.','My passport is valid, but I still need to apply for a visa before the trip.','제 여권은 유효하지만, 여행 전에 비자는 신청해야 해요.','Don''t forget to check your passport expiration date.','여권 만료일 확인을 잊지 마세요.','Some countries grant visas on arrival.','일부 나라들은 도착 시 비자를 발급해 줘요.'),
('nuc_travel_04','hotel','hostel',NULL,'호텔 (개인실)','호스텔 (공용실)',NULL,'hotel은 개인실이 있는 숙박 시설, hostel은 저렴하지만 침실을 공유하는 곳이에요.','hostel은 backpacker에게 인기 있는 저렴한 선택이에요.','B1','travel',2,4,'hotel hostel accommodation travel','We stayed at a luxury hotel in Paris.','우리는 파리의 고급 호텔에 묵었어요.','I saved money by sleeping in a hostel dorm.','저는 호스텔 도미토리에서 자며 돈을 아꼈어요.','We splurged on a hotel for our anniversary, though we usually backpack and stay in a hostel.','평소에는 배낭여행을 하며 호스텔에 묵지만, 기념일에는 큰맘 먹고 호텔에서 묵었어요.','We chose a small boutique hotel near the river.','강 근처 작은 부티크 호텔을 골랐어요.','Hostels are great places to meet other travelers.','호스텔은 다른 여행자들을 만나기 좋은 곳이에요.'),
('nuc_travel_15','explore','discover',NULL,'탐험하다 (행위)','발견하다 (결과)',NULL,'explore는 탐구·탐험하는 과정, discover는 새로운 것을 발견하는 결과.','explore는 과정·행위, discover는 결과·발견. 처음 발견하는 것은 discover, 둘러보는 것은 explore.','B1','travel',1,0,'exploring discovering travel adventure hidden','We explored the old town for hours.','우리는 몇 시간 동안 구시가지를 둘러봤어요.','I discovered a hidden cafe in the alley.','저는 골목에서 숨은 카페를 발견했어요.','On weekends we like to explore the countryside by car.','우리는 주말이면 차로 시골을 둘러보는 걸 좋아해요.','While exploring the city, I discovered a beautiful park.','도시를 탐험하다가 아름다운 공원을 발견했어요.','Explore new places; discover new things.','새 장소를 탐험하고, 새로운 것을 발견하세요.'),
('nuc_travel_05','reservation','booking',NULL,'예약 (격식)','예약 (일상)',NULL,'둘 다 예약을 뜻하지만, reservation은 격식·레스토랑, booking은 온라인·숙박에서 더 자주 써요.','미국에서는 reservation, 영국에서는 booking을 더 자주 써요.','B2','travel',1,5,'reservation booking hotel restaurant','I have a reservation under Kim.','김 이름으로 예약했어요.','I made a hotel booking online.','저는 온라인으로 호텔을 예약했어요.','I made a dinner reservation for Saturday and confirmed our flight booking on the same day.','저는 토요일 저녁 식사를 예약하고, 같은 날 항공편 예약도 확정했어요.','I''d like to make a reservation for two at 7 p.m.','저녁 7시에 2인 예약하고 싶어요.','You can confirm your booking by email.','이메일로 예약을 확인할 수 있어요.'),
('nuc_travel_06','sightseeing','tourism',NULL,'관광 (활동)','관광 (산업·개념)',NULL,'sightseeing은 명소를 구경하는 행위, tourism은 관광 산업·현상 전체를 가리켜요.','go sightseeing(관광하다), work in tourism(관광업에서 일하다)처럼 써요.','B2','travel',2,6,'sightseeing tourism landmark city','We spent the day sightseeing in Rome.','우리는 로마에서 하루 종일 관광을 했어요.','Tourism contributes greatly to the local economy.','관광업은 지역 경제에 크게 기여해요.','A day of sightseeing felt magical, but for the town, tourism is serious business.','하루 동안의 관광은 마법 같았지만, 그 마을에게 관광업은 진지한 사업이에요.','We spent the morning sightseeing in the old town.','오전에 구시가지에서 관광했어요.','Tourism is a major industry for this small country.','관광은 이 작은 나라의 주요 산업이에요.'),
('nuc_travel_07','souvenir','memento',NULL,'기념품 (상점)','추억품 (개인)',NULL,'souvenir는 여행지에서 파는 기념품, memento는 개인적 추억이 담긴 물건이에요.','souvenir는 상업적, memento는 감정적·개인적 가치를 강조해요.','B2','travel',1,7,'souvenir memento travel memory gift','She bought souvenirs for her friends.','그녀는 친구들을 위해 기념품을 샀어요.','This ticket stub is a memento of our first date.','이 입장권 조각은 우리 첫 데이트의 기념물이에요.','I picked up a cheap souvenir at the gift shop, but this pressed flower is my real memento.','저는 선물 가게에서 값싼 기념품을 샀지만, 이 눌린 꽃이야말로 진짜 제 추억의 물건이에요.','She brought back a small souvenir from each city.','그녀는 각 도시에서 작은 기념품을 가져왔어요.','I keep this seashell as a memento of our beach trip.','저는 이 조개껍데기를 우리 해변 여행의 추억으로 간직해요.'),
('nuc_travel_08','itinerary','route',NULL,'여행 일정표','경로',NULL,'itinerary는 날짜별 여행 계획, route는 이동 경로를 뜻해요.','itinerary는 시간표 포함 계획서, route는 단순히 길·경로예요.','B2','travel',2,8,'itinerary route plan travel map','Our tour guide handed out the itinerary.','여행 가이드가 일정표를 나눠 줬어요.','We took the scenic route along the coast.','우리는 해안을 따라 경치 좋은 길로 갔어요.','Our itinerary keeps us busy each day, and the driving route hugs the mountains.','일정표 덕분에 매일 바쁘고, 운전 경로는 산을 따라 이어져요.','The itinerary lists three museums for tomorrow.','여행 일정표에는 내일 세 박물관이 적혀 있어요.','We took the coastal route to enjoy the views.','경치를 즐기기 위해 해안 경로로 갔어요.'),
('nuc_travel_09','currency','exchange rate',NULL,'통화','환율',NULL,'currency는 특정 나라의 돈, exchange rate는 통화 간 교환 비율이에요.','currency exchange는 환전, exchange rate는 환율을 가리켜요.','B2','travel',1,9,'currency exchange rate money travel','The local currency is the won.','현지 통화는 원이에요.','Check the exchange rate before converting money.','돈을 환전하기 전에 환율을 확인하세요.','You''ll need to carry some local currency for the markets and small shops.','시장과 작은 가게들을 위해 현지 통화를 좀 가지고 다녀야 해요.','Some countries don''t use their own currency anymore.','어떤 나라들은 더 이상 자국 통화를 쓰지 않아요.','The exchange rate is best at official kiosks.','환율은 공식 키오스크가 가장 좋아요.'),
('nuc_travel_10','jet lag','fatigue',NULL,'시차 피로','피로',NULL,'jet lag은 시간대 변화로 생기는 수면 장애, fatigue는 일반적인 피로예요.','jet lag은 시차, fatigue는 신체적 피로감을 가리켜요.','B2','travel',2,10,'jet lag fatigue sleep travel','I suffered from jet lag for two days.','저는 이틀 동안 시차로 고생했어요.','Travel fatigue can happen even on short trips.','여행 피로는 짧은 여행에서도 생길 수 있어요.','The jet lag from the long flight left me with a heavy fatigue that lasted all week.','긴 비행으로 인한 시차 때문에 한 주 내내 심한 피로가 가시지 않았어요.','Jet lag hit me hard after the trip to New York.','뉴욕 여행 후 시차 피로가 심하게 왔어요.','Travel fatigue can build up over many short trips.','여행 피로는 여러 짧은 여행에 걸쳐 쌓일 수 있어요.'),
('nuc_travel_11','expatriate','immigrant',NULL,'주재원 / 장기 체류 외국인','이민자',NULL,'expatriate(expat)는 일시적으로 해외에 거주하는 사람, immigrant는 영구 이민자예요.','expat은 주로 일·라이프스타일 목적, immigrant는 영구 정착을 가리켜요.','C1','travel',1,11,'expatriate immigrant abroad living','Many expats live in Singapore for work.','많은 외국 주재원들이 일 때문에 싱가포르에 살아요.','Her parents were immigrants from Vietnam.','그녀의 부모님은 베트남에서 온 이민자였어요.','He''s an expat on a two-year contract, not an immigrant planning to stay for good.','그는 2년 계약으로 온 주재원이지, 영영 정착하려는 이민자가 아니에요.','Many expats settle in Seoul for the food and culture.','많은 주재원들이 음식과 문화 때문에 서울에 정착해요.','Immigrants bring rich cultural diversity to their new countries.','이민자들은 새 나라에 풍부한 문화적 다양성을 가져와요.'),
('nuc_travel_12','nomadic','transient',NULL,'유목적인 / 떠돌이','일시적인 / 떠돌이',NULL,'nomadic은 한 곳에 정착하지 않고 이동하는 삶, transient는 일시적·짧은 체류를 강조해요.','nomadic lifestyle은 디지털 노마드처럼 이동하는 삶, transient는 일시 거주예요.','C1','travel',2,12,'nomadic transient lifestyle digital nomad','She leads a nomadic lifestyle, moving every few months.','그녀는 몇 달마다 옮겨 다니는 유목민적인 생활 방식을 살아요.','The city has a large transient population of tourists.','그 도시에는 관광객으로 이루어진 큰 유동 인구가 있어요.','He prefers a nomadic life on the road, while tourists are just a transient presence in each town.','그는 길 위에서의 유목민 같은 삶을 선호하지만, 관광객들은 각 마을에 잠시 머무는 일시적인 존재일 뿐이에요.','She lives a nomadic life working from cafes around the world.','그녀는 세계 곳곳의 카페에서 일하며 유목적인 삶을 살아요.','A transient crowd fills the train station every weekend.','주말마다 일시적인 인파가 기차역을 가득 채워요.'),
('nuc_travel_13','traverse','navigate',NULL,'횡단하다','항법으로 나아가다',NULL,'traverse는 어떤 지역을 가로질러 이동하는 것, navigate는 방향을 파악하며 경로를 찾는 것이에요.','traverse는 거리·지역을, navigate는 방향 찾기를 강조해요.','C2','travel',1,13,'traverse navigate journey explore','They traversed the entire continent by bicycle.','그들은 자전거로 대륙 전체를 횡단했어요.','She navigated through the narrow mountain roads.','그녀는 좁은 산길을 헤쳐 나갔어요.','The expedition traversed the frozen plateau in three weeks.','그 탐험대는 3주 만에 얼어붙은 고원을 횡단했어요.','They traversed the desert in just over a week.','그들은 일주일 조금 넘게 사막을 횡단했어요.','I had to navigate through unfamiliar streets late at night.','저는 늦은 밤 낯선 거리를 찾아가야 했어요.'),
('nuc_weather_01','rain','drizzle',NULL,'비','이슬비 / 보슬비',NULL,'rain은 일반적인 비, drizzle은 매우 가늘고 약하게 내리는 비예요.','drizzle은 우산 없이도 걸을 수 있을 만큼 약한 비예요.','B1','weather',1,1,'rain drizzle wet street','It started to rain heavily.','비가 세차게 내리기 시작했어요.','A light drizzle made the street shiny.','가벼운 이슬비가 거리를 반짝이게 했어요.','It wasn''t proper rain, just a fine drizzle that barely wet the pavement.','제대로 된 비가 아니라, 포장도로를 겨우 적실 정도의 가는 이슬비였어요.','It looks like it''s going to rain all weekend.','주말 내내 비가 올 것 같아요.','A light drizzle is falling outside the window.','창문 밖에는 가벼운 이슬비가 내리고 있어요.'),
('nuc_weather_02','wind','breeze','gust','바람','산들바람','돌풍','breeze는 부드럽고 상쾌한 바람, wind는 일반적 바람, gust는 갑자기 세게 부는 돌풍이에요.','강도 순서: breeze < wind < gust. 날씨 예보에서 gust를 자주 들어요.','B1','weather',1,2,'wind breeze gust weather','A cold wind blew all day.','하루 종일 찬 바람이 불었어요.','A gentle breeze cooled the afternoon.','산들바람이 오후를 시원하게 해 줬어요.','A sudden gust knocked over the umbrella.','갑작스러운 돌풍이 우산을 쓰러뜨렸어요.','A cool breeze made the afternoon perfect for a picnic.','시원한 산들바람이 오후를 소풍하기에 완벽하게 만들었어요.','A strong wind blew dust across the road.','강한 바람이 도로 너머로 먼지를 날렸어요.'),
('nuc_weather_03','cloudy','overcast',NULL,'흐린','완전히 흐린',NULL,'cloudy는 구름이 일부 있는 상태, overcast는 하늘 전체가 구름으로 덮인 상태예요.','예보에서 overcast는 종일 구름이 가득 낀 날을 뜻해요.','B1','weather',2,3,'cloudy overcast sky grey','It was partly cloudy this morning.','오늘 아침엔 부분적으로 구름이 꼈어요.','The sky was completely overcast by noon.','정오쯤엔 하늘이 완전히 흐려졌어요.','It started out cloudy, but by afternoon the sky was completely overcast.','처음엔 구름이 끼더니, 오후가 되자 하늘이 완전히 흐려졌어요.','It''s a bit cloudy, but I think the sun will come out.','약간 흐리지만 해가 나올 것 같아요.','The morning was overcast and cool.','아침은 완전히 흐리고 시원했어요.'),
('nuc_weather_04','hot','warm',NULL,'더운','따뜻한',NULL,'warm은 적당히 따뜻한 기분 좋은 날씨, hot은 불쾌할 만큼 더운 날씨예요.','기분 좋은 날씨에는 warm, 불쾌하게 더울 때는 hot을 쓰면 정확해요.','B1','weather',2,4,'hot warm temperature summer','It was so hot that we stayed indoors.','너무 더워서 우리는 실내에 머물렀어요.','The weather was warm and pleasant.','날씨가 따뜻하고 쾌적했어요.','The morning was pleasantly warm, but by noon it became unbearably hot.','아침에는 기분 좋게 따뜻했지만, 정오쯤에는 견딜 수 없을 만큼 더워졌어요.','It''s too hot to walk outside at midday.','한낮에는 밖에서 걷기 너무 더워요.','The kitchen was warm and smelled of fresh bread.','주방은 따뜻하고 갓 구운 빵 냄새가 났어요.'),
('nuc_weather_05','cold','chilly','freezing','추운','쌀쌀한','매우 추운','chilly는 약간 쌀쌀한 정도, cold는 춥다는 일반적 표현, freezing은 매우 심하게 춥거나 과장 표현이에요.','강도 순서: chilly < cold < freezing. freezing은 과장 표현으로도 써요.','B1','weather',2,5,'cold chilly freezing winter','It''s cold enough to wear a coat.','코트를 입어야 할 만큼 추워요.','It''s a bit chilly — bring a jacket.','좀 쌀쌀하니 재킷을 챙기세요.','It''s freezing outside today!','오늘 밖은 너무 추워요!','It''s a bit chilly tonight — grab a sweater.','오늘 밤 좀 쌀쌀해요 — 스웨터 챙기세요.','It''s absolutely freezing — my fingers are numb.','진짜 너무 추워요 — 손가락이 무감각해요.'),
('nuc_weather_06','storm','shower',NULL,'폭풍','소나기',NULL,'shower는 짧고 갑작스러운 비, storm은 강풍이나 번개를 동반한 거센 날씨예요.','예보에서 "scattered showers"는 곳곳에 소나기, "storm warning"은 강한 폭풍 경보예요.','B2','weather',1,6,'storm shower rain weather','The storm caused widespread damage.','그 폭풍은 광범위한 피해를 일으켰어요.','We got caught in a brief shower.','우리는 잠깐 소나기를 만났어요.','What began as a light shower quickly grew into a violent storm with thunder.','가벼운 소나기로 시작한 것이 곧 천둥을 동반한 거센 폭풍으로 변했어요.','A big storm is heading toward the coast tonight.','큰 폭풍이 오늘 밤 해안으로 향하고 있어요.','There were scattered showers throughout the morning.','아침 내내 곳곳에 소나기가 내렸어요.'),
('nuc_weather_07','fog','mist',NULL,'짙은 안개','엷은 안개 / 안개비',NULL,'mist는 옅고 부드러운 안개, fog는 더 짙어 시야를 심하게 가리는 안개예요.','운전·항공 예보에서 fog는 visibility(가시거리) 문제를 일으켜요.','B2','weather',2,7,'fog mist visibility morning','Dense fog closed the airport.','짙은 안개로 공항이 폐쇄되었어요.','A light mist hung over the lake.','옅은 안개가 호수 위에 드리워 있었어요.','A thin mist drifted off the river, but it never thickened into proper fog.','강에서 옅은 안개가 피어올랐지만, 제대로 된 짙은 안개로 짙어지지는 않았어요.','Thick fog made driving very dangerous.','짙은 안개로 운전이 매우 위험했어요.','A soft mist covered the valley at dawn.','새벽에 부드러운 안개가 골짜기를 덮었어요.'),
('nuc_weather_08','humid','muggy',NULL,'습한','후텁지근한',NULL,'humid는 습도가 높은 상태, muggy는 습하고 더워서 불쾌한 상태예요.','muggy는 humid보다 불쾌함이 추가된 표현이에요.','B2','weather',1,8,'humid muggy summer heat','Seoul summers are very humid.','서울의 여름은 매우 습해요.','It was so muggy that we could barely breathe.','너무 후텁지근해서 숨을 거의 쉴 수 없었어요.','The air was humid all week, but today it turned downright muggy and oppressive.','한 주 내내 공기가 습했는데, 오늘은 그야말로 후텁지근하고 답답했어요.','It was so humid that my hair frizzed up.','너무 습해서 제 머리가 부풀어 올랐어요.','It''s muggy outside — I''d rather stay indoors.','밖이 후텁지근해서 — 그냥 실내에 있고 싶어요.'),
('nuc_weather_09','lightning','thunder',NULL,'번개','천둥',NULL,'lightning은 눈에 보이는 번쩍임, thunder는 귀에 들리는 천둥소리예요.','번개(lightning)가 먼저 보이고, 천둥(thunder)이 나중에 들려요.','B2','weather',2,9,'lightning thunder storm','Lightning struck the tree.','번개가 나무를 내리쳤어요.','We heard thunder in the distance.','우리는 멀리서 천둥소리를 들었어요.','We saw the lightning flash first, then the thunder followed a few seconds later.','우리는 번개가 번쩍이는 것을 먼저 봤고, 몇 초 뒤에 천둥이 따라왔어요.','Lightning lit up the whole sky for a second.','번개가 1초간 하늘 전체를 비췄어요.','The thunder rumbled for almost ten seconds.','천둥이 거의 10초 동안 울렸어요.'),
('nuc_weather_10','forecast','predict',NULL,'예보하다','예측하다',NULL,'forecast는 날씨·경제 등 전문적 예측, predict는 다양한 상황에서의 예측을 뜻해요.','weather forecast는 공식 기상 예보, predict는 더 넓은 문맥에서 써요.','B2','weather',1,10,'forecast predict weather report','The forecast calls for snow tomorrow.','일기 예보에서 내일 눈이 온다고 해요.','Scientists predicted the weather would change.','과학자들은 날씨가 바뀔 거라고 예측했어요.','Meteorologists forecast heavy rain across the coast tonight.','기상학자들은 오늘 밤 해안 전역에 폭우가 내릴 것으로 예보했어요.','The forecast says it''ll be sunny all weekend.','예보에 따르면 주말 내내 맑을 거예요.','Economists predicted rising prices for the next year.','경제학자들은 내년 가격 상승을 예측했어요.'),
('nuc_weather_11','blizzard','snowstorm',NULL,'눈보라','폭설',NULL,'snowstorm은 폭설을 동반한 폭풍, blizzard는 강풍과 폭설이 함께하는 더 극심한 눈보라예요.','blizzard는 공식 기상 용어로 특정 기준(풍속·가시거리)을 충족해야 해요.','C1','weather',1,11,'blizzard snowstorm winter storm','The blizzard shut down the entire city.','눈보라로 도시 전체가 마비되었어요.','A sudden snowstorm surprised drivers.','갑작스러운 눈보라가 운전자들을 당황하게 했어요.','What forecasters called a snowstorm soon turned into a full blizzard with blinding winds.','예보관들이 눈보라라고 부른 것은 곧 앞이 안 보일 정도의 거센 바람을 동반한 거대한 눈보라로 변했어요.','A blizzard kept us inside for the entire day.','눈보라로 우리는 하루 종일 실내에 있었어요.','A heavy snowstorm closed every road in the area.','폭설로 그 지역 모든 도로가 폐쇄됐어요.'),
('nuc_weather_12','temperate','mild',NULL,'온화한 (기후)','온화한 (날씨)',NULL,'mild는 특정 날이 온화하다는 표현, temperate는 기후 유형 자체를 가리켜요.','climate is temperate(기후), today is mild(날씨)처럼 스케일이 달라요.','C1','weather',2,12,'temperate mild climate zone','Korea has a temperate climate.','한국은 온화한 기후를 가지고 있어요.','We had a mild winter this year.','올해는 겨울이 포근했어요.','Living in a temperate region means the climate is mild for most of the year.','온대 지역에 산다는 건 일 년 내내 기후가 온화하다는 뜻이에요.','The temperate climate makes spring last for weeks.','온화한 기후 덕분에 봄이 몇 주간 지속돼요.','It was a mild day perfect for a long walk.','긴 산책에 완벽한 온화한 날이었어요.'),
('nuc_weather_13','arid','drought',NULL,'건조한 (지형)','가뭄',NULL,'arid는 강수량이 매우 적은 건조한 기후·지역, drought는 비정상적으로 비가 안 오는 기간이에요.','arid는 형용사(지역·기후), drought는 명사(기간·사건)로 써요.','C2','weather',1,13,'arid drought desert dry','The Sahara is an arid region.','사하라는 건조한 지역이에요.','The drought lasted for three years.','가뭄이 3년 동안 지속됐어요.','The region is naturally arid, so even a short drought can devastate the crops.','그 지역은 본래 건조해서 짧은 가뭄에도 농작물이 큰 피해를 입을 수 있어요.','The arid landscape stretched for miles without any trees.','건조한 풍경이 나무 한 그루 없이 몇 마일 펼쳐졌어요.','The drought finally ended after months of light rain.','가뭄이 몇 달간의 약한 비 끝에 마침내 끝났어요.'),
('nuc_work_15','begin','start',NULL,'시작하다 (격식)','시작하다 (일반)',NULL,'begin과 start는 거의 동의어. 다만 begin이 약간 더 격식·문어체적, start는 일상·구어체적.','begin과 start는 대부분 호환. 다만 자동차·기계는 start만 (start the engine).','A2','work',1,0,'beginning starting fresh sunrise launch','The meeting begins at 9 AM.','회의는 오전 9시에 시작해요.','Let''s start cooking.','요리를 시작해요.','The new semester begins right after the holidays.','새 학기는 연휴가 끝나자마자 시작해요.','The ceremony begins now; the party starts later.','의식은 지금 시작하고, 파티는 나중에 시작해요.','Begin with the introduction; start with a smile.','서론부터 시작하세요; 미소로 시작하세요.'),
('nuc_work_18','sometimes','occasionally',NULL,'가끔 (50% 정도)','이따금 (30% 정도)',NULL,'sometimes는 가끔, occasionally는 더 드물게 (이따금). sometimes > occasionally 빈도.','sometimes (50%) > occasionally (30%). occasionally는 더 드문 빈도.','A2','work',1,0,'sometimes occasional calendar habit irregular','I sometimes work from home.','저는 가끔 재택근무를 해요.','I occasionally work from home.','저는 이따금 재택근무를 해요.','I sometimes take the long way home to clear my head.','저는 가끔 머리를 식히려고 멀리 돌아서 집에 가요.','We sometimes eat out, but only occasionally on weekdays.','우리는 가끔 외식하지만, 평일에는 이따금만 해요.','She sometimes calls her mom, occasionally visits her dad.','그녀는 가끔 엄마에게 전화하고, 이따금 아빠를 방문해요.'),
('nuc_work_01','job','career',NULL,'직업 (현재)','커리어 (장기)',NULL,'job은 현재 하는 특정 일, career는 장기적인 직업 경력과 발전을 뜻해요.','"change jobs"는 직장 이동, "career change"는 직종 자체를 바꾸는 것이에요.','B1','work',1,1,'job career work profession','I have a job at a tech company.','저는 한 IT 회사에서 일하고 있어요.','She has built a successful career in finance.','그녀는 금융 분야에서 성공적인 경력을 쌓았어요.','This is just a job to pay the bills, not the career I really want to build.','이건 그저 생활비를 벌기 위한 일일 뿐이지, 제가 정말로 쌓고 싶은 경력은 아니에요.','I started a new job last month at a small studio.','저는 지난달 작은 스튜디오에서 새 직장을 시작했어요.','Her career in journalism has spanned three decades.','그녀의 저널리즘 경력은 30년에 걸쳐요.'),
('nuc_work_02','boss','manager',NULL,'상사 (구어)','관리자 (직책)',NULL,'boss는 구어로 자기 상사를 가리키고, manager는 공식 직함이에요.','boss는 비공식, manager는 공식 조직 직함이에요.','B1','work',2,2,'boss manager office leadership','My boss approved my vacation request.','상사가 제 휴가 신청을 승인해 줬어요.','The project manager assigned tasks to the team.','프로젝트 매니저가 팀에 업무를 배정했어요.','My boss trusts me, even though the official manager signs off on my reports.','공식 담당자가 제 보고서를 결재하긴 하지만, 상사는 저를 신뢰해요.','My boss is very supportive of my growth.','제 상사는 제 성장을 매우 지지해 주세요.','The product manager scheduled a kickoff meeting.','제품 매니저가 킥오프 회의를 잡았어요.'),
('nuc_work_03','salary','wage',NULL,'월급 (연봉제)','시급 / 일당',NULL,'salary는 월·연 단위로 받는 고정 급여, wage는 시간·일 단위로 받는 임금이에요.','salaried employee(월급쟁이) vs hourly/wage worker(시급제 근로자)로 구분해요.','B1','work',1,3,'salary wage income work payment','Her annual salary is 50 million won.','그녀의 연봉은 5천만 원이에요.','The minimum wage was raised this year.','올해 최저임금이 인상되었어요.','She earns a fixed monthly salary, while her brother is paid an hourly wage at the warehouse.','그녀는 고정 월급을 받지만, 그녀의 남동생은 창고에서 시급을 받아요.','Her salary doubled after the promotion.','승진 후 그녀의 월급이 두 배가 됐어요.','Many part-time workers earn an hourly wage.','많은 시간제 근로자들이 시급을 받아요.'),
('nuc_work_04','task','project',NULL,'업무 (단위)','프로젝트 (복합)',NULL,'task는 특정한 단일 작업, project는 여러 task가 포함된 큰 작업이에요.','task는 to-do list의 항목, project는 여러 task를 포함한 복합 업무예요.','B1','work',2,4,'task project work team office','My first task was to send the report.','제 첫 업무는 보고서를 보내는 거였어요.','The team launched a six-month project.','그 팀은 6개월짜리 프로젝트를 시작했어요.','Breaking the report into smaller tasks made it less overwhelming.','보고서를 작은 업무들로 나누니 부담이 덜했어요.','Please complete this task before lunch.','점심 전에 이 업무를 완료해 주세요.','The project ran for nine months and involved five teams.','그 프로젝트는 9개월간 진행됐고 다섯 팀이 참여했어요.'),
('nuc_work_14','finish','complete',NULL,'끝내다 (일반)','완료하다 (격식·전체)',NULL,'finish는 일상적이고 광범위, complete는 좀 더 격식 있고 "끝까지 마쳤다"는 완결성 강조.','finish는 일상적·간단, complete는 격식·완결. 양식 작성·과제 제출은 complete가 자연스러워요.','B1','work',1,0,'project completion finished tasks checklist','I finished the book last night.','저는 어젯밤에 그 책을 다 읽었어요.','She completed the marathon in 4 hours.','그녀는 마라톤을 4시간 만에 완주했어요.','I''ll finish replying to these emails before the meeting.','회의 전에 이 이메일들에 답장을 끝낼게요.','I finished the draft, but I need to complete the final version.','초안은 끝냈지만 최종본을 완성해야 해요.','He finished work early; she completed the project on time.','그는 일을 일찍 끝냈고, 그녀는 프로젝트를 제때 완료했어요.'),
('nuc_work_17','often','frequently',NULL,'자주 (일반)','빈번하게 (격식)',NULL,'often과 frequently는 동의어. often은 일상, frequently는 격식·문어체에서 더 자주 써요.','often은 일상, frequently는 보고서·뉴스·격식 표현. "often" 70%, "frequently" 70% — 의미 같음.','B1','work',1,0,'often clock calendar repeated schedule','I often go to the gym.','저는 자주 헬스장에 가요.','He frequently travels for business.','그는 출장을 자주 다녀요.','We often hold our team meetings on Monday mornings.','우리는 보통 월요일 아침에 팀 회의를 자주 열어요.','She often calls; he frequently visits.','그녀는 자주 전화하고, 그는 빈번하게 방문해요.','We often meet for coffee, but frequently miss each other.','우리는 자주 커피를 마시지만, 빈번하게 서로 어긋나요.'),
('nuc_work_19','always','constantly',NULL,'항상, 늘 (중립)','끊임없이 (부정·과도함)',NULL,'always는 중립적 "항상", constantly는 "끊임없이" 보통 부정적 뉘앙스 (귀찮음·과도함).','always는 중립, constantly는 보통 부정적 (귀찮음·과도). "He''s constantly late" = 짜증 섞임.','B1','work',1,0,'always constantly continuous nonstop pattern','She''s always smiling.','그녀는 늘 웃고 있어요.','He''s constantly checking his phone.','그는 끊임없이 휴대폰을 확인해요.','My manager always trusts my judgment on these decisions.','제 상사는 이런 결정에 대해 항상 제 판단을 믿어줘요.','I always wake up at 7, but my neighbor constantly slams doors.','저는 항상 7시에 일어나는데, 옆집 사람은 끊임없이 문을 쾅 닫아요.','She''s always there for me; he''s constantly complaining.','그녀는 항상 제 곁에 있어주는데, 그는 끊임없이 불평해요.'),
('nuc_work_20','never','hardly ever','rarely','전혀 ~ 않다 (0%)','거의 ~ 않다 (5%)','드물게 (10%)','never < hardly ever < rarely 빈도 (0% < 5% < 10%). 셋 다 부정적 빈도지만 강도 다름.','never (0%) < hardly ever (5%) < rarely (10%) < seldom (15%). hardly ever와 rarely는 거의 같음.','B1','work',1,0,'never rarely calendar habit infrequent zero','I never eat fast food.','저는 패스트푸드를 절대 먹지 않아요.','I hardly ever eat fast food.','저는 패스트푸드를 거의 먹지 않아요.','I rarely eat fast food.','저는 패스트푸드를 좀처럼 먹지 않아요.','I never smoke, hardly ever drink, and rarely stay up late.','저는 절대 담배 안 피우고, 거의 안 마시고, 늦게까지 잘 안 있어요.','She never lies, hardly ever exaggerates, and rarely complains.','그녀는 절대 거짓말 안 하고, 거의 과장 안 하고, 드물게 불평해요.'),
('nuc_work_21','soon','immediately',NULL,'곧 (시간 여유 있음)','즉시 (시간 여유 없음)',NULL,'soon은 "곧, 머지않아"로 시간 여유 있음. immediately는 "즉시, 당장" 긴급함.','soon은 시간 여유, immediately는 긴급. "soon" = 몇 분~며칠, "immediately" = 지금 당장.','B1','work',1,0,'soon urgent immediately quick fast clock','I''ll see you soon.','곧 뵙겠습니다.','Please respond immediately.','즉시 답변해 주세요.','Don''t worry, the results will be ready soon.','걱정하지 마세요, 결과는 곧 준비될 거예요.','I''ll be there soon — I''m leaving immediately.','곧 도착할게요 — 지금 즉시 출발해요.','The package will arrive soon; the alarm sounded and we left immediately.','소포는 곧 도착할 거예요; 경보가 울리자 우리는 즉시 떠났어요.'),
('nuc_work_05','colleague','coworker',NULL,'동료 (격식)','동료 (일상)',NULL,'둘 다 같은 직장 동료를 가리키지만, colleague는 격식·직업적 맥락에서 더 자주 써요.','colleague는 발표·이메일에서, coworker는 일상 대화에서 더 자연스러워요.','B2','work',1,5,'colleague coworker office team','I''d like to introduce my colleague, Dr. Park.','제 동료인 박 박사님을 소개해 드릴게요.','My coworker and I eat lunch together.','직장 동료와 저는 함께 점심을 먹어요.','In the report I referred to my colleague, but over lunch I just call her my coworker.','보고서에서는 그녀를 제 동료라고 표현했지만, 점심을 먹을 때는 그냥 직장 동료라고 불러요.','I have lunch with my colleagues every Wednesday.','저는 매주 수요일 동료들과 점심을 먹어요.','My coworker brought homemade cookies for everyone.','제 동료가 모두를 위해 수제 쿠키를 가져왔어요.'),
('nuc_work_06','resign','retire',NULL,'사직하다','은퇴하다',NULL,'resign은 자진 퇴직, retire는 나이·연금으로 경력을 마무리하는 은퇴예요.','resign은 자발적 그만두기, retire는 직업 생활 마감이에요.','B2','work',1,6,'resign retire quit career end','She resigned from her position last week.','그녀는 지난주에 자리에서 사임했어요.','He plans to retire at 60.','그는 60세에 은퇴할 계획이에요.','He decided to resign and join a startup, while his older colleague chose to retire that year.','그는 사임하고 스타트업에 합류하기로 했고, 그의 나이 많은 동료는 그해에 은퇴하기로 했어요.','He plans to resign after finding a better offer.','그는 더 나은 제안을 찾은 후 사직할 계획이에요.','She''s planning to retire and travel the world.','그녀는 은퇴하고 세계를 여행할 계획이에요.'),
('nuc_work_07','deadline','due date',NULL,'마감 시한','제출 기한',NULL,'deadline은 절대 넘으면 안 되는 마감, due date는 제출·납부 기한을 뜻해요.','deadline은 프로젝트·미디어, due date는 과제·청구서에 자주 써요.','B2','work',2,7,'deadline due date schedule work','The deadline for submissions is Friday noon.','제출 마감은 금요일 정오예요.','The payment due date is the 25th of each month.','납부 기한은 매달 25일이에요.','The report''s deadline is Monday, but the invoice''s due date isn''t until the end of the month.','보고서 마감은 월요일이지만, 청구서 납부 기한은 월말까지예요.','The deadline is tomorrow at 5 p.m. — no extensions.','마감은 내일 오후 5시예요 — 연장 없어요.','Your library book has a due date of June 10.','도서관 책의 반납 기한은 6월 10일이에요.'),
('nuc_work_08','remote','hybrid',NULL,'재택근무','혼합 근무',NULL,'remote work는 완전 재택근무, hybrid는 사무실과 재택을 병행하는 방식이에요.','remote, hybrid, on-site(full office)는 최근 가장 중요한 근무 형태 용어예요.','B2','work',1,8,'remote hybrid work office home','She works fully remote from home.','그녀는 집에서 완전히 원격으로 일해요.','Our team has a hybrid schedule: three days in office.','우리 팀은 주 3일 출근하는 하이브리드 근무제예요.','Since going remote, she rarely commutes into the city.','원격 근무를 시작한 뒤로 그녀는 도심으로 통근하는 일이 거의 없어요.','Working remotely lets me see my kids more often.','재택근무 덕분에 아이들을 더 자주 볼 수 있어요.','Our hybrid model has worked well for the past year.','저희 혼합 근무 모델은 작년에 잘 작동했어요.'),
('nuc_work_09','productive','efficient',NULL,'생산적인','효율적인',NULL,'productive는 많은 성과를 내는 것, efficient는 낭비 없이 자원을 잘 쓰는 것이에요.','productive는 결과의 양, efficient는 과정의 질을 강조해요.','B2','work',2,9,'productive efficient work performance','She had a very productive day and finished three reports.','그녀는 아주 생산적인 하루를 보냈고 보고서 세 개를 끝냈어요.','He found a more efficient way to organize data.','그는 데이터를 정리하는 더 효율적인 방법을 찾았어요.','Working in short bursts keeps me far more productive.','짧게 집중해서 일하면 훨씬 더 생산적이에요.','Mornings are my most productive time of day.','아침이 제 하루 중 가장 생산적인 시간이에요.','A more efficient process saved the team weeks of work.','더 효율적인 프로세스가 팀의 몇 주 작업을 절약해 줬어요.'),
('nuc_work_16','earn','gain',NULL,'벌다 (노동·자격)','얻다 (이익·결과)',NULL,'earn은 노력·자격으로 얻는 것 (돈·존경·자격), gain은 결과로 얻는 것 (이익·체중·경험).','earn은 노력·자격의 대가, gain은 결과로서의 획득. 돈은 보통 earn (gain은 갑작스러운 이익 뉘앙스).','B2','work',1,0,'money career earning success career','She earns a high salary as an engineer.','그녀는 엔지니어로서 높은 급여를 받아요.','He gained valuable experience abroad.','그는 해외에서 값진 경험을 쌓았어요.','It took her years to earn the trust of her colleagues.','그녀가 동료들의 신뢰를 얻기까지는 여러 해가 걸렸어요.','I earn money by working; I gain happiness by helping others.','저는 일해서 돈을 벌고, 남을 도와 행복을 얻어요.','She earned the promotion; he gained confidence over time.','그녀는 승진을 얻었고, 그는 시간이 지나면서 자신감을 얻었어요.'),
('nuc_work_10','delegate','assign',NULL,'위임하다','지시·배정하다',NULL,'delegate는 권한과 책임까지 넘기는 것, assign은 업무를 지정해 맡기는 것이에요.','delegate는 권한 이양, assign은 단순 업무 배정을 강조해요.','C1','work',1,10,'delegate assign management leadership','A good manager delegates tasks to the team.','좋은 관리자는 팀에 업무를 위임해요.','The teacher assigned homework to students.','선생님이 학생들에게 숙제를 내주셨어요.','She learned to delegate routine work so she could focus on strategy.','그녀는 전략에 집중할 수 있도록 일상적인 업무를 위임하는 법을 배웠어요.','A good leader knows how to delegate effectively.','좋은 리더는 효과적으로 위임하는 법을 알아요.','The professor assigned a 10-page paper for next month.','교수님은 다음 달까지 10페이지 논문을 배정했어요.'),
('nuc_work_11','appraisal','evaluation',NULL,'인사 고과','평가',NULL,'appraisal은 직원 성과를 평가하는 공식 과정, evaluation은 다양한 맥락의 평가예요.','performance appraisal은 HR 용어, evaluation은 더 넓게 써요.','C1','work',2,11,'appraisal evaluation HR performance','Annual appraisals determine salary increases.','연례 인사 평가가 급여 인상을 결정해요.','The teacher conducted an evaluation of the program.','그 교사는 그 프로그램에 대한 평가를 실시했어요.','He felt nervous before his first performance appraisal.','그는 첫 인사 평가를 앞두고 긴장했어요.','Her annual appraisal showed strong results.','그녀의 연간 인사 고과는 좋은 결과를 보였어요.','The team conducted a thorough evaluation of the new software.','팀은 새 소프트웨어에 대한 철저한 평가를 진행했어요.'),
('nuc_work_12','redundancy','layoff',NULL,'정리 해고 (영국)','정리 해고 (미국)',NULL,'redundancy는 영국 영어로 인력 감축, layoff는 미국 영어로 같은 의미예요. 둘 다 해고가 아닌 감원이에요.','redundancy(영국) = layoff(미국). 직원 실수가 아닌 경영 결정이에요.','C1','work',1,12,'redundancy layoff employment work','Many workers faced redundancy after the merger.','많은 직원들이 합병 후 정리 해고에 직면했어요.','The company announced mass layoffs last quarter.','그 회사는 지난 분기에 대규모 감원을 발표했어요.','She was offered a generous package when she took voluntary redundancy.','그녀는 희망퇴직을 신청하면서 후한 보상 패키지를 제안받았어요.','After the merger, several roles faced redundancy.','합병 후 여러 직무가 정리 해고에 직면했어요.','Mass layoffs hit the industry hard last spring.','대규모 정리 해고가 지난 봄 그 산업에 큰 타격을 줬어요.'),
('nuc_work_13','remuneration','compensation',NULL,'보수 (격식)','보상·보수 (포괄)',NULL,'remuneration은 격식 있는 급여·보수 표현, compensation은 급여·혜택·피해 보상을 모두 포함해요.','remuneration은 HR·계약서, compensation은 법적 보상에도 써요.','C2','work',1,13,'remuneration compensation salary HR','The remuneration package includes health insurance.','보수 패키지에는 건강보험이 포함되어 있어요.','Workers received compensation for lost wages.','직원들은 손실된 임금에 대한 보상을 받았어요.','His remuneration was reviewed at the end of the fiscal year.','그의 보수는 회계연도 말에 재검토되었어요.','The remuneration includes a generous bonus structure.','보수에는 넉넉한 보너스 구조가 포함돼요.','Workers received fair compensation for the overtime.','근로자들은 초과 근무에 대한 공정한 보상을 받았어요.');
